-- Poems batch 411
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-122','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','剪腊成梅天著意。',70,'宋词/ci.song.5000.json','["剪腊成梅天著意。", "黄色浓浓，对萼匀装缀。", "百和薰肌香旖旎。", "仙裳应渍蔷薇水。", "雪径相逢人半醉。", "手折低枝，拥髻云争翠。", "嗅蕊拈枝无限思。", "玉真未洒梨花泪。"]'),
('song-ci-123','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','青玉一枝红类吐。',70,'宋词/ci.song.5000.json','["青玉一枝红类吐。", "粉颊愁寒，浓与胭脂传。", "辨杏猜桃君莫误。", "天姿不到风尘处。", "云破月来花下住。", "要伴佳人，弄影参差舞。", "只有暗香穿绣户。", "昭华一曲惊吹去。"]'),
('song-ci-124','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','雪霁花梢春欲到。',70,'宋词/ci.song.5000.json','["雪霁花梢春欲到。", "饯腊迎春，一夜花开早。", "青帝回舆云缥缈。", "鲜鲜金雀来飞绕。", "绣阁纱窗人窈窕。", "翠缕红丝，斗剪幡儿小。", "戴在花枝争笑道。", "愿人常共春难老。"]'),
('song-ci-125','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','秾艳夭桃春信漏。',70,'宋词/ci.song.5000.json','["秾艳夭桃春信漏。", "弄粉飘香，枫叶飞丹后。", "酒入冰肌红欲透。", "无言不许群芳斗。", "楼外何人揎翠袖。", "剪落金刀，插处浓云覆。", "肯与刘郎仙去否。", "武陵回路相思瘦。"]'),
('song-ci-126','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','翠袖盘花金拈线。',70,'宋词/ci.song.5000.json','["翠袖盘花金拈线。", "晓炙银簧，劝饮随深浅。", "复幕重帘谁得见。", "馀醺微觉红浮面。", "别唤清商开绮宴。", "玉管双横，抹起梁州遍。", "白苎歌前寒莫怨。", "湘梅萼里春那远。"]'),
('song-ci-127','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','千古铜台今莫问。',70,'宋词/ci.song.5000.json','["千古铜台今莫问。", "流水浮云，歌舞西陵近。", "烟柳有情开不尽。", "东风约定年年信。", "天与麟符行乐分。", "带缓球纹，雅宴催云鬓。", "翠雾萦纡销篆印。", "筝声恰度秋鸿阵。"]'),
('song-ci-128','蝶恋花','王安中','宋','宋词','song-ci','蝶恋花','[]','未帖宜春双彩胜。',69,'宋词/ci.song.5000.json','["未帖宜春双彩胜。", "手点酥山，玉筋人争莹。", "节过日长心自准。", "迟留碧瓦看红影。", "楼外尖风吹鬓冷。", "一望平林，□□花相映", "落粉筛云晴未定。", "朝酲只凭阑干醒。"]'),
('song-ci-129','一落索','王安中','宋','宋词','song-ci','一落索','[]','梦破池塘杳杳。',56,'宋词/ci.song.5000.json','["梦破池塘杳杳。", "情随春草。", "尊前风味不胜清，赋白雪、幽兰调。", "秀句银钩争妙。", "殷勤东道。", "蛮笺传与翠鬟歌，便买断、千金笑。"]'),
('song-ci-130','一落索','王安中','宋','宋词','song-ci','一落索','[]','欲访瑶台蓬岛。',56,'宋词/ci.song.5000.json','["欲访瑶台蓬岛。", "烟云缥缈。", "清游却到凤皇池，听檀板、新声妙。", "天上除书催早。", "人瞻元老。", "东风烟柳罩河堤，更何处、深春好。"]'),
('song-ci-131','木兰花・玉楼春','王安中','宋','宋词','song-ci','木兰花・玉楼春','[]','尧天雨露承新诏。',64,'宋词/ci.song.5000.json','["尧天雨露承新诏。", "珂马风生趋急召。", "玉符曾将虎牙军，金殿还升龙尾道。", "征西镇北功成早。", "仗钺登坛今未老。", "樽前休更说燕然，且听阳关三叠了。"]'),
('song-ci-132','玉蝴蝶','王安中','宋','宋词','song-ci','玉蝴蝶','[]','御水毂纹风皱，画桥横处，沙路晴时。',124,'宋词/ci.song.5000.json','["御水毂纹风皱，画桥横处，沙路晴时。", "曲坞藏春，朱户翠竹参差。", "过墙花、娇无限思，笼槛柳、低不胜垂。", "海棠枝。", "为东君爱，未敢离披。", "迟迟。", "日华融丽，悠扬丝管，掩冉旌旗。", "喜入繁红，坐来开尽不须吹。", "听莺迁、还思上苑，约凤浴、应展新池。", "促归期。", "燕飞蝶舞，特地熙熙。"]'),
('song-ci-133','水龙吟','王安中','宋','宋词','song-ci','水龙吟','[]','魏台长乐坊西，画桥倒影烟堤远。',126,'宋词/ci.song.5000.json','["魏台长乐坊西，画桥倒影烟堤远。", "东风与染，揉蓝春水，湾环清浅。", "浴鹭翘莎，戏鱼吹絮，落红漂卷。", "为游人盛踪，兰舟彩舫，飞轻棹、凌波面。", "乐事年来乍见。", "趁旌旗、谷莺娇啭。", "追随况有，疏帘珠袖，浓香绀幰。", "萧寺高亭，茂林斜照，且留芳宴。", "看韶华烂向，尊前放手，作梨花晚。"]'),
('song-ci-134','临江仙','王安中','宋','宋词','song-ci','临江仙','[]','六六云从龙戏月，天颜带笑尝新。',70,'宋词/ci.song.5000.json','["六六云从龙戏月，天颜带笑尝新。", "年年回首建溪春。", "香甘先玉食，珍宠在枫宸。", "赐品暂醒歌里醉，延和行对台臣。", "宫瓯浮雪乳花匀。", "九重清昼永，宣坐议东巡。"]'),
('song-ci-135','小重山','王安中','宋','宋词','song-ci','小重山','[]','重举金猊多炷香。',70,'宋词/ci.song.5000.json','["重举金猊多炷香。", "仙方调绛雪，坐初尝。", "醉鬟娇捧不成行。", "颜如玉，玉碗共争光。", "飞盖莫催忙。", "歌檀临阅处，缓何妨。", "远山横翠为谁长。", "人归去，馀梦绕高唐。"]'),
('song-ci-136','小重山','王安中','宋','宋词','song-ci','小重山','[]','椽烛乘珠清漏长。',70,'宋词/ci.song.5000.json','["椽烛乘珠清漏长。", "醉痕衫袖湿，有馀香。", "红牙双捧旋排行。", "将歌处，相向更催妆。", "明月映东墙。", "海棠花径密，迸流光。", "迟留春笋缓催汤。", "兰堂静，人已候虚廊。"]'),
('song-ci-137','江神子・江城子','王安中','宋','宋词','song-ci','江神子・江城子','[]','荷花遮水水漫溪。',86,'宋词/ci.song.5000.json','["荷花遮水水漫溪。", "柳底垂。", "乱蝉嘶。", "舍辔何妨，临水照征衣。", "一扇香风摇不尽，人念远，意凄迷。", "骑鲸仙子已相知。", "数归期。", "赋新诗。", "更想翟公，门外雀罗稀。", "陶令此襟尘几许，聊欲向，北窗披。"]'),
('song-ci-138','徵招调中腔・徵招','王安中','宋','宋词','song-ci','徵招调中腔・徵招','[]','红云茜雾笼金阙。',66,'宋词/ci.song.5000.json','["红云茜雾笼金阙。", "圣运叶、星虹佳节。", "紫禁晓风馥天香，奏九韶、帝心悦。", "瑶阶万岁蟠桃结。", "睿算永、壶天风月。", "日观几时六龙来，金缕玉牒告功业。"]'),
('song-ci-139','清平乐','王安中','宋','宋词','song-ci','清平乐','[]','花时微雨。',54,'宋词/ci.song.5000.json','["花时微雨。", "未减春分数。", "占取帘疏花密处。", "把酒听歌金缕。", "斜风轻度浓香。", "闲情正与春长。", "向晚红灯入坐，尝新青杏催觞。"]'),
('song-ci-140','清平乐','王安中','宋','宋词','song-ci','清平乐','[]','花枝敧晚。',54,'宋词/ci.song.5000.json','["花枝敧晚。", "过雨红珠转。", "欲共东君论缱绻。", "繁艳休将风卷。", "归来凝思闲窗。", "寒花莫□微觞。", "解慢不成幽梦，燕泥惊落雕梁。"]'),
('song-ci-141','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，形胜魏西州。',64,'宋词/ci.song.5000.json','["安阳好，形胜魏西州。", "曼衍山河环故国，升平歌鼓沸高楼。", "和气镇飞浮。", "笼画陌，乔木几春秋。", "花外轩窗排远岫，竹间门巷带长流。", "风物更清幽。"]'),
('song-ci-142','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，戟户府居雄。',64,'宋词/ci.song.5000.json','["安阳好，戟户府居雄。", "白昼锦衣清宴处，铁梁丹榭画图中。", "壁记旧三公。", "棠讼悄，池馆北园通。", "夏夜泉声来枕簟，春风花影透帘栊。", "行乐兴何穷。"]'),
('song-ci-143','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，物外占天平。',64,'宋词/ci.song.5000.json','["安阳好，物外占天平。", "叠叠挼蓝烟岫色，淙淙鸣玉晚溪声。", "仙路驭风行。", "松路转，丹碧照飞甍。", "金界花开常烂熳，云根石秀小峥嵘。", "幽事不胜清。"]'),
('song-ci-144','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，泮水盛儒宫。',64,'宋词/ci.song.5000.json','["安阳好，泮水盛儒宫。", "金字照碑光射斗，芸香书阁势凌空。", "肃肃采芹风。", "来劝学，乡衮首文翁。", "岁岁青衿多振鹭，人人彩笔竞腾虹。", "九万奋飞同。"]'),
('song-ci-145','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，耆旧迹依然。',64,'宋词/ci.song.5000.json','["安阳好，耆旧迹依然。", "醉白垂杨低掠水，延松高桧老参天。", "曾映两貂蝉。", "王谢族，兰玉秀当年。", "画隼朱轮人继踵，丹台碧落世多贤。", "簪绂看家传。"]'),
('song-ci-146','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，负郭相君园。',64,'宋词/ci.song.5000.json','["安阳好，负郭相君园。", "绿野移春花自老，平泉醒酒石空存。", "月馆对风轩。", "人选胜，幽径破苔痕。", "拥砌翠筠侵坐冷，穿亭玉溜落池喧。", "归意黯重门。"]'),
('song-ci-147','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，曲水似山阴。',64,'宋词/ci.song.5000.json','["安阳好，曲水似山阴。", "咽咽清泉岩溜细，弯弯碧甃篆痕深。", "永昼坐披襟。", "红袖小，歌扇画泥金。", "鸭绿波随双叶转，鹅黄酒到十分斟。", "重听绕梁音。"]'),
('song-ci-148','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，□□又翬飞。',64,'宋词/ci.song.5000.json','["安阳好，□□又翬飞。", "拨垅旋栽花密密，著行重接柳依依。", "鸳瓦荡晴辉。", "池面渺，相望是荣归。", "两世风流今可见，一门恩数古来稀。", "谁与赋缁衣。"]'),
('song-ci-149','安阳好・忆江南','王安中','宋','宋词','song-ci','安阳好・忆江南','[]','安阳好，千古邺台都。',64,'宋词/ci.song.5000.json','["安阳好，千古邺台都。", "穗帐歌人春不见，金楼梦凤夜相呼。", "辇路旧萦纡。", "闲引望，漳水绕城隅。", "暗有渔樵收故物，谁将宫殿点新图。", "平野漫烟芜。"]'),
('song-ci-150','破子清平乐・清平乐','王安中','宋','宋词','song-ci','破子清平乐・清平乐','[]','烟云千里。',54,'宋词/ci.song.5000.json','["烟云千里。", "一抹西山翠。", "碧瓦红楼山对起。", "楼下飞花流水。", "锦堂风月依然。", "后池莲叶田田。", "缥缈贯珠歌里，从容倒玉尊前。"]'),
('song-ci-151','小重山','王安中','宋','宋词','song-ci','小重山','[]','碧藕花风入袖香。',70,'宋词/ci.song.5000.json','["碧藕花风入袖香。", "涓涓清露浥，玉肌凉。", "折花无语傍横塘。", "随折处，一寸万丝长。", "还更擘莲房。", "莲心真个苦，似离肠。", "凌波新恨尽难忘。", "分携也，触事著思量。"]'),
('song-ci-152','虞美人','王安中','宋','宋词','song-ci','虞美人','[]','星郎才思生雕管。',66,'宋词/ci.song.5000.json','["星郎才思生雕管。", "四海声名满。", "尊前新唱更新妍。", "况有玉人相劝、拚酡颜。", "芙蓉幕下同时客。", "年少那重得。", "且寻幽梦赋高唐。", "莫为浮名容易、却相妨。"]'),
('song-ci-153','虞美人','王安中','宋','宋词','song-ci','虞美人','[]','清商初入昭华琯。',66,'宋词/ci.song.5000.json','["清商初入昭华琯。", "宫叶秋声满。", "草麻初罢月蝉娟。", "想见明朝喜色、动天颜。", "持杯满劝龙头客。", "荣遇时方得。", "词源三峡泻瞿塘。", "便是醉中宣去、也无妨。"]'),
('song-ci-154','虞美人','王安中','宋','宋词','song-ci','虞美人','[]','文昌郎自文无比。',66,'宋词/ci.song.5000.json','["文昌郎自文无比。", "风露行千里。", "试寻天上使星看。", "却见锦衣白昼、过乡关。", "边城落照孤鸿外。", "联璧人相对。", "应吟红叶送清秋。", "向我旧题诗处、更重游。"]'),
('song-ci-155','卜算子','王安中','宋','宋词','song-ci','卜算子','[]','客舍两三花，并脸开清晓。',52,'宋词/ci.song.5000.json','["客舍两三花，并脸开清晓。", "一朵涓涓韵已高，一朵纤纤袅。", "谁与插斜红，拥髻争春好。", "此意遥知梦已传，月落前村悄。"]'),
('song-ci-156','一落索','王安中','宋','宋词','song-ci','一落索','[]','塞柳未传春信。',56,'宋词/ci.song.5000.json','["塞柳未传春信。", "霜花侵鬓。", "送君西去指秦关，看日近、长安近。", "玉帐同时英俊。", "合离无定。", "路逢新雁北来归，寄一字、燕山问。"]'),
('song-ci-157','临江仙','王安中','宋','宋词','song-ci','临江仙','[]','凤拨鵾弦鸣夜永，直疑人在浔阳。',70,'宋词/ci.song.5000.json','["凤拨鵾弦鸣夜永，直疑人在浔阳。", "轻云薄雾隔新妆。", "但闻儿女语，倏忽变轩昂。", "且看金泥花那面，指痕微印红桑。", "几多馀暖与真香。", "移船犹自可，卷箔又何妨。"]'),
('song-ci-158','浣溪沙','王安中','宋','宋词','song-ci','浣溪沙','[]','宫缬悭裁翡翠轻。',48,'宋词/ci.song.5000.json','["宫缬悭裁翡翠轻。", "文犀松串水晶明。", "飐风新样称娉婷。", "带笑缓摇春笋细，障羞斜映远山横。", "玉肌无汗暗香清。"]'),
('song-ci-159','卜算子','王安中','宋','宋词','song-ci','卜算子','[]','燕尾道冠儿，蝉翼生衫子。',52,'宋词/ci.song.5000.json','["燕尾道冠儿，蝉翼生衫子。", "敧枕看书卧北窗，簟展潇湘水。", "团扇弄薰风，皓质添凉意。", "谁与文君作粉真，只此莲花是。"]'),
('song-ci-160','洞仙歌','王安中','宋','宋词','song-ci','洞仙歌','[]','深庭夜寂，但凉蟾如昼。',100,'宋词/ci.song.5000.json','["深庭夜寂，但凉蟾如昼。", "鹊起高槐露华透。", "听曲楼玉管，吹彻伊州，金钏响，轧轧朱扉暗扣。", "迎人巧笑道，好个今宵，怎不相寻暂携手。", "见淡净晚妆残，对月偏宜，多情更、越饶纤瘦。", "早促分飞霎时休，便恰似阳台，梦云归后。"]'),
('song-ci-161','失调名','王安中','宋','宋词','song-ci','失调名','[]','笑时眼迷青意贴，行时鞋露绣旁相。',16,'宋词/ci.song.5000.json','["笑时眼迷青意贴，行时鞋露绣旁相。"]'),
('song-ci-162','点绛唇','王安中','宋','宋词','song-ci','点绛唇','[]','岘首亭空，劝君休堕羊碑泪。',50,'宋词/ci.song.5000.json','["岘首亭空，劝君休堕羊碑泪。", "宦游如寄。", "且伴山翁醉。", "说与鲛人，莫解江皋佩。", "将归思。", "晕红萦翠。", "细织回文字。"]'),
('song-ci-163','菩萨蛮','王安中','宋','宋词','song-ci','菩萨蛮','[]','雨零花昼春杯举。',52,'宋词/ci.song.5000.json','["雨零花昼春杯举。", "举杯春昼花零雨。", "诗令酒行迟。", "迟行酒令诗。", "满斟犹换盏。", "盏换犹斟满。", "天转月光圆。", "圆光月转天。"]'),
('song-ci-164','菩萨蛮','王安中','宋','宋词','song-ci','菩萨蛮','[]','绿笺长写新成曲。',52,'宋词/ci.song.5000.json','["绿笺长写新成曲。", "曲成新写长笺绿。", "豪句逞才高。", "高才逞句豪。", "美容歌皓齿。", "齿皓歌容美。", "香篆小花团。", "团花小篆香。"]'),
('song-ci-165','菩萨蛮','王安中','宋','宋词','song-ci','菩萨蛮','[]','玉纤传酒浮香菊。',52,'宋词/ci.song.5000.json','["玉纤传酒浮香菊。", "菊香浮酒传纤玉。", "弦管沸欢筵。", "筵欢沸管弦。", "出帘珠袖蔌。", "蔌袖珠帘出。", "眉晕浅山低。", "低山浅晕眉。"]'),
('song-ci-166','菩萨蛮','王安中','宋','宋词','song-ci','菩萨蛮','[]','浦烟迷处回莲步。',52,'宋词/ci.song.5000.json','["浦烟迷处回莲步。", "步莲回处迷烟浦。", "罗绮媚横波。", "波横媚绮罗。", "细眉双拂翠。", "翠拂双眉细。", "歌意任情多。", "多情任意歌。"]'),
('song-ci-167','点绛唇','张继先','宋','宋词','song-ci','点绛唇','[]','小小葫芦，生来不大身材矮。',50,'宋词/ci.song.5000.json','["小小葫芦，生来不大身材矮。", "子儿在内。", "无口如何怪。", "藏得乾坤，此理谁人会。", "腰间带。", "臣今偏爱。", "胜挂金鱼袋。"]'),
('song-ci-168','忆桃源','张继先','宋','宋词','song-ci','忆桃源','[]','长生之话口相传。',56,'宋词/ci.song.5000.json','["长生之话口相传。", "求丹金液全。", "混成一物作神仙。", "丁宁说与贤。", "休咽气，莫胡言。", "岂知造化玄。", "用铅投汞汞投铅。", "分明颠倒颠。"]'),
('song-ci-169','忆桃源','张继先','宋','宋词','song-ci','忆桃源','[]','白云堆里采芙蓉。',56,'宋词/ci.song.5000.json','["白云堆里采芙蓉。", "枝枝香艳浓。", "灵龟畔岸起祥风。", "楼高十二重。", "黄金殿，碧云笼。", "丹砂透顶红。", "神机运处鬼神通。", "清真达上宫。"]'),
('song-ci-170','临江仙','张继先','宋','宋词','song-ci','临江仙','[]','莫怪精神都素淡，全谙千载松头。',70,'宋词/ci.song.5000.json','["莫怪精神都素淡，全谙千载松头。", "羽人幽意苦相投。", "殷勤争点写，展转动吟酬。", "况有咸阳兄弟事，教人闻见忘忧。", "我生曾是眷仙标。", "一从挥洒后，相继未能休。"]'),
('song-ci-171','临江仙','张继先','宋','宋词','song-ci','临江仙','[]','自古清真灵妙降，安妃来就杨君。',70,'宋词/ci.song.5000.json','["自古清真灵妙降，安妃来就杨君。", "因缘冥会异常伦。", "仙风聊设相，真道本无亲。", "惟有元规能访问，深将此意相闻。", "大家宜赏缀新文。", "免教尘世士，诮笑上天人。"]'),
('song-ci-172','临江仙','张继先','宋','宋词','song-ci','临江仙','[]','蠢动含灵天赋与，逍遥性分元均。',70,'宋词/ci.song.5000.json','["蠢动含灵天赋与，逍遥性分元均。", "莫生异见乱吾真。", "只今中有主，浑与化为人。", "那更徽词清彻底，轻埃欲染无因。", "惟应得此便凝神。", "百魔咸息战，六道永停轮。"]'),
('song-ci-173','沁园春','张继先','宋','宋词','song-ci','沁园春','[]','劫运将新，天书降恩，圣师命魔。',140,'宋词/ci.song.5000.json','["劫运将新，天书降恩，圣师命魔。", "正阴阳错忤，鬼神淆混，依凭城市，绵亘山河。", "杀气闭空，阴容夺昼，万姓罹殃日已多。", "青城上，见琉璃高座，忽起巍峨。", "群妖忿怒扬戈。", "竞奔走、攻山若舞梭。", "感神光一瞬，龙催虎陷，威音一动，电掣霆呵。", "立活化民，摄邪归正，生息熙熙享太和。", "风云静，见天连碧汉，月浸澄波。"]'),
('song-ci-174','沁园春','张继先','宋','宋词','song-ci','沁园春','[]','真一长存，太虚同体，妙门自开。',141,'宋词/ci.song.5000.json','["真一长存，太虚同体，妙门自开。", "既混元初判，两仪布景，复还根本，全籍灵台。", "浩气冲开，谷神滋化，渐觉神光空际来。", "幽绝处，听龙吟虎啸，蓦地风雷。", "奇哉。", "妙道难猜。", "鲜点化、愚迷成大材。", "试与君说破，分明状似，蚌含渊月，秋兔怀胎。", "壮志男儿，当年高士，莫把身心惹世埃。", "功成后，任身居紫府，名列仙阶。"]'),
('song-ci-175','沁园春','张继先','宋','宋词','song-ci','沁园春','[]','急急修行，细算人生，能有几时。',140,'宋词/ci.song.5000.json','["急急修行，细算人生，能有几时。", "任万般千种风流好，柰一朝身死，不免抛离。", "蓦地思量，死生事大，使我心如刀剑挥。", "难留住，那金乌箭疾，玉兔梭飞。", "早觉悟、莫教迟。", "我清净、谁能婚少妻。", "便假饶月里，姮娥见在，从他越国，有貌西施。", "此个风流，更无心恋，且放宽怀免是非。", "蓬莱路，仗三千行满，独跨鸾归。"]'),
('song-ci-176','沁园春','张继先','宋','宋词','song-ci','沁园春','[]','况有夷途，正透元关，众所共传。',138,'宋词/ci.song.5000.json','["况有夷途，正透元关，众所共传。", "愿万魔披散，诸尘荡尽，琴心和雅，天性清圆。", "未信凡流，可回高步，留恋形声情更延。", "真消息，定如何唤醒，聊证言诠。", "虽由宿命因缘。", "达士何曾无慨然。", "算尽专为妙，闲多乐少，一成潇洒，永绝忧煎。", "影照澄潭，声流虚谷，业火消亡睹瑞莲。", "安平泰，看坚完如地，长久如天。"]'),
('song-ci-177','满庭芳','张继先','宋','宋词','song-ci','满庭芳','[]','闲里工夫，无中妙用，切休拟议参详。',118,'宋词/ci.song.5000.json','["闲里工夫，无中妙用，切休拟议参详。", "龙降虎伏，真土自中黄。", "行动起居寝食，随缘度、莫动真阳。", "归根处，神凝脉住，玉界发天光。", "风高，鹏翼远，水深舟运，物理昭彰。", "但明心是道，专役天罡。", "信口呼神招鬼，和暘谷、不是颠狂。", "痴迷者，风霆在手，应用反乖张。"]'),
('song-ci-178','满庭芳','张继先','宋','宋词','song-ci','满庭芳','[]','心境双清，古今同乐，胜缘休道无媒。',118,'宋词/ci.song.5000.json','["心境双清，古今同乐，胜缘休道无媒。", "天门高妙，应仗至人开。", "岂比寻常意绪，方寸地、不贮纤埃。", "仍须信，金坚石确，一志断无回。", "真元，真可爱，真师真友，且喜无猜。", "就中更脱洒，不顾形骸。", "可是正容而悟，凭真趣、改易凡胎。", "神明会，尘缨世网，莫共话由来。"]'),
('song-ci-179','满庭芳','张继先','宋','宋词','song-ci','满庭芳','["\u8861\u5c71"]','调理三关，安和四体，静无忧扰相煎。',118,'宋词/ci.song.5000.json','["调理三关，安和四体，静无忧扰相煎。", "太微冥契，元始语诸仙。", "玉宇重修妙典，西台□、南岳题篇。", "崇□好，身田在世，心向太清天。", "云边。", "曾降圣，金坛夜拜，高驾留连。", "论琼华灵液，形与神全。", "形体须凭妙气，神来舍、黄阙丹田。", "真精旨，明光辅相，天地保长年。"]'),
('song-ci-180','洞仙歌','张继先','宋','宋词','song-ci','洞仙歌','[]','孤峰绝顶，更无人能到。',101,'宋词/ci.song.5000.json','["孤峰绝顶，更无人能到。", "万里虚空没边徼。", "正秋高景静，雾扫云收，风露里，惟有月华高照。", "浮生纷过客，好天良夜，醉舞狂歌错昏晓。", "有谁知、一性圆满恒河，亘万古、光明不老。", "竞对月、论利与谈名，全不想驹阴，暗催年少。"]'),
('song-ci-181','渔家傲','张继先','宋','宋词','song-ci','渔家傲','[]','草草开尊资一笑。',72,'宋词/ci.song.5000.json','["草草开尊资一笑。", "微生病苦随缘了。", "友义交情如地厚。", "心相照。", "今人莫遣前人诮。", "灯火荧荧山悄悄。", "芝兰佳气松筠茂。", "得便盘桓尘世表。", "香初透。", "邻鸡且莫催清晓。"]'),
('song-ci-182','更漏子','张继先','宋','宋词','song-ci','更漏子','[]','固元精，收听视。',58,'宋词/ci.song.5000.json','["固元精，收听视。", "物外身无此地。", "接子谬，季真非。", "无为翻有为。", "但心虚，教腹实。", "密与寥天为一。", "华阳洞，广寒宫。", "人人方寸中。"]'),
('song-ci-183','更漏子','张继先','宋','宋词','song-ci','更漏子','[]','是和非，双打过。',58,'宋词/ci.song.5000.json','["是和非，双打过。", "免共相魔生火。", "谈有相，损顽空。", "斋居看望中。", "圣贤风，行处在。", "巧智争如休卖。", "诗与酒，且乘闲。", "随缘发笑颜。"]'),
('song-ci-184','更漏子','张继先','宋','宋词','song-ci','更漏子','[]','诵真经，期万过。',58,'宋词/ci.song.5000.json','["诵真经，期万过。", "未灭无明心火。", "宜回首，探真空。", "融怡淡漠中。", "自古人，何处在。", "谩记声名沽卖。", "抛尘累，养清闲。", "琼浆自驻颜。"]'),
('song-ci-185','瑶台月','张继先','宋','宋词','song-ci','瑶台月','[]','天开景运。',154,'宋词/ci.song.5000.json','["天开景运。", "记建武中兴，炎刘重盛。", "明良际会，八表风调雨顺。", "任一时、岳降生申，正千载、河清诞圣。", "祥云拥，流霞映。", "飞仙拱，魁星炯。", "佳应是、师真毓瑞，人天交庆。", "蘅薇香满元宵景。", "耀天目、神光如镜。", "见龙章凤质，降伏群魔归正。", "禀玄元、立教开先，悟至道、心空神领。", "昌元嗣，明真镜。", "同无有，怡清净。", "绵永度，三途六道，神仙同证。"]'),
('song-ci-186','喜迁莺','张继先','宋','宋词','song-ci','喜迁莺','[]','深源密坞，问牧竖樵童，俱迷方所。',126,'宋词/ci.song.5000.json','["深源密坞，问牧竖樵童，俱迷方所。", "蓬藋纵横，龙蛇出没，玉峡搀空无路。", "不恋雁塔荣名，解守鱼渊寒素。", "这勤苦。", "但坚心自有，神灵呵护。", "猛悟。", "无回顾。", "一点虚明，万劫无今古。", "胎息根深，灵泉穴秘，静里运调阳火。", "莫问地久天长，管取收因结果。", "休轻负。", "把天谷真机，与君说破。"]'),
('song-ci-187','喜迁莺','张继先','宋','宋词','song-ci','喜迁莺','[]','情缠识缚，欢时人不悟，酒中真乐。',126,'宋词/ci.song.5000.json','["情缠识缚，欢时人不悟，酒中真乐。", "纵欲招愆，迷心失行，却道为他狂药。", "须信醉舞狂歌，也有良知真觉。", "无倚泊。", "任暖气同流，三关三络。", "落魄。", "清闲客。", "醉乡深处，风月长酬酢。", "空花消亡，光明显露，人我自皆忘却。", "不问市酝村醪，尽可浅斟低酌。", "从鄙薄。", "竞口口谈醒，言言成错。"]'),
('song-ci-188','雪夜渔舟','张继先','宋','宋词','song-ci','雪夜渔舟','[]','晚风歇。',124,'宋词/ci.song.5000.json','["晚风歇。", "谩自棹扁舟，顺流观雪。", "山耸瑶峰，林森玉树，高下尽无分别。", "性情澄彻。", "更没个、故人堪说。", "恍然身世，如居天上，水晶宫阙。", "万尘声影绝。", "透尘空无外，水天相接。", "浩气冲盈，真宫深厚，永夜不愁寒冽。", "愧怜鄙劣。", "只解道、赴炎趋热。", "停桡失笑，知心都付，野梅江月。"]'),
('song-ci-189','春从天上来','张继先','宋','宋词','song-ci','春从天上来','[]','王土平平。',128,'宋词/ci.song.5000.json','["王土平平。", "正海息波澜，岳敛云烟。", "三景虚明，八表澄清，一月普照诸天。", "有流霞洞焕，映黍珠、徐下空玄。", "绝形言。", "见千真拱极，万气朝元。", "当时鹤鸣夜半，感真符宝篆，特地清传。", "碧湛龙文，红凝龟篆，绛衣舞鬣蹁跹。", "计功成果就，无真教、郭景飞仙。", "已千年。", "亘灯灯续焰，光朗无边。"]'),
('song-ci-190','风入松','张继先','宋','宋词','song-ci','风入松','[]','深耕易耨寸田中。',92,'宋词/ci.song.5000.json','["深耕易耨寸田中。", "看真个英雄。", "夜来犹上星台望，全不厌、水绿云红。", "便是清交素友，频相视、笑晴空。", "玉阶瑶甃翠重重。", "带萱草葱葱。", "流霞尽饮何辞醉，更休数、尘里千锺。", "晓夜朝元去也，怎忍舍、大夫松。"]'),
('song-ci-191','摸鱼儿','张继先','宋','宋词','song-ci','摸鱼儿','[]','甚山灵、斗奇夸巧，悬峰遥献形似。',140,'宋词/ci.song.5000.json','["甚山灵、斗奇夸巧，悬峰遥献形似。", "仓船炉灶无封闭，零落车罗机履。", "山临水。", "任瓮杵、辘轳厩架俱闲毁。", "床棺尘委。", "更乐隐棋休，料闲真隐，三教忘宾主。", "人都语，二十四岩佳致。", "来往溯流观指。", "目前景相纷虚幻，神仙家在何许。", "君莫取。", "这身世、山林朝市随缘遇。", "休论诡异。", "但总绝情缘，一空妍丑，觌面先寻你。"]'),
('song-ci-192','惜时芳・思归乐','张继先','宋','宋词','song-ci','惜时芳・思归乐','[]','虚心劲节争萧散。',68,'宋词/ci.song.5000.json','["虚心劲节争萧散。", "无冬夏、钩阑侧畔。", "霜风雪色沈沈晚。", "残不了、细枝纤干。", "情中意里尘沙恨。", "试与聆、弦歌急慢。", "无嫌青翠开青眼。", "相看似、太原家惯。"]'),
('song-ci-193','清平乐','张继先','宋','宋词','song-ci','清平乐','[]','天先天后。',54,'宋词/ci.song.5000.json','["天先天后。", "真土藏灵秀。", "妙用自然循火候。", "节节薰烝教透。", "不分龙麝檀沈。", "都能入鼻通心。", "待得烟消息住，浑身变见真金。"]'),
('song-ci-194','苏幕遮','张继先','宋','宋词','song-ci','苏幕遮','[]','先天生，后天久。',38,'宋词/ci.song.5000.json','["先天生，后天久。", "道有真诠，谛听当时受。", "恰是迷天迷望斗。", "只恐微躯，薄幸随枯朽。"]'),
('song-ci-195','苏幕遮','张继先','宋','宋词','song-ci','苏幕遮','[]','抱孤琴，弹小操。',76,'宋词/ci.song.5000.json','["抱孤琴，弹小操。", "独坐幽轩，尽日无人到。", "惟乐烟霞长啸傲。", "明月清风，今古长为道。", "识乾坤，知牝牡。", "懒共尘劳，汨汨争奔走。", "爱杀高眠消白昼。", "一任他家，玉兔金乌走。"]'),
('song-ci-196','西江月','张继先','宋','宋词','song-ci','西江月','[]','蓬户横开岑寂，寒窗侧映清晖。',58,'宋词/ci.song.5000.json','["蓬户横开岑寂，寒窗侧映清晖。", "竹风偷入五香帏。", "还有好音相惠。", "须信毫芒可入，明珠胎里忘机。", "宵征夜宴是和非。", "月府仙人无愧。"]'),
('song-ci-197','南乡子','张继先','宋','宋词','song-ci','南乡子','[]','无奈这群迷。',66,'宋词/ci.song.5000.json','["无奈这群迷。", "味色声中若系羁。", "尽任改头兼换面，何悲。", "不染伊时不管伊。", "春去又秋兮。", "莫遣空逾十二时。", "好把自然真妙旨，修为。", "尘事萦仍道甚希。"]'),
('song-ci-198','南乡子','张继先','宋','宋词','song-ci','南乡子','[]','久不上春台。',66,'宋词/ci.song.5000.json','["久不上春台。", "直待将身跨九垓。", "懒向人间深有谓，氛埃。", "难趁邪风伤圣胎。", "水栏映山斋。", "赏遍从容首自回。", "长谢故人书曲意，徽哉。", "赢得腰琴拂袂来。"]'),
('song-ci-199','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','楸枰静，黑白两奁均。',64,'宋词/ci.song.5000.json','["楸枰静，黑白两奁均。", "山水最宜情共乐，琴书赢得道相亲。", "一局一番新。", "松影里，轻度几回春。", "随分也曾施手段，争先还恐费精神。", "长是暗饶人。"]'),
('song-ci-200','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，仙构占仙峰。',64,'宋词/ci.song.5000.json','["西源好，仙构占仙峰。", "一鹤性灵清我宇，万龙风雨乱霜空。", "高静太疏慵。", "天地乐，山水静流通。", "行坐卧怜尘外景，虚空寂是道家风。", "非细乐相从。"]'),
('song-ci-201','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，龙首虎头高。',64,'宋词/ci.song.5000.json','["西源好，龙首虎头高。", "风雨每掀清宇宙，林峦长似涌波涛。", "吟咏有诗豪。", "成大乐，美称适相遭。", "醮斗清筵投羽札，启元喜会执金刀。", "身净隔纷骚。"]'),
('song-ci-202','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，岩馆凿松厓。',64,'宋词/ci.song.5000.json','["西源好，岩馆凿松厓。", "五斗洞前斟玉斝，半酣窗外抚金杯。", "无累自悠哉。", "青翠色，玉竹自新栽。", "风到莫来摇老木，雨霖时复洗圆苔。", "如此恼诗才。"]'),
('song-ci-203','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，春日日初长。',64,'宋词/ci.song.5000.json','["西源好，春日日初长。", "不看人间三月景，常思天上万花香。", "幽赏一时狂。", "歌笑也，空洞大歌章。", "千景净来风谷秀，三云归后月林光。", "沈麝似兰香。"]'),
('song-ci-204','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，迎夏洒炎风。',64,'宋词/ci.song.5000.json','["西源好，迎夏洒炎风。", "红锦石边怜一派，老张岩上恋群峰。", "时得化龙筇。", "琴振玉，晓色倚梧桐。", "黼黻文章朝内盛，山川林木野亭空。", "朱火焕明中。"]'),
('song-ci-205','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，秋景道人怜。',64,'宋词/ci.song.5000.json','["西源好，秋景道人怜。", "时至自然天气肃，夜凉犹喜月华圆。", "长啸碧崖颠。", "须信酒，难别咏歌边。", "是处伐薪为炭后，此时尝稻庆丰年。", "童子舞胎仙。"]'),
('song-ci-206','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，冬日雪中松。',64,'宋词/ci.song.5000.json','["西源好，冬日雪中松。", "携手石坛承爱景，静观天地入清宫。", "恰似大茅峰。", "襟袂冷，琴里意浓浓。", "吹月洞箫含碧玉，动人佳趣转黄锺。", "情绪发於中。"]'),
('song-ci-207','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，幽径不成斜。',64,'宋词/ci.song.5000.json','["西源好，幽径不成斜。", "山谷隐连无改色，池塘空静默无瑕。", "人钓水之涯。", "仙舫小，人欲盼君家。", "归棹日回如览镜，放船星落似乘槎。", "风雨乱寒沙。"]'),
('song-ci-208','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，神洞自相求。',64,'宋词/ci.song.5000.json','["西源好，神洞自相求。", "傍水垦田流涧急，砍山开径小花浮。", "踪迹旧人留。", "忘万物，爽气白云收。", "司命暂曾寻寝静，紫阳真是步条幽。", "思继此公游。"]'),
('song-ci-209','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，人在水晶宫。',64,'宋词/ci.song.5000.json','["西源好，人在水晶宫。", "长愿玉津名濯鼎，恰如龙井到天峰。", "的的好遗风。", "清彻底，岂忤李唐隆。", "自浸岩前崖石洁，不笼天外岭云浓。", "澄彻莹怀中。"]'),
('song-ci-210','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，雨霁敛红纱。',64,'宋词/ci.song.5000.json','["西源好，雨霁敛红纱。", "碧水静摇招钓叟，绿苔寒迫起渔家。", "携驾会春茶。", "风浩浩，锦荫石屏华。", "濯鼎上方敲翠竹，辘轳西去碎丹砂。", "休问乐津涯。"]'),
('song-ci-211','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','[]','西源好，还向观庭西。',64,'宋词/ci.song.5000.json','["西源好，还向观庭西。", "拚晚菊明方丈外，傍寒梅放六花飞。", "三鹤会同时。", "清净宇，处一贯无为。", "戴月夜中仍是别，衔香原上不须迷。", "於此振衣归。"]'),
('song-ci-212','减字木兰花','张继先','宋','宋词','song-ci','减字木兰花','[]','严寒冬月。',52,'宋词/ci.song.5000.json','["严寒冬月。", "前日阳生几降雪。", "松柏凌霄。", "森耸庭中叹后凋。", "昔人犹豫。", "身入山林深静处。", "今古同符。", "好趁笙歌且自娱。"]'),
('song-ci-213','江神子・江城子','张继先','宋','宋词','song-ci','江神子・江城子','[]','彩云楼阁瑞烟平。',86,'宋词/ci.song.5000.json','["彩云楼阁瑞烟平。", "雨初晴。", "月胧明。", "夜静天风，吹下步虚声。", "何处朝元归去晚，双凤小，五云轻。", "落花流水两关情。", "恨无凭。", "梦难成。", "倚遍阑干，依旧楚风清。", "露滴松梢人静也，开宝篆，诵黄庭。"]'),
('song-ci-214','鹊桥仙','张继先','宋','宋词','song-ci','鹊桥仙','[]','神清心妙，山长水远，有分何年瞻望。',68,'宋词/ci.song.5000.json','["神清心妙，山长水远，有分何年瞻望。", "晴空一月彩云飞，又起我、无穷想像。", "一阳门径，九华恩露，惟愿分明指向。", "竹风频起紫微烟，似有意、许归吾党。"]'),
('song-ci-215','水调歌头','张继先','宋','宋词','song-ci','水调歌头','[]','高真留妙诀，达士济群迷。',114,'宋词/ci.song.5000.json','["高真留妙诀，达士济群迷。", "心清行洁，天人凡圣尽皈依。", "不在搬精运气，不在飞罡蹑斗，心乱转狐疑。", "但要除邪妄，心地合神祗。", "悟真空，离世网，绝关机。", "养吾浩气，驱雷役电震天威。", "混合百神归一，一念通天彻地，方始了无为。", "叱咤生风雨，玩世挟明时。"]'),
('song-ci-216','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','一更一点一更初。',64,'宋词/ci.song.5000.json','["一更一点一更初。", "城门半掩行人疏。", "茅庵潇洒一事无。", "孤灯相对光清虚。", "蒲团安稳身不拘。", "跏趺大坐心如如。", "月轮微出天东隅。", "空中露出无名珠。"]'),
('song-ci-217','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','二更二点二更深。',64,'宋词/ci.song.5000.json','["二更二点二更深。", "宫锺声绝夜沈沈。", "明月满天如写金。", "同光共影无昏沈。", "起来闲操无弦琴。", "声高调古惊人心。", "琴罢独歌还独吟。", "松风涧水俱知音。"]'),
('song-ci-218','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','三更三点三更中。',64,'宋词/ci.song.5000.json','["三更三点三更中。", "烟开雾敛静无风。", "月华迸入水晶宫。", "四方上下同一空。", "光明遍转华胥同。", "千古万古无初终。", "铁蛇飞舞如流虹。", "倒骑白凤游崆峒。"]'),
('song-ci-219','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','四更四点四更长。',64,'宋词/ci.song.5000.json','["四更四点四更长。", "迎午迸鼠心不忙。", "丹炉伏火生新香。", "群阴剥尽回真阳。", "金娥木父欢相当。", "醍醐次进无停觞。", "主宾倒置情不伤。", "更阑别去还相忘。"]'),
('song-ci-220','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','五更五点五更残。',64,'宋词/ci.song.5000.json','["五更五点五更残。", "青冥风露逼人寒。", "扶桑推出红银盘。", "城门依旧声尘喧。", "明暗二景交相转。", "生来死去纷易换。", "道人室中天宇宽。", "日出三竿万启关。"]'),
('song-ci-221','度清霄','张继先','宋','宋词','song-ci','度清霄','[]','独自行兮独自坐。',64,'宋词/ci.song.5000.json','["独自行兮独自坐。", "独自歌兮独自和。", "日日街头走一过。", "我不识吾谁识我。", "人间旦暮自四时。", "玄中消息不推移。", "觌面相呈知不知。", "知时自唱罗罗哩。"]'),
('song-ci-222','望江南・忆江南','张继先','宋','宋词','song-ci','望江南・忆江南','["\u9ec4\u6cb3"]','秋夜事，月里竹亭亭。',64,'宋词/ci.song.5000.json','["秋夜事，月里竹亭亭。", "清籁与谁喧池水，微风遣我下檐楹。", "圆缺若为情。", "终南道，累寄笑歌声。", "丹阙夜凉通马去，黄河天晓照舟横。", "联辔去还成。"]'),
('song-ci-223','贺新郎','叶梦得','宋','宋词','song-ci','贺新郎','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','睡起啼莺语。',142,'宋词/ci.song.5000.json','["睡起啼莺语。", "掩青苔、房栊向晚，乱红无数。", "吹尽残花无人见，惟有垂杨自舞。", "渐暖霭、初回轻暑。", "宝扇重寻明月影，暗尘侵、尚有乘鸾女。", "惊旧恨，遽如许。", "江南梦断横江渚。", "浪黏天、葡萄涨绿，半空烟雨。", "无限楼前沧波意，谁采苹花寄取。", "但怅望、兰舟容与。", "万里云帆何时到，送孤鸿、目断千山阻。", "谁为我，唱金缕。"]'),
('song-ci-224','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','渺渺楚天阔，秋水去无穷。',114,'宋词/ci.song.5000.json','["渺渺楚天阔，秋水去无穷。", "两淮不辨牛马，轻浪舞回风。", "独倚高台一笑，圉圉游鱼来往，还戏此波中。", "危栏对千里，落日照澄空。", "子非我，安知我，意真同。", "鹏飞鲲化何有，沧海漫冲融。", "堪笑磻溪遣老，白首直钩溪畔，岁晚忽衰翁。", "功业竟安在，徒自兆非熊。"]'),
('song-ci-225','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','霜降碧天静，秋事促西风。',114,'宋词/ci.song.5000.json','["霜降碧天静，秋事促西风。", "寒声隐地，初听中夜入梧桐。", "起瞰高城回望，寥落关河千里，一醉与君同。", "叠鼓闹清晓，飞骑引雕弓。", "岁将晚，客争笑，问衰翁。", "平生豪气安在，沈领为谁雄。", "何似当筵虎士，挥手弦声响处，双雁落遥空。", "老矣真堪愧，回首望云中。"]'),
('song-ci-226','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','江海渺千里，飘荡叹流年。',114,'宋词/ci.song.5000.json','["江海渺千里，飘荡叹流年。", "等闲匹马相过，乘兴却け然。", "十载悲欢如梦，抚掌惊呼相语，往事尽飞烟。", "此会真难偶，此醉且留连。", "酒方半，谁轻使，动离弦。", "我歌未阕公去，明日复山川。", "空有高城危槛，缥缈当筵清唱，馀响落尊前。", "细雨黄花后，飞雁点遥天。"]'),
('song-ci-227','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','修眉扫遥碧，清镜走回流。',114,'宋词/ci.song.5000.json','["修眉扫遥碧，清镜走回流。", "堤外柳烟深浅，碧瓦起朱楼。", "分付平云千里，包卷骚人遗思，春色入帘钩。", "桃李尽无语，波影动兰舟。", "念谢公，平生志，在沧洲。", "登临漫怀风景，佳处每难酬。", "却叹从来贤士，如我与公多矣，名迹竟谁留。", "惟有尊前醉，何必问消忧。"]'),
('song-ci-228','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','今古几流转，身世两奔忙。',114,'宋词/ci.song.5000.json','["今古几流转，身世两奔忙。", "那知一丘一壑，何处不堪藏。", "须信超然物外，容易扁舟相踵，分占水云乡。", "雅志真无负，来日故应长。", "问骐骥，空矫首，为谁昂。", "冥鸿天际，尘事分付一轻芒。", "认取骚人生此，但有轻蓬短楫，多制芰荷裳。", "一笑陶彭泽，千载贺知章。"]'),
('song-ci-229','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','河汉下平野，香雾卷西风。',114,'宋词/ci.song.5000.json','["河汉下平野，香雾卷西风。", "倚空千嶂横起，银阙正当中。", "常恨年年此夜，醉倒歌呼谁和，何事偶君同。", "莫恨岁华晚，容易感梧桐。", "揽清影，君试与，问天公。", "遥知玉斧初斫，重到广寒宫。", "付与孤光千里，不遣微云点缀，为我洗长空。", "老去狂犹在，应未笑衰翁。"]'),
('song-ci-230','水调歌头','叶梦得','宋','宋词','song-ci','水调歌头','[]','秋色渐将晚，霜信报黄花。',114,'宋词/ci.song.5000.json','["秋色渐将晚，霜信报黄花。", "小窗低户深映，微路绕敧斜。", "为问山翁何事，坐看流年轻度，拚却鬓双华。", "徙倚望沧海，天净水明霞。", "念平昔，空飘荡，遍天涯。", "归来三径重扫，松竹本吾家。", "却恨悲风时起，冉冉云间新雁，边马怨胡笳。", "谁似东山老，谈笑静胡沙。"]'),
('song-ci-231','八声甘州','叶梦得','宋','宋词','song-ci','八声甘州','[]','故都迷岸草，望长淮、依然绕孤城。',119,'宋词/ci.song.5000.json','["故都迷岸草，望长淮、依然绕孤城。", "想乌衣年少，芝兰秀发，戈戟云横。", "坐看骄兵南渡，沸浪骇奔鲸。", "转盼东流水，一顾功成。", "千载八公山下，尚断崖草木，遥拥峥嵘。", "漫云涛吞吐，无处问豪英。", "信劳生、空成今古，笑我来、何事怆遗情。", "东山老，可堪岁晚，独听桓筝。"]'),
('song-ci-232','八声甘州','叶梦得','宋','宋词','song-ci','八声甘州','[]','又新正过了，问东风、消息几时来。',119,'宋词/ci.song.5000.json','["又新正过了，问东风、消息几时来。", "笑春工多思，留连底事，犹未轻回。", "应为瑶刀裁翦，容易惜花开。", "试向湖边望，几处寒梅。", "好是绿莎新径，剩安排芳意，特地重栽。", "便从今追赏，莫遣暂停杯。", "有千株、深红浅白，倩缓歌、急管与相催。", "凭看取，暖烟细霭，先到高台。"]'),
('song-ci-233','八声甘州','叶梦得','宋','宋词','song-ci','八声甘州','[]','问浮家泛宅，自玄真、去后有谁来。',119,'宋词/ci.song.5000.json','["问浮家泛宅，自玄真、去后有谁来。", "漫烟波千顷，云峰倒影，空翠成堆。", "可是溪山无主，佳处却徘徊。", "暮雨卷晴野，落照天开。", "老去馀生江海，伴远公香火，犹有宗雷。", "便何妨元亮，携酒间相陪。", "寄清谈、芒鞋筇杖，更尽驱、风月入尊罍。", "江村路，我歌君和，莫棹船回。"]'),
('song-ci-234','八声甘州','叶梦得','宋','宋词','song-ci','八声甘州','[]','寄知还倦鸟，对飞云、无心两难齐。',119,'宋词/ci.song.5000.json','["寄知还倦鸟，对飞云、无心两难齐。", "漫飘然欲去，悠然且止，依旧山西。", "十亩荒园未遍，趁雨却锄犁。", "敢忘邻翁约，有酒同携。", "况是岩前新创，带小轩横绝，松桂成蹊。", "试凭高东望，云海与天低。", "送沧波、浮空千里，照断霞、明灭卷晴霓。", "君休笑，此生心事，老更沈迷。"]'),
('song-ci-235','念奴娇','叶梦得','宋','宋词','song-ci','念奴娇','[]','故山渐近，念渊明归意，け然论谁。',120,'宋词/ci.song.5000.json','["故山渐近，念渊明归意，け然论谁。", "归去来兮秋已老，松菊三径犹存。", "稚子欢迎，飘飘风袂，依约旧衡门。", "琴书萧散，更欣有酒盈尊。", "惆怅萍梗无根，天涯行已遍，空负田园。", "去矣何之窗户小，容膝聊倚南轩。", "倦鸟知还，晚云遥映，山气欲黄昏。", "此还真意，故应欲辨忘言。"]'),
('song-ci-236','念奴娇','叶梦得','宋','宋词','song-ci','念奴娇','["\u6d1e\u5ead\u6e56"]','洞庭波冷，望冰轮初转，沧海沈沈。',120,'宋词/ci.song.5000.json','["洞庭波冷，望冰轮初转，沧海沈沈。", "万顷孤光云阵卷，长笛吹破层阴。", "汹涌三江，银涛无际，遥带五湖深。", "酒阑歌罢，至今鼍怒龙吟。", "回首江海平生，漂流容易散，佳期难寻。", "缥缈高城风露爽，独倚危栏重临。", "醉倒清尊，姮娥应笑，犹有向来心。", "广寒宫殿，为予聊借琼林。"]'),
('song-ci-237','念奴娇','叶梦得','宋','宋词','song-ci','念奴娇','[]','云峰横起，障吴关三面，真成尤物。',120,'宋词/ci.song.5000.json','["云峰横起，障吴关三面，真成尤物。", "倒卷回潮目尽处，秋水黏天无壁。", "绿鬓人归，如今虽在，空有千茎雪。", "追寻如梦，满馀诗句犹杰。", "闻道尊酒登临，孙郎终古恨，长歌时发。", "万里云屯瓜步晚，落日旌旗明灭。", "鼓吹风高，画船遥想，一笑吞穷发。", "当时曾照，更谁重问山月。"]'),
('song-ci-238','满庭芳','叶梦得','宋','宋词','song-ci','满庭芳','[]','麦陇如云，清风吹破，夜来疏雨才晴。',118,'宋词/ci.song.5000.json','["麦陇如云，清风吹破，夜来疏雨才晴。", "满川烟草，残照落微明。", "缥渺危栏曲槛，遥天尽、日脚初平。", "青林外，参差暝霭，萦带远山横。", "孤城。", "春雨过，绿阴是处，时有莺声。", "问落絮游丝，毕竟何成。", "信步苍苔绕遍，真堪付、闲客闲行。", "微吟罢，重回皓首，江海渺遗情。"]'),
('song-ci-239','满庭芳','叶梦得','宋','宋词','song-ci','满庭芳','[]','枫落吴江，扁舟摇荡，暮山斜照催晴。',118,'宋词/ci.song.5000.json','["枫落吴江，扁舟摇荡，暮山斜照催晴。", "此心长在，秋水共澄明。", "底事经年易判，惊遗恨、悄悄难平。", "临风处，佳人万里，霜笛与谁横。", "长城。", "谁敢犯，知君五字，元有诗声。", "笑茅舍何时，归计真成。", "绿鬓朱颜老尽，柴车在、行即终行。", "聊相待，狂歌醉舞，虽老未忘情。"]'),
('song-ci-240','满庭芳','叶梦得','宋','宋词','song-ci','满庭芳','[]','一曲离歌，烟村人去，马头微雪新晴。',118,'宋词/ci.song.5000.json','["一曲离歌，烟村人去，马头微雪新晴。", "隔年光景，回首近清明。", "断送残花又老，春波净、湖水初平。", "谁重到，雕阑尽日，遥想画桥横。", "高城。", "凝望久，何人为我，重唱馀声。", "问桃李如今，几处阴成。", "老去从游似梦，尊前事、空有经行。", "犹能记，殷勤寄语，多谢故人情。"]'),
('song-ci-241','满江红','叶梦得','宋','宋词','song-ci','满江红','[]','一朵黄花，先催报、秋归消息。',112,'宋词/ci.song.5000.json','["一朵黄花，先催报、秋归消息。", "满芳枝凝露，为谁装饰。", "便向尊前拚醉倒，古今同是东篱侧。", "问何须、特地赋归来，抛彭泽。", "回首去，年时节。", "开口笑，真难得。", "史君今郡更，自成行客。", "霜鬓不辞重插满，他年此会何人忆。", "记多情、曾伴小阑干，亲攀摘。"]'),
('song-ci-242','满江红','叶梦得','宋','宋词','song-ci','满江红','[]','雪后郊原，烟林静、梅花初坼。',112,'宋词/ci.song.5000.json','["雪后郊原，烟林静、梅花初坼。", "春欲半，犹自探春消息。", "一眼平芜看不尽，夜来小雨催新碧。", "笑去年、携酒折花人，花应识。", "兰舟漾，城南陌。", "云影淡，天容窄。", "绕风漪十顷，暖浮晴色。", "恰似槎头收钓处，坐中仍有江南客。", "问何如、雨桨下苕溪，吞云泽。"]'),
('song-ci-243','应天长','叶梦得','宋','宋词','song-ci','应天长','[]','松陵秋已老，正柳岸田家，酒醅初熟。',116,'宋词/ci.song.5000.json','["松陵秋已老，正柳岸田家，酒醅初熟。", "鲈脍莼羹，万里水天相续。", "扁舟凌浩渺，寄一叶、暮涛吞沃。", "青箬笠，西塞山前，自翻新曲。", "来往未应足。", "便细雨斜风，有谁拘束。", "陶写中年，何待更须丝竹。", "鸱夷千古意，算入手、比来尤速。", "最好是，千点云峰，半篙澄绿。"]'),
('song-ci-244','定风波','叶梦得','宋','宋词','song-ci','定风波','[]','破萼初惊一点红。',73,'宋词/ci.song.5000.json','["破萼初惊一点红。", "又看青子映帘栊。", "冰雪肌肤谁复见。", "清浅。", "尚馀疏影照晴空。", "惆怅年年桃李伴。", "肠断。", "只应芳信负东风。", "待得微黄春亦暮。", "烟雨。", "半和飞絮作濛濛。"]'),
('song-ci-245','定风波','叶梦得','宋','宋词','song-ci','定风波','[]','渺渺空波下夕阳。',73,'宋词/ci.song.5000.json','["渺渺空波下夕阳。", "睡痕初破水风凉。", "过雨归云留不住。", "何处。", "远村烟树半微茫。", "莫笑经年人老矣。", "归计。", "得迟留处也何妨。", "老子兴来殊不浅。", "帘卷。", "更邀明月坐胡床。"]'),
('song-ci-246','定风波','叶梦得','宋','宋词','song-ci','定风波','[]','千步长虹跨碧流。',73,'宋词/ci.song.5000.json','["千步长虹跨碧流。", "两山浮影转螭头。", "付与诗人都总领。", "风景。", "更逢仙客下瀛洲。", "袅袅凉风吹汗漫。", "平岸。", "遥空新卷绛河收。", "却怪姮娥真好事。", "须记。", "探支明月作中秋。"]'),
('song-ci-247','定风波','叶梦得','宋','宋词','song-ci','定风波','[]','斜汉初看素月流。',73,'宋词/ci.song.5000.json','["斜汉初看素月流。", "坐惊金饼出云头。", "华发萧然吹素领。", "光景。", "何妨分付属沧洲。", "莫待霜花飘烂漫。", "苹岸。", "更凭佳句尽拘收。", "解与破除消万事。", "犹记。", "一尊同得二年秋。"]'),
('song-ci-248','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','碧潭浮影蘸红旗。',86,'宋词/ci.song.5000.json','["碧潭浮影蘸红旗。", "日初迟。", "漾晴漪。", "我欲寻芳，先遣报春知。", "尽放百花连夜发，休更待，晓风吹。", "满携尊酒弄繁枝。", "与佳期。", "伴群嬉。", "犹有邦人，争唱醉翁词。", "应笑今年狂太守，能痛饮，似当时。"]'),
('song-ci-249','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','翩迁飞舞半空来。',86,'宋词/ci.song.5000.json','["翩迁飞舞半空来。", "晓风催。", "巧萦回。", "野旷天遥，回望兴悠哉。", "欲问玉京知远近，试携手，上高台。", "云涛无际卷崔嵬。", "敛浮埃。", "照琼瑰。", "点缀林花，真个是多才。", "说与化工留妙手，休尽放，一时开。"]'),
('song-ci-250','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','芙蓉开过雨初晴。',86,'宋词/ci.song.5000.json','["芙蓉开过雨初晴。", "曲池平。", "画桥横。", "耿耿银河，遥下蘸空明。", "一舸吴松归未得，聊共住，小蓬瀛。", "问君何事引前旌。", "趣归程。", "背高城。", "鱼鸟三年，谁道总无情。", "试遣他年歌此曲，应尚记，别时声。"]'),
('song-ci-251','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','生涯何有但青山。',86,'宋词/ci.song.5000.json','["生涯何有但青山。", "小溪湾。", "转潺湲。", "投老归来，终寄此山间。", "茅舍半敧风雨横，荒径晚，乱榛菅。", "强扶衰病上巉巅。", "水云闲。", "伴跻攀。", "湖海苍茫，千里在吴关。", "漫有一杯聊自醉，休更问，鬓毛斑。"]'),
('song-ci-252','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','甘泉祠殿汉离宫。',86,'宋词/ci.song.5000.json','["甘泉祠殿汉离宫。", "五云中。", "渺难穷。", "永漏通宵，壶矢转金铜。", "曾从钧天知帝所，孤鹤老，寄辽东。", "强扶衰病步龙锺。", "雪花濛。", "打窗风。", "一点青灯，惆怅伴南宫。", "惟有史君同此恨，丹凤□，水云重。"]'),
('song-ci-253','江城子','叶梦得','宋','宋词','song-ci','江城子','[]','银涛无际卷蓬瀛。',86,'宋词/ci.song.5000.json','["银涛无际卷蓬瀛。", "落霞明。", "暮云平。", "曾见青鸾、紫凤下层城。", "二十五弦弹不尽，空感慨，惜馀情。", "苍梧烟水断归程。", "卷霓旌。", "为谁迎。", "空有千行，流泪寄幽贞。", "舞罢鱼龙云海晚，千古恨，入江声。"]'),
('song-ci-254','竹马儿','叶梦得','宋','宋词','song-ci','竹马儿','[]','与君记，平山堂前细柳，几回同挽。',125,'宋词/ci.song.5000.json','["与君记，平山堂前细柳，几回同挽。", "又征帆夜落，危槛依旧，遥临云巘。", "自笑来往匆匆，朱颜渐改，故人俱远。", "横笛想遗声，但寒松千丈，倾崖苍藓。", "世事终何已，田阴纵在，岁阴仍晚。", "稽康老来尤懒。", "只要莼羹菰饭。", "却欲便买茅庐，短篷轻楫，尊酒犹能办。", "君能过我，水云聊为伴。"]'),
('song-ci-255','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','小雨初回昨夜凉。',48,'宋词/ci.song.5000.json','["小雨初回昨夜凉。", "绕篱新菊已催黄。", "碧空无际卷苍茫。", "千里断鸿供远目，十年芳草挂愁肠。", "缓歌聊与送瑶觞。"]'),
('song-ci-256','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','睡粉轻消露脸新。',48,'宋词/ci.song.5000.json','["睡粉轻消露脸新。", "醉红初破玉肌匀。", "尊前留得两州春。", "剩挽雕盘敧醉帽，重催飞骑走红尘。", "十年兰茝笑骚人。"]'),
('song-ci-257','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','荷叶荷花水底天。',48,'宋词/ci.song.5000.json','["荷叶荷花水底天。", "玉壶冰酒酿新泉。", "一欢聊复记他年。", "我亦故山归去客，与君分手暂流连。", "佳人休唱好因缘。"]'),
('song-ci-258','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','休笑山翁不住山。',48,'宋词/ci.song.5000.json','["休笑山翁不住山。", "二年偷向此中闲。", "归来赢得鬓毛斑。", "瓮底新醅供酩酊，城头曲槛俯淙潺。", "山翁老去此山间。"]'),
('song-ci-259','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','绛蜡烧残夜未分。',48,'宋词/ci.song.5000.json','["绛蜡烧残夜未分。", "宝筝声缓拍初匀。", "斗枢光照坐生春。", "便恐赐环归衮绣，莫辞挥翰落烟云。", "凤城西去断离魂。"]'),
('song-ci-260','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','绿野歌欢喜见分。',48,'宋词/ci.song.5000.json','["绿野歌欢喜见分。", "骤惊和气晓来匀。", "妙歌谁敢和阳春。", "梅蕊旧年迎腊雪，月华今夜破寒云。", "独醒争笑楚人魂。"]'),
('song-ci-261','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','物外光阴不属春。',48,'宋词/ci.song.5000.json','["物外光阴不属春。", "且留风景伴佳辰。", "醉归谁管断肠人。", "柳絮尚飘庭下雪，梨花空作梦中云。", "竹间篱落水边门。"]'),
('song-ci-262','浣溪沙','叶梦得','宋','宋词','song-ci','浣溪沙','[]','千古风流咏白苹。',48,'宋词/ci.song.5000.json','["千古风流咏白苹。", "二年歌笑拥朱轮。", "翩翩却忆上林春。", "剑履便应陪北阙，裤襦那更假西人。", "玉堂金殿要词臣。"]'),
('song-ci-263','永遇乐','叶梦得','宋','宋词','song-ci','永遇乐','["\u6d1e\u5ead\u6e56"]','苹芷芳州，故人回首，云海何处。',128,'宋词/ci.song.5000.json','["苹芷芳州，故人回首，云海何处。", "五亩荒田，殷勤问我，归计真成否。", "洞庭波冷，秋风袅袅，木叶乱随风舞。", "记扁舟、横斜载月，目极暮涛烟渚。", "传声试问，垂虹千顷，兰棹有谁重驻。", "雪溅雷翻，潮头过后，帆影敧前浦。", "此中高兴，何人解道，天也未应轻付。", "且留取、千锺痛饮，与君共赋。"]'),
('song-ci-264','永遇乐','叶梦得','宋','宋词','song-ci','永遇乐','[]','天末山横，半空箫鼓，楼观高起。',128,'宋词/ci.song.5000.json','["天末山横，半空箫鼓，楼观高起。", "指点栽成，东风满院，总是新桃李。", "纶巾羽扇，一尊饮罢，目送断鸿千里。", "揽清歌、馀音不断，缥缈尚萦流水。", "年来自笑无情，何事犹有，多情遗思。", "绿鬓朱颜，匆匆拚了，却记花前醉。", "明年春到，重寻幽梦，应在乱莺声里。", "拍阑干、斜阳转处，有谁共倚。"]'),
('song-ci-265','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','闻道今年春信早，梅花不怕馀寒。',70,'宋词/ci.song.5000.json','["闻道今年春信早，梅花不怕馀寒。", "凭君先向近南看。", "香苞开遍未。", "莫待北枝残。", "肠断陇头他日恨，江南几驿征鞍。", "一杯聊与尽馀欢。", "风情何似我，老去未应阑。"]'),
('song-ci-266','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','梦里江南浑不记，祗君幽户难忘。',70,'宋词/ci.song.5000.json','["梦里江南浑不记，祗君幽户难忘。", "夜来急雪绕东堂。", "竹窗松径里，何处问归航。", "瓮底新醅应已熟，一尊知与谁尝。", "会须雄笔卷苍茫。", "雪涛声隐户，琼玉照颓墙。"]'),
('song-ci-267','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','不见跳鱼翻曲港，湖边特地经过。',68,'宋词/ci.song.5000.json','["不见跳鱼翻曲港，湖边特地经过。", "萧萧疏雨乱风荷。", "微云吹散，凉月坠平波。", "白酒一杯还径醉，归来散发婆娑。", "无人能唱采莲歌。", "小轩敧枕，檐影挂星河。"]'),
('song-ci-268','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','碧瓦新霜侵晓梦，黄花已过清秋。',70,'宋词/ci.song.5000.json','["碧瓦新霜侵晓梦，黄花已过清秋。", "风帆何处挂扁舟。", "故人归欲尽，残日更回头。", "乐圃桥边烦借问，有人高卧江楼。", "寄声聊为诉离忧。", "桂丛应已老，何事久淹留。"]'),
('song-ci-269','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','闻道安车来过我，百花未敢飘零。',70,'宋词/ci.song.5000.json','["闻道安车来过我，百花未敢飘零。", "疾催弦管送杯行。", "五朝瞻旧老，挥麈听风生。", "凤诏远从天上落，高堂燕喜初醒。", "莫言白发减风情。", "此时谁得似，饮罢却精明。"]'),
('song-ci-270','临江仙','叶梦得','宋','宋词','song-ci','临江仙','["\u897f\u6e56"]','三月莺花都过了，晓来雪片犹零。',70,'宋词/ci.song.5000.json','["三月莺花都过了，晓来雪片犹零。", "嵩阳居士记行行。", "西湖初水满，遥想縠纹生。", "欲为海棠传信息，如今底事长醒。", "不应高卧顿忘情。", "留春春不住，老眼若为明。"]'),
('song-ci-271','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','唱彻阳关分别袂，佳人粉泪空零。',70,'宋词/ci.song.5000.json','["唱彻阳关分别袂，佳人粉泪空零。", "请君重作醉歌行。", "一欢须痛饮，回首念平生。", "却怪老来风味减，半酣易逐愁醒。", "因花那更赋闲情。", "鬓毛今尔耳，空笑老渊明。"]'),
('song-ci-272','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','潋滟湖光供一笑，未须醉日论千。',70,'宋词/ci.song.5000.json','["潋滟湖光供一笑，未须醉日论千。", "将军曾记旧临边。", "野塘新水漫，烟岸藕如船。", "却怪情多春又老，回肠易逐愁煎。", "何如旌旆郁相连。", "凯歌归玉帐，锦帽碧油前。"]'),
('song-ci-273','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','学士园林人不到，传声欲问江梅。',70,'宋词/ci.song.5000.json','["学士园林人不到，传声欲问江梅。", "曲阑清浅小池台。", "已知春意近，为我著诗催。", "急管行觞围舞袖，故人坐上三台。", "此欢此宴固难陪。", "不辞同二老，倒载习池回。"]'),
('song-ci-274','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','不与群芳争绝艳，化工自许寒梅。',70,'宋词/ci.song.5000.json','["不与群芳争绝艳，化工自许寒梅。", "一枝临晚照歌台。", "眼明浑未见，弦管莫惊催。", "记取刘郎归去路，千里应话天台。", "酒阑不惜更重陪。", "夜寒衣袂薄，犹有暗香回。"]'),
('song-ci-275','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','三日疾风吹浩荡，绿芜未遍平沙。',70,'宋词/ci.song.5000.json','["三日疾风吹浩荡，绿芜未遍平沙。", "约回残影射明霞。", "水光遥泛坐，烟柳卧敧斜。", "霜鬓不堪春点检，留连又见芳华。", "一枝重插去年花。", "此身江海梦，何处定吾家。"]'),
('song-ci-276','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','自笑天涯无定准，飘然到处迟留。',70,'宋词/ci.song.5000.json','["自笑天涯无定准，飘然到处迟留。", "兴阑却上五湖舟。", "鲈莼新有味，碧树已惊秋。", "台上微凉初过雨，一尊聊记同游。", "寄声时为到沧洲。", "遥知敧枕处，万壑看交流。"]'),
('song-ci-277','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','山半飞泉鸣玉佩，回波倒卷粼粼。',70,'宋词/ci.song.5000.json','["山半飞泉鸣玉佩，回波倒卷粼粼。", "解巾聊濯十年尘。", "青山应却怪，此段久无人。", "行乐应须贤太守，风光过眼逡巡。", "不辞常作坐中宾。", "只愁花解笑，衰鬓不宜春。"]'),
('song-ci-278','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','手种千株桃李树，参差半已成阴。',70,'宋词/ci.song.5000.json','["手种千株桃李树，参差半已成阴。", "主人何事马骎骎。", "二年江海路，空负种花心。", "试问中间安小槛，此还长要追寻。", "却惊摇落动悲吟。", "春归知早晚，为我变层林。"]'),
('song-ci-279','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','绝顶参差千嶂列，不知空水相浮。',70,'宋词/ci.song.5000.json','["绝顶参差千嶂列，不知空水相浮。", "下临湖海见三州。", "落霞横暮景，为客小迟留。", "卷尽微云天更阔，此行不负清秋。", "忽惊河汉近人流。", "青霄元有路，一笑倚琼楼。"]'),
('song-ci-280','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','一醉三年那易得，应须大白同浮。',70,'宋词/ci.song.5000.json','["一醉三年那易得，应须大白同浮。", "已知绝景是吾州。", "姮娥仍有意，更肯为人留。", "万籁无声遥夜永，人间未识高秋。", "从来我客尽风流。", "故知怜老子，尤胜在南楼。"]'),
('song-ci-281','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','卷地惊风吹雨去，却看香雾轻浮。',70,'宋词/ci.song.5000.json','["卷地惊风吹雨去，却看香雾轻浮。", "遥知清影遍南州。", "万峰横玉立，谁为此山留。", "邂逅一欢须共惜，年年长记今秋。", "平生江海恨飘流。", "元龙真老懒，无意卧高楼。"]'),
('song-ci-282','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','一醉年年今夜月，酒船聊更同浮。',70,'宋词/ci.song.5000.json','["一醉年年今夜月，酒船聊更同浮。", "恨无羯鼓打梁州。", "遗声犹好在，风景一时留。", "老去狂歌君勿笑，已拚双鬓成秋。", "会须击节溯中流。", "一声云外笛，惊看水明楼。"]'),
('song-ci-283','临江仙','叶梦得','宋','宋词','song-ci','临江仙','[]','草草一年真过梦，此生不恨萍浮。',70,'宋词/ci.song.5000.json','["草草一年真过梦，此生不恨萍浮。", "且令从事到青州。", "已能从辟谷，那更话封留。", "好月尚寻当日约，故人何啻三秋。", "援琴欲写竹间流。", "此声谁解听，空上仲宣楼。"]'),
('song-ci-284','虞美人','叶梦得','宋','宋词','song-ci','虞美人','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','落花已作风前舞。',66,'宋词/ci.song.5000.json','["落花已作风前舞。", "又送黄昏雨。", "晓来庭院半残红。", "惟有游丝千丈、罥晴空。", "殷勤花下同携手。", "更尽杯中酒。", "美人不用敛蛾眉。", "我亦多情、无奈酒阑时。"]'),
('song-ci-285','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','翻翻翠叶梧桐老。',66,'宋词/ci.song.5000.json','["翻翻翠叶梧桐老。", "雨后凉生早。", "葛巾藜杖正关情。", "莫遣繁蝉、容易作秋声。", "遥空不尽青天去。", "一抹残霞暮。", "病馀无力厌跻攀。", "为寄曲阑幽意、到西山。"]'),
('song-ci-286','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','一声鶗鴂催春晚。',66,'宋词/ci.song.5000.json','["一声鶗鴂催春晚。", "芳草连空远。", "年年馀恨怨残红。", "可是无情、容易爱随风。", "茂林修竹山阴道。", "千载谁重到。", "半湖流水夕阳前。", "犹有一觞一咏、似当年。"]'),
('song-ci-287','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','东风一夜催春到。',66,'宋词/ci.song.5000.json','["东风一夜催春到。", "杨柳朝来好。", "莫辞尊酒重携持。", "老去情怀、能有几人知。", "凤台园里新诗伴。", "不用相追唤。", "一声清唱落琼卮。", "千顷西风烟浪、晚云迟。"]'),
('song-ci-288','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','数声微雨风惊晓。',66,'宋词/ci.song.5000.json','["数声微雨风惊晓。", "烛影猗残照。", "客愁不奈五更寒。", "明日梨花开尽、有谁看。", "追寻犹记清明近。", "为向花前问。", "东风正使解欺侬。", "不道花应有恨、也匆匆。"]'),
('song-ci-289','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','平波涨绿春堤满。',66,'宋词/ci.song.5000.json','["平波涨绿春堤满。", "渡口人归晚。", "短篷轻楫费追寻。", "始信十年归梦、是如今。", "故人回望高阳里。", "遥想车连骑。", "尊前点检旧年春。", "应有海棠、犹记插花人。"]'),
('song-ci-290','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','绿阴初过黄梅雨。',66,'宋词/ci.song.5000.json','["绿阴初过黄梅雨。", "隔叶闻莺语。", "睡馀谁遣夕阳斜。", "时有微凉风动、入窗纱。", "天涯走遍终何有。", "白发空搔首。", "未须锦瑟怨年华。", "为寄一声长笛、怨梅花。"]'),
('song-ci-291','虞美人','叶梦得','宋','宋词','song-ci','虞美人','[]','梅花落尽桃花小。',66,'宋词/ci.song.5000.json','["梅花落尽桃花小。", "春事馀多少。", "新亭风景尚依然。", "白发故人相遇、且留连。", "家山应在层林外。", "怅望花前醉。", "半天烟雾尚连空。", "换取扁舟归去、与君同。"]'),
('song-ci-292','减字木兰花','叶梦得','宋','宋词','song-ci','减字木兰花','[]','黄花渐老。',52,'宋词/ci.song.5000.json','["黄花渐老。", "秋色欲归还草草。", "花下前期。", "花老空歌鹊踏枝。", "狂酲易醒。", "不似旧时长酩酊。", "玉簟新凉。", "数尽更筹夜更长。"]'),
('song-ci-293','减字木兰花','叶梦得','宋','宋词','song-ci','减字木兰花','[]','前村夜半。',52,'宋词/ci.song.5000.json','["前村夜半。", "每为江梅肠欲断。", "浅紫深红。", "谁信漫天雪里逢。", "醉头扶起。", "宿酒阑干犹困倚。", "便莫催残。", "明日东风为扫看。"]'),
('song-ci-294','减字木兰花','叶梦得','宋','宋词','song-ci','减字木兰花','[]','粉消妆半。',52,'宋词/ci.song.5000.json','["粉消妆半。", "一曲阳春歌始断。", "便觉香红。", "十倍光华昔未逢。", "杨花吹起。", "犹自风前相枕倚。", "莫恨春残。", "留取新诗子细看。"]'),
('song-ci-295','木兰花・玉楼春','叶梦得','宋','宋词','song-ci','木兰花・玉楼春','[]','花残却是春留恋。',64,'宋词/ci.song.5000.json','["花残却是春留恋。", "几日馀香吹酒面。", "湿烟不隔柳条青，小雨池塘初有燕。", "波光纵使明如练。", "可奈落红纷似霰。", "解将心事诉东风，只有啼莺千种啭。"]'),
('song-ci-296','点绛唇','叶梦得','宋','宋词','song-ci','点绛唇','[]','高柳萧萧，睡馀已觉西风劲。',50,'宋词/ci.song.5000.json','["高柳萧萧，睡馀已觉西风劲。", "小窗人静。", "淅沥生秋听。", "底事多情，欲与流年竞。", "残云瞑。", "坠巾慵整。", "独立芝兰径。"]'),
('song-ci-297','点绛唇','叶梦得','宋','宋词','song-ci','点绛唇','[]','缥缈危亭，笑谈独在千峰上。',50,'宋词/ci.song.5000.json','["缥缈危亭，笑谈独在千峰上。", "与谁同赏。", "万里横烟浪。", "老去情怀，犹作天涯想。", "空惆怅。", "少年豪放。", "莫学衰翁样。"]'),
('song-ci-298','点绛唇','叶梦得','宋','宋词','song-ci','点绛唇','[]','山上飞泉，漫流山下知何处。',50,'宋词/ci.song.5000.json','["山上飞泉，漫流山下知何处。", "乱云无数。", "留得幽人住。", "深闭柴门，听尽空檐雨。", "秋还暮。", "小窗低户。", "惟有寒蛩语。"]'),
('song-ci-299','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','不怕微霜点玉肌。',64,'宋词/ci.song.5000.json','["不怕微霜点玉肌。", "恨无流水照冰姿。", "与君著意从头看，初见今年第一枝。", "人醉后，雪消时。", "江南春色寄来迟。", "使君本是花前客，莫怪殷勤为赋诗。"]'),
('song-ci-300','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','夹路行歌尽落梅。',64,'宋词/ci.song.5000.json','["夹路行歌尽落梅。", "篆烟香细袅寒灰。", "云移碧海三山近，月破中天九陌开。", "追乐事，惜多才。", "车声遥听走晴雷。", "十年梦断钧天奏，犹记流霞醉后杯。"]'),
('song-ci-301','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','小雨初收报夕阳。',64,'宋词/ci.song.5000.json','["小雨初收报夕阳。", "归云欲渡转横塘。", "空回雨盖翻新影，不见琼肌洗暗香。", "追落景，弄微凉。", "尚馀残泪浥空床。", "只应自有东风恨，长遣啼痕破晚妆。"]'),
('song-ci-302','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','晓日初开露未晞。',64,'宋词/ci.song.5000.json','["晓日初开露未晞。", "夕烟轻散雨还微。", "暗摇绿雾游鯈戏，斜映红云属玉飞。", "情脉脉，恨依依。", "沙边空见棹船归。", "何人解舞新声曲，一试纤腰六尺围。"]'),
('song-ci-303','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','兰茝空悲楚客秋。',64,'宋词/ci.song.5000.json','["兰茝空悲楚客秋。", "旌旗谁见使君游。", "凌云不隔三山路，破浪聊凭万里舟。", "公欲去，尚能留。", "杯行到手未宜休。", "新诗无物堪伦比，愿探珊瑚出宝钩。"]'),
('song-ci-304','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','天末残霞卷暮红。',64,'宋词/ci.song.5000.json','["天末残霞卷暮红。", "波间时见没凫翁。", "斜风细雨家何在，老矣生涯尽个中。", "惟此意，与公同。", "未须持酒祝牛宫。", "旁人不解轻蓑意，犹说黄金宝带重。"]'),
('song-ci-305','鹧鸪天','叶梦得','宋','宋词','song-ci','鹧鸪天','[]','一曲青山映小池。',64,'宋词/ci.song.5000.json','["一曲青山映小池。", "绿荷阴尽雨离披。", "何人解识秋堪美，莫为悲秋浪赋诗。", "携浊酒，绕东篱。", "菊残犹有傲霜枝。", "一年好景君须记，正是橙黄橘绿时。"]'),
('song-ci-306','水龙吟','叶梦得','宋','宋词','song-ci','水龙吟','[]','对花常欲留春，恨春故遣花飞早。',126,'宋词/ci.song.5000.json','["对花常欲留春，恨春故遣花飞早。", "晓来雨过，绿阴新处，几番芳草。", "一片飘时，已知消减，满庭谁扫。", "料多情也似，愁人易感，先催趁、朱颜老。", "犹有清明未过，但狂风、匆匆难保。", "酒醒梦断，年年此恨，不禁相恼。", "只恐春应，暗留芳信，与花争好。", "有姚黄一朵，殷勤付与，送金杯倒。"]'),
('song-ci-307','水龙吟','叶梦得','宋','宋词','song-ci','水龙吟','[]','舵楼横笛孤吹，暮云散尽天如水。',126,'宋词/ci.song.5000.json','["舵楼横笛孤吹，暮云散尽天如水。", "人间底事，忽惊飞堕，冰壶千里。", "玉树风清，漫披遥卷，与空无际。", "料嫦娥此夜，殷勤偏照，知人在、千山里。", "常恨孤光易转，仗多情、使君料理。", "一杯起舞，曲终须寄，狂歌重倚。", "为问飘流，几逢清影，有谁同记。", "但尊中有酒，长追旧事，拚年年醉。"]'),
('song-ci-308','千秋岁','叶梦得','宋','宋词','song-ci','千秋岁','[]','晓烟溪畔。',87,'宋词/ci.song.5000.json','["晓烟溪畔。", "曾记东风面。", "化工更与重裁翦。", "额黄明艳粉，不共妖红软。", "凝露脸。", "多情正似当时见。", "谁相沧波岸。", "特地移闲馆。", "情一缕，愁千点。", "烦君搜妙语，为我催清宴。", "须细看。", "粉粉乱蕊空凡艳。"]'),
('song-ci-309','千秋岁','叶梦得','宋','宋词','song-ci','千秋岁','[]','雨声萧瑟，初到梧桐响。',87,'宋词/ci.song.5000.json','["雨声萧瑟，初到梧桐响。", "人不寐，秋声爽。", "低檐灯暗淡，画幕风来往。", "谁共赏。", "依稀记得船篷上。", "拍岸浮轻浪。", "水阔菰蒲长。", "相别浦，收横纲。", "绿蓑冲瞑□，艇子摇双桨。", "君莫忘。", "此情犹是当时唱。"]'),
('song-ci-310','蓦山溪','叶梦得','宋','宋词','song-ci','蓦山溪','[]','一年春事，常恨风和雨。',102,'宋词/ci.song.5000.json','["一年春事，常恨风和雨。", "趁取未残时，醉花前、春应相许。", "山公倒载，日暮习池回，问东风，春知否，莫道空归去。", "满城歌吹，也似春和豫。", "争笑使君狂，占风光、不教飞絮。", "明朝酒醒，满地落残红，唱新词，追好景，犹有君收聚。"]'),
('song-ci-311','清平乐','叶梦得','宋','宋词','song-ci','清平乐','[]','水空相映。',53,'宋词/ci.song.5000.json','["水空相映。", "淡碧涵千顷。", "素练不收寒玉镜。", "□落阶无影。", "纤纤与捧金杯。", "暗香逐舞徘徊。", "雪尽玉容开遍，东风不管寒梅。"]'),
('song-ci-312','雨中花慢','叶梦得','宋','宋词','song-ci','雨中花慢','[]','痛饮狂歌，百计强留，风光无奈春归。',123,'宋词/ci.song.5000.json','["痛饮狂歌，百计强留，风光无奈春归。", "春去也，应知相赏，未忍相违。", "卷地风惊，争催春暮雨，顿回寒威。", "对黄昏萧瑟，冰肤洗尽，犹覆霞衣。", "多情断了，为花狂恼，故飘万点霏微。", "低粉面、妆台酒散，泪颗频挥。", "可是盈盈有意，只应真惜分飞。", "拚令吹尽，明朝酒醒，忍对红稀。"]'),
('song-ci-313','南乡子','叶梦得','宋','宋词','song-ci','南乡子','[]','浅碧蘸鳞鳞。',66,'宋词/ci.song.5000.json','["浅碧蘸鳞鳞。", "照眼全无一点尘。", "百草千花都过了，初新。", "翠竹高槐不占春。", "歌啸堕纶巾。", "午醉醒来尚欠伸。", "待得月明归去也，青苹。", "更有凉风解送人。"]'),
('song-ci-314','南乡子','叶梦得','宋','宋词','song-ci','南乡子','[]','小院雨新晴。',66,'宋词/ci.song.5000.json','["小院雨新晴。", "初听黄鹂第一声。", "满地绿阴人不到，盈盈。", "一点孤花尚有情。", "却傍水边行。", "叶底跳鱼浪自惊。", "日暮小舟何处去，斜横。", "冲破波痕久未平。"]'),
('song-ci-315','南乡子','叶梦得','宋','宋词','song-ci','南乡子','[]','山畔小池台。',66,'宋词/ci.song.5000.json','["山畔小池台。", "曾记幽人著意栽。", "乱石参差春至晚，徘徊。", "素景冲寒却自开。", "绝绝照琼瑰。", "孤负芳心巧翦裁。", "应恐练裙惊缟夜，残杯。", "且放疏枝待我来。"]'),
('song-ci-316','卜算子','叶梦得','宋','宋词','song-ci','卜算子','[]','新月挂林梢，暗水鸣枯沼。',52,'宋词/ci.song.5000.json','["新月挂林梢，暗水鸣枯沼。", "时见疏星落画檐，几点流萤小。", "归意已无多，故作连环绕。", "欲寄新声问采菱，水阔烟波渺。"]'),
('song-ci-317','卜算子','叶梦得','宋','宋词','song-ci','卜算子','[]','晓雨洗新妆，艳艳惊衰眼。',52,'宋词/ci.song.5000.json','["晓雨洗新妆，艳艳惊衰眼。", "不趁东风取次开，待得清霜晚。", "曲港照回流，影乱微波浅。", "作态低昂好自持，水阔烟波远。"]'),
('song-ci-318','菩萨蛮','叶梦得','宋','宋词','song-ci','菩萨蛮','[]','平波不尽蒹葭远。',52,'宋词/ci.song.5000.json','["平波不尽蒹葭远。", "清霜半落沙痕浅。", "烟树晚微茫。", "孤鸿下夕阳。", "梅花消息近。", "试向南枝问。", "记得水边春。", "江南别后人。"]'),
('song-ci-319','蝶恋花','叶梦得','宋','宋词','song-ci','蝶恋花','[]','薄雪消时春已半。',70,'宋词/ci.song.5000.json','["薄雪消时春已半。", "踏遍苍苔，手挽花枝看。", "一缕游丝牵不断。", "多情更觉蜂儿乱。", "尽日平波回远岸。", "倒影浮光，却记冰初泮。", "酒力无多吹易散。", "馀寒向晚风惊幔。"]'),
('song-ci-320','醉蓬莱','叶梦得','宋','宋词','song-ci','醉蓬莱','[]','问东风何事，断送残红，便拚归去。',120,'宋词/ci.song.5000.json','["问东风何事，断送残红，便拚归去。", "牢落征途，笑行人羁旅。", "一曲阳关，断云残霭，做渭城朝雨。", "欲寄离愁，绿阴千啭，黄鹂空语。", "遥想湖边，浪摇空翠，弦管风高，乱花飞絮。", "曲水流觞，有山公行处。", "翠袖朱阑，故人应也，弄画船烟浦。", "会写相思，尊前为我，重翻新句。"]'),
('song-ci-321','南歌子','叶梦得','宋','宋词','song-ci','南歌子','[]','雨惜山容敛，云矜棹影开。',62,'宋词/ci.song.5000.json','["雨惜山容敛，云矜棹影开。", "忽看霁色射林隈。", "为问湖亭清影、为谁来。", "尽洗归时路，重倾醉后杯。", "未应霜雪遽相催。", "留得佳期犹在、共徘徊。"]'),
('song-ci-322','采桑子','叶梦得','宋','宋词','song-ci','采桑子','[]','山蹊小路归来晚，暮雪缤纷。',52,'宋词/ci.song.5000.json','["山蹊小路归来晚，暮雪缤纷。", "尊酒殷勤。", "邂逅相从只有君。", "全家住处无人到，元在重云。", "此景谁分。", "万玉参差更作群。"]'),
('song-ci-323','南歌子','叶梦得','宋','宋词','song-ci','南歌子','[]','麦陇深初转，桃溪曲渐成。',62,'宋词/ci.song.5000.json','["麦陇深初转，桃溪曲渐成。", "绿槐重叠午阴清。", "更有榴花一朵、照人明。", "画栋清微暑，疏帘入晚晴。", "请君坐待縠纹平。", "看取红幢翠盖、引前旌。"]'),
('song-ci-324','菩萨蛮','叶梦得','宋','宋词','song-ci','菩萨蛮','[]','经年不踏斜桥路。',52,'宋词/ci.song.5000.json','["经年不踏斜桥路。", "青山试问谁为主。", "密叶转回风。", "寒泉落半空。", "此间无限兴。", "可便荒三径。", "明日下扁舟。", "沧波莫浪游。"]'),
('song-ci-325','好事近','赵士','宋','宋词','song-ci','好事近','[]','雪里晓寒浓，已见蜡梅初折。',53,'宋词/ci.song.5000.json','["雪里晓寒浓，已见蜡梅初折。", "应是月娥仙挂，与娇魂香魄。", "玉人挨鬓一枝斜，不忍更多摘。", "酒面暗沈疏影，照鹅儿颜色。"]'),
('song-ci-326','好事近','赵士','宋','宋词','song-ci','好事近','[]','萧洒点疏从，浑似蜜房雕刻。',53,'宋词/ci.song.5000.json','["萧洒点疏从，浑似蜜房雕刻。", "不爱艳妆浓粉，借娇黄一拂。", "有情常恁早相逢，须信做尤物。", "已是恼人风韵，更芝兰香骨。"]'),
('song-ci-327','好事近','赵士','宋','宋词','song-ci','好事近','[]','造化有深功，缀就梢头黄蜡。',53,'宋词/ci.song.5000.json','["造化有深功，缀就梢头黄蜡。", "剪刻翻成新样，与江梅殊别。", "半开微露紫檀心，萧洒对风月。", "素手偏宜折取，向乌云斜插。"]'),
('song-ci-328','好事近','赵士','宋','宋词','song-ci','好事近','[]','剪蜡缀寒条，标韵自然奇绝。',53,'宋词/ci.song.5000.json','["剪蜡缀寒条，标韵自然奇绝。", "不待陇头春信，喜一枝先折。", "寿阳妆鉴晓初开，残柍若飞雪。", "何似嫩黄新蕊，映眉心娇月。"]'),
('song-ci-329','锦缠绊・锦缠道','江衍','宋','宋词','song-ci','锦缠绊・锦缠道','[]','屈曲新堤，占断满村佳气。',77,'宋词/ci.song.5000.json','["屈曲新堤，占断满村佳气。", "画檐两行连云际。", "乱山叠翠水回还，岸边楼阁，金碧遥相倚。", "柳阴低，艳映花光美。", "好升平、为谁初起。", "大都风物只由人，旧时荒垒，今日香烟地。"]'),
('song-ci-330','蓦山溪','周铢','宋','宋词','song-ci','蓦山溪','[]','松陵江上，极目烟波缈。',102,'宋词/ci.song.5000.json','["松陵江上，极目烟波缈。", "天际接沧溟，到如今、东流未了。", "吴樯越橹，都是利名人，空扰扰，知多少，只见朱颜老。", "故园应是，绿遍池塘草。", "家住十洲西，算随分、生涯自好。", "渔蓑清贵，休羡谢三郎，红蕖月，白苹风，何似长安道。"]'),
('song-ci-331','眼儿媚','王赏','宋','宋词','song-ci','眼儿媚','[]','凌寒低亚出墙枝。',58,'宋词/ci.song.5000.json','["凌寒低亚出墙枝。", "孤瘦雪霜姿。", "岁华已晚，暗香幽艳，自与时违。", "化工放出江头路，沙水冷相宜。", "东风自此，别开红紫，是处芳菲。"]'),
('song-ci-332','水调歌头','李光','宋','宋词','song-ci','水调歌头','[]','元亮赋归去，富贵比浮云。',114,'宋词/ci.song.5000.json','["元亮赋归去，富贵比浮云。", "常於闹里，端的认得主和宾。", "肯羡当年轩冕，时引壶觞独酌，一笑落冠巾。", "园圃日成趣，桃李几番春。", "挹清风，追往躅，事如新。", "遗编讽咏，敛衽千载友斯人。", "君爱谪仙风调，我恨楼船迫胁，终污永王璘。", "何似北窗下，寂寞可栖神。"]'),
('song-ci-333','水调歌头','李光','宋','宋词','song-ci','水调歌头','[]','兵器暗吴楚，江汉久凄凉。',114,'宋词/ci.song.5000.json','["兵器暗吴楚，江汉久凄凉。", "当年俊杰安在，酌酒酹严光。", "南顾豺狼吞噬，北望中原板荡，矫首讯穹苍。", "归去谢宾友，客路饱风霜。", "闭柴扉，窥千载，考三皇。", "兰亭胜处，依旧流水绕修篁。", "傍有湖光千顷，时泛扁舟一叶，啸傲水云乡。", "寄语骑鲸客，何事返南荒。"]'),
('song-ci-334','水调歌头','李光','宋','宋词','song-ci','水调歌头','[]','自笑客行久，新火起新烟。',114,'宋词/ci.song.5000.json','["自笑客行久，新火起新烟。", "园林春半风暖，花落柳飞绵。", "坐想稽山佳处，贺老门前湖水，敧侧钓鱼船。", "何事成淹泊，流转海南边。", "水中影，镜中像，慢流连。", "此心未住，赢得忧患苦相缠。", "行尽荒烟蛮瘴，深入维那境界，参透祖师禅。", "宴坐超三际，萧洒任吾年。"]'),
('song-ci-335','水调歌头','李光','宋','宋词','song-ci','水调歌头','[]','独步长桥上，今夕是中秋。',114,'宋词/ci.song.5000.json','["独步长桥上，今夕是中秋。", "群黎怪我何事，流转古儋州。", "风定潮平如练，云散月明如昼，孤兴在扁舟。", "笑尽一杯酒，水调杂蛮讴。", "少年场，金兰契，尽白头。", "相望万里，悲我已是十年流。", "晚遇玉霄仙子，授我王屋奇书，归路指蓬邱。", "不用乘风御，八极可神游。"]'),
('song-ci-336','南歌子','李光','宋','宋词','song-ci','南歌子','[]','佳节多离恨，难逢笑口开。',62,'宋词/ci.song.5000.json','["佳节多离恨，难逢笑口开。", "使君携客上层台。", "不用篱边凝望、白衣来。", "且看花经眼，休辞酒满杯。", "玉人低唱管弦催。", "归去琐窗无梦、月徘徊。"]'),
('song-ci-337','南歌子','李光','宋','宋词','song-ci','南歌子','[]','南圃秋香过，东篱菊未英。',62,'宋词/ci.song.5000.json','["南圃秋香过，东篱菊未英。", "蓼花无数满寒汀。", "中有一枝纤软、吐微馨。", "被冷沈烟细，灯青梦水成。", "皎如月明入窗棂。", "天女维摩相对、两忘情。"]'),
('song-ci-338','临江仙','李光','宋','宋词','song-ci','临江仙','[]','画栋朱楼凌缥缈，全家住在层城。',68,'宋词/ci.song.5000.json','["画栋朱楼凌缥缈，全家住在层城。", "中秋风露助凄清。", "香凝燕寝，遮莫下帘旌。", "佳节喜逢今夕月，后房重按新声。", "姮娥端解妒娉婷。", "微云点缀，不放十分明。"]'),
('song-ci-339','减字木兰花','李光','宋','宋词','song-ci','减字木兰花','[]','芳心一点。',52,'宋词/ci.song.5000.json','["芳心一点。", "瘴雾难侵尘不染。", "冷澹谁看。", "月转霜林怯夜寒。", "一枝孤静。", "梦破小窗曾记省。", "烛影参差。", "脉脉还如背立时。"]'),
('song-ci-340','念奴娇','李光','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','榕林叶暗，见一枝独放，霜华争白。',120,'宋词/ci.song.5000.json','["榕林叶暗，见一枝独放，霜华争白。", "写我精神惟赖有，萧洒西湖词客。", "玉骨清羸，冰容冷落，似恨关山隔。", "蛮烟侵妒，未应减动肌雪。", "幽梦时绕芳枝，夜寒谁见我，身为蝴蝶。", "抱蕊窥丛惊睡觉，窗影横斜和月。", "谢馆池边，松风亭下，忍使香消歇。", "多情饶恨，算应天解磨折。"]'),
('song-ci-341','汉宫春','李光','宋','宋词','song-ci','汉宫春','[]','危阁临流，渺沧波万顷，涌出冰轮。',118,'宋词/ci.song.5000.json','["危阁临流，渺沧波万顷，涌出冰轮。", "星河澹澹，天衢迥绝纤尘。", "琼楼玉馆，遍人间、水月精神。", "□□□，清江瘴海，乘流处处分身。", "邦侯盛集佳宾。", "有香风缥缈，和气氤氲。", "华灯耀添绮席，笑语烘春。", "窥帘映牖，看素娥、偏顾幽人。", "空怅望，通明观阙，遥瞻一朵红云。"]'),
('song-ci-342','鹧鸪天','李光','宋','宋词','song-ci','鹧鸪天','[]','踏舞贪看赤脚娘。',64,'宋词/ci.song.5000.json','["踏舞贪看赤脚娘。", "送春春去莫悲伤。", "飞花逐水归何处，落絮沾泥不解狂。", "都是醉，任飞扬。", "百年三万六千场。", "使君亲按新歌舞，魂梦相逢笑楚襄。"]'),
('song-ci-343','武陵春','李光','宋','宋词','song-ci','武陵春','[]','漠漠春阴人似雾，那用绣帘垂。',56,'宋词/ci.song.5000.json','["漠漠春阴人似雾，那用绣帘垂。", "不道持杯是阿谁。", "须拚倒金罍。", "人世浑知天上月，离合比盈亏。", "冒雨须来带雨归。", "神女解相随。"]'),
('song-ci-344','渔家傲','李光','宋','宋词','song-ci','渔家傲','[]','海外无寒花发早。',72,'宋词/ci.song.5000.json','["海外无寒花发早。", "一枝不忍簪风帽。", "归插净瓶花转好。", "维摩老。", "年来却被花枝恼。", "忽忆故乡花满道。", "狂歌痛饮俱年少。", "桃坞花开如野烧，都醉倒。", "花深往往眠芳草。"]'),
('song-ci-345','水调歌头','李光','宋','宋词','song-ci','水调歌头','[]','晚渡呼舟急，寒日正苍茫。',114,'宋词/ci.song.5000.json','["晚渡呼舟急，寒日正苍茫。", "西兴浦口云树，真个是吾乡。", "闻□蜗庐好在，小圃犹存松菊，三径未全荒。", "收拾桑榆景，蓑笠换金章。", "珥金貂，拥珠履，在岩廊。", "回头万事何有，一枕梦黄粮。", "十载人间忧患，赢得萧萧华发，清镜照星霜。", "醉倒休扶我，身世永相忘。"]'),
('song-ci-346','雨中花慢','张生1','宋','宋词','song-ci','雨中花慢','[]','事往人离，还似暮峡归云，陇上流泉。',117,'宋词/ci.song.5000.json','["事往人离，还似暮峡归云，陇上流泉。", "奈强分圆镜，枉断哀弦。", "常记酒阑歌畔，难忘月底花前。", "旧携手处，层楼朱户，触目依然。", "从来惯向，绣帏罗帐，镇效比翼纹鸳。", "谁念我、而今清夜，常是孤眠。", "入户不如飞絮，傍怀争及炉烟。", "这回休也，一生心事，为尔萦牵。"]'),
('song-ci-347','向湖边','江纬','宋','宋词','song-ci','向湖边','[]','退处相关，幽栖林薮，舍宇第须茅盖。',126,'宋词/ci.song.5000.json','["退处相关，幽栖林薮，舍宇第须茅盖。", "翠巘清泉，启轩窗遥对。", "遇等闲、邻里过从，亲朋临顾，草草便成幽会。", "策杖携壶，向湖边柳外。", "旋买溪鱼，便斫银丝脍。", "谁复欲痛饮，如长鲸吞海。", "共惜醺酣，恐欢娱难再。", "矧清风明月非钱买。", "休追念、金马玉堂心胆碎。", "且斗尊前，有阿谁身在。"]'),
('song-ci-348','卜算子','美奴','宋','宋词','song-ci','卜算子','[]','送我出东门，乍别长安道。',54,'宋词/ci.song.5000.json','["送我出东门，乍别长安道。", "两岸垂杨锁暮烟，正是秋光老。", "一曲古《阳关》，莫惜金尊倒。", "君向潇湘我向秦，鱼雁何时到。"]'),
('song-ci-349','如梦令','美奴','宋','宋词','song-ci','如梦令','[]','日暮马嘶人去。',40,'宋词/ci.song.5000.json','["日暮马嘶人去。", "船逐清波东注。", "后夜最高楼，还肯思量人否。", "无绪。", "无绪。", "生怕黄昏疏雨。"]'),
('song-ci-350','人娇','张扩','宋','宋词','song-ci','人娇','[]','深院海棠，谁倩春工染就。',84,'宋词/ci.song.5000.json','["深院海棠，谁倩春工染就。", "映窗户、烂如锦绣。", "东君何意，便风狂雨骤。", "堪恨处，一枝未曾到手。", "今日乍晴，匆匆命酒。", "犹及见、胭脂半透。", "残红几点，明朝知在否。", "问何似，去年看花时候。"]'),
('song-ci-351','人娇','张扩','宋','宋词','song-ci','人娇','[]','多少胭脂，匀成点就。',82,'宋词/ci.song.5000.json','["多少胭脂，匀成点就。", "千枝乱、攒红堆绣。", "花无长好，更光阴去骤。", "对景忆良朋，故应招手。", "曾记年时，花间把酒。", "枉淋浪、春衫湿透。", "文园今病，问远能来否。", "却道有，荼蘼牡丹时候。"]'),
('song-ci-352','菩萨蛮','赵子崧','宋','宋词','song-ci','菩萨蛮','[]','锦如花色春残饮。',52,'宋词/ci.song.5000.json','["锦如花色春残饮。", "饮残春色花如锦。", "楼上正人愁。", "愁人正上楼。", "晏天横阵雁。", "雁阵横天晏。", "思远寄情词。", "词情寄远思。"]'),
('song-ci-353','菩萨蛮','赵子崧','宋','宋词','song-ci','菩萨蛮','[]','雨荷惊起双飞鹭。',52,'宋词/ci.song.5000.json','["雨荷惊起双飞鹭。", "鹭飞双起惊荷雨。", "浓醉一轩风。", "风轩一醉浓。", "午阴清散暑。", "暑散清阴午。", "斜日转窗纱。", "纱窗转日斜。"]'),
('song-ci-354','菩萨蛮','赵子崧','宋','宋词','song-ci','菩萨蛮','[]','断鸿归处飞云乱。',52,'宋词/ci.song.5000.json','["断鸿归处飞云乱。", "乱云飞处归鸿断。", "风弄叶翻红。", "红翻叶弄风。", "柳残凋院后。", "后院凋残柳。", "楼外水云秋。", "秋云水外楼。"]'),
('song-ci-355','菩萨蛮','赵子崧','宋','宋词','song-ci','菩萨蛮','[]','月天遥照寒窗雪。',52,'宋词/ci.song.5000.json','["月天遥照寒窗雪。", "雪窗寒照遥天月。", "门掩欲黄昏。", "昏黄欲掩门。", "锦鹓双并枕。", "枕并双鹓锦。", "云鬓整纤琼。", "琼纤整鬓云。"]'),
('song-ci-356','菩萨蛮','鉴堂','宋','宋词','song-ci','菩萨蛮','[]','落花丛外风惊鹊。',52,'宋词/ci.song.5000.json','["落花丛外风惊鹊。", "鹊惊风外丛花落。", "乡梦困时长。", "长时困梦乡。", "暮天江口渡。", "渡口江天暮。", "林远度栖禽。", "禽栖度远林。"]'),
('song-ci-357','菩萨蛮','鉴堂','宋','宋词','song-ci','菩萨蛮','[]','竹枝高映荷池绿。',52,'宋词/ci.song.5000.json','["竹枝高映荷池绿。", "绿池荷映高枝竹。", "流水碧浮鸥。", "鸥浮碧水流。", "酒尊陪旧友。", "友旧陪尊酒。", "吟客坐时斟。", "斟时坐客吟。"]'),
('song-ci-358','菩萨蛮','鉴堂','宋','宋词','song-ci','菩萨蛮','[]','砌风鸣叶繁霜坠。',52,'宋词/ci.song.5000.json','["砌风鸣叶繁霜坠。", "坠霜繁叶鸣风砌。", "山外水潺潺。", "潺潺水外山。", "冷衾愁夜永。", "永夜愁衾冷。", "砧响更蛩吟。", "吟蛩更响砧。"]'),
('song-ci-359','菩萨蛮','鉴堂','宋','宋词','song-ci','菩萨蛮','[]','浦南回桨归庭户。',52,'宋词/ci.song.5000.json','["浦南回桨归庭户。", "户庭归桨回南浦。", "帘卷欲晴天。", "天晴欲卷帘。", "月光交映雪。", "雪映交光月。", "残漏怯宵寒。", "寒宵怯漏残。"]'),
('song-ci-360','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','碧窗纱透春寒极。',52,'宋词/ci.song.5000.json','["碧窗纱透春寒极。", "极寒春透纱窗碧。", "谁送缕金衣。", "衣金缕送谁。", "玉肌生嫩粟。", "粟嫩生肌玉。", "温处坐香茵。", "茵香坐处温。"]'),
('song-ci-361','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','折来初步东溪月。',52,'宋词/ci.song.5000.json','["折来初步东溪月。", "月溪东步初来折。", "香处是瑶芳。", "芳瑶是处香。", "藓花浮晕浅。", "浅晕浮花藓。", "清对一枝瓶。", "瓶枝一对清。"]'),
('song-ci-362','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','浅红绡透春裁剪。',52,'宋词/ci.song.5000.json','["浅红绡透春裁剪。", "剪裁春透绡红浅。", "机锦织情丝。", "丝情织锦机。", "意深凭远寄。", "寄远凭深意。", "波渺胜愁多。", "多愁胜渺波。"]'),
('song-ci-363','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','点点花飞春恨浅。',52,'宋词/ci.song.5000.json','["点点花飞春恨浅。", "浅恨春飞花点点。", "莺语似多情。", "情多似语莺。", "恋春增酒劝。", "劝酒增春恋。", "颦损翠蛾新。", "新蛾翠损颦。"]'),
('song-ci-364','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','曲屏春展山浮玉。',52,'宋词/ci.song.5000.json','["曲屏春展山浮玉。", "玉浮山展春屏曲。", "香鸭瑞云翔。", "翔云瑞鸭香。", "醉深留客意。", "意客留深醉。", "凉枕怯宵长。", "长宵怯枕凉。"]'),
('song-ci-365','菩萨蛮','梅窗','宋','宋词','song-ci','菩萨蛮','[]','玉钗松鬓凝云绿。',52,'宋词/ci.song.5000.json','["玉钗松鬓凝云绿。", "绿云凝鬓松钗玉。", "双翠碍枝长。", "长枝碍翠双。", "色丝添意密。", "密意添丝色。", "红映袖纱笼。", "笼纱袖映红。"]'),
('song-ci-366','西江月','梅窗','宋','宋词','song-ci','西江月','[]','雨过轻风弄柳，湖东映日春烟。',58,'宋词/ci.song.5000.json','["雨过轻风弄柳，湖东映日春烟。", "晴芜平水远连天。", "隐隐飞翻舞燕。", "燕舞翻飞隐隐。", "天连远水平芜。", "晴烟春日映东湖。", "柳弄风轻过雨。"]'),
('song-ci-367','阮郎归','梅窗','宋','宋词','song-ci','阮郎归','[]','皇州新景媚晴春。',56,'宋词/ci.song.5000.json','["皇州新景媚晴春。", "春晴媚景新。", "万家明月醉风清。", "清风醉月明。", "人游乐，乐游人。", "游人乐太平。", "御楼神圣喜都民。", "民都喜圣神。"]'),
('song-ci-368','踏莎行','欧阳','宋','宋词','song-ci','踏莎行','[]','雁字成行，角声悲送。',68,'宋词/ci.song.5000.json','["雁字成行，角声悲送。", "无端又作长安梦。", "青衫小帽这回来，安仁两鬓秋霜重。", "孤馆残灯，小楼钟动。", "马踢踏破前村冻。", "平生牵系为浮名，名垂万古知何用。"]'),
('song-ci-369','洞仙歌','刘一止','宋','宋词','song-ci','洞仙歌','[]','细风轻雾，锁山城清晓。',100,'宋词/ci.song.5000.json','["细风轻雾，锁山城清晓。", "冷蕊疏枝为谁好。", "对斜桥孤驿，流水溅溅，无限意，清影徘徊自照。", "何郎空立马，恼乱馀香，绮思凭花更娟妙。", "肠断处，天涯路远音稀，行人怨、角声吹老。", "叹客里经春又三年，向月地云阶，负伊多少。"]'),
('song-ci-370','夜行船','刘一止','宋','宋词','song-ci','夜行船','[]','十顷疏梅开半就。',68,'宋词/ci.song.5000.json','["十顷疏梅开半就。", "折芳条、嫩香沾袖。", "今度何郎，尊前疑怪，花共那人俱瘦。", "恻恻轻寒吹散酒。", "高城近、怕听更漏。", "可惜溪桥，月明风露，长是在人归后。"]'),
('song-ci-371','念奴娇','刘一止','宋','宋词','song-ci','念奴娇','[]','江边故国，望南云缥缈，连山修木。',120,'宋词/ci.song.5000.json','["江边故国，望南云缥缈，连山修木。", "远意渊明束带见，乡里儿曹何辱。", "世味熏人，折腰从事，俯仰何时足。", "可怜菊下，醉吟谁共徵逐。", "我爱九日佳名，飘然归思，想当年丘谷。", "梦绕篱边犹眷恋，满把清尊馀馥。", "援笔洪都，如君英妙，满座方倾属。", "月台挥袖，叫云声横断玉。"]'),
('song-ci-372','念奴娇','刘一止','宋','宋词','song-ci','念奴娇','[]','故山秋晚，叹萧萧华发，霜林同色。',120,'宋词/ci.song.5000.json','["故山秋晚，叹萧萧华发，霜林同色。", "崖谷题诗追旧赏，往往苍苔绿壁。", "二士权奇，一翁衰病，努力攀筇屐。", "佛香吹过，了知境是空寂。", "别后风月佳时，拄颐何事，想东林遥碧。", "小砑蛮笺惊秀句，天巧何会雕刻。", "倚马雄才，凌云逸气，路觉丹霄直。", "三千牍就，看君归奏文石。"]'),
('song-ci-373','念奴娇','刘一止','宋','宋词','song-ci','念奴娇','[]','燕台暮集，对秋容凄紧，松阴幂幂。',120,'宋词/ci.song.5000.json','["燕台暮集，对秋容凄紧，松阴幂幂。", "徙倚阑边临翠壑，千顷风烟横出。", "坐待冰轮，天空云散，一色如苍璧。", "姮娥有意，为谁来赴今夕。", "身世如许飘流，佳时轻过了，他年空忆。", "我辈情锺端未愧，昔日兰亭陈迹。", "坐上何人，骊歌凄断，语别还应惜。", "有心红烛，替人珠泪频滴。"]'),
('song-ci-374','念奴娇','刘一止','宋','宋词','song-ci','念奴娇','[]','水烟收尽，望汀苹千顷，银光如幂。',120,'宋词/ci.song.5000.json','["水烟收尽，望汀苹千顷，银光如幂。", "霜镜无痕清夜久，惟有惊鱼跳出。", "月在杯中，我疑天赐，欢饮仍如璧。", "姮娥应为，后期偿赛今夕。", "遥想当日同盟，山斋孤讽，有新诗相忆。", "聚散难常空怅望，萍梗飘流踪迹。", "明月明年，此身此夜，知与谁同惜。", "参横河侧，短篷清露时滴。"]'),
('song-ci-375','踏莎行','刘一止','宋','宋词','song-ci','踏莎行','[]','两水中分，三山半落。',68,'宋词/ci.song.5000.json','["两水中分，三山半落。", "风云气象通廖廓。", "少年怀古有新诗，清愁不是伤春作。", "六代豪华，一时燕乐。", "从教雨打风吹却。", "与君携酒近阑干，月明满地天无幕。"]'),
('song-ci-376','虞美人','刘一止','宋','宋词','song-ci','虞美人','[]','浪花云叶交加舞。',66,'宋词/ci.song.5000.json','["浪花云叶交加舞。", "身近轻冥路。", "天知此客解骑鲸。", "今夜一江明月、送行行。", "从今直上鳌峰去。", "应记经行处。", "莫将险语乱江声。", "却怕月中高卧、彩虹惊。"]'),
('song-ci-377','江城子','刘一止','宋','宋词','song-ci','江城子','[]','秋香岩下著尊罍。',86,'宋词/ci.song.5000.json','["秋香岩下著尊罍。", "小徘徊。", "莫停杯。", "来岁花时，相望两悠哉。", "看取修眉萦度曲，真个泪，界香腮。", "船头击鼓片帆开。", "晓风吹。", "首应回。", "景物撩人，诗思不胜催。", "会有江山凄惋句，凭过雁，寄侬来。"]'),
('song-ci-378','临江仙','刘一止','宋','宋词','song-ci','临江仙','[]','柳外双旌斜照日，匆匆去意难留。',70,'宋词/ci.song.5000.json','["柳外双旌斜照日，匆匆去意难留。", "大江旁畔老诸侯。", "举觞仍气概，觅句更风流。", "迟暮不堪容易别，溪声为写离愁。", "自从今日转船头。", "他时扶杖叟，独立向沧洲。"]'),
('song-ci-379','临江仙','刘一止','宋','宋词','song-ci','临江仙','[]','落日西风原上好，笛声谁奏伊凉。',70,'宋词/ci.song.5000.json','["落日西风原上好，笛声谁奏伊凉。", "缓寻山径掇幽芳。", "平生真自许，江海老潜郎。", "最爱杯中浮蚁闹，鹅儿破壳娇黄。", "使君醉里是家乡。", "更追修禊帖，一咏一传觞。"]'),
('song-ci-380','雪月交光・醉蓬莱','刘一止','宋','宋词','song-ci','雪月交光・醉蓬莱','[]','正五云飞杖，缟素褰裳，乱空交舞。',120,'宋词/ci.song.5000.json','["正五云飞杖，缟素褰裳，乱空交舞。", "拂石归来，向玉阶微步。", "欲唤冰娥，暂凭风使，为扫氛驱雾。", "渐见停轮，人间未识，高空真侣。", "千里无尘，地连天迥，倦客古来，路迷江树。", "故国烟深，想溪树何处。", "云鬓分行，翠眉萦曲，对夜寒尊俎。", "清影徘徊，端应坐有，风流能赋。"]'),
('song-ci-381','望海潮','刘一止','宋','宋词','song-ci','望海潮','[]','垂杨深院，啼莺清昼，东风细绕檐牙。',129,'宋词/ci.song.5000.json','["垂杨深院，啼莺清昼，东风细绕檐牙。", "野色乱春，娇云捧日，燕翻蝶舞交加。", "温诏下天涯。", "早画船飞楫，叠鼓鸣挝。", "共挽旌幢，缓留丝竹醉韶华。", "江都自古豪夸。", "正迷楼坠絮，月观吹花。", "玉扆眷深，金瓯望重，何人暗草黄麻。", "归路接堤沙。", "宴上林风月，紫阙烟霞。", "凤检飞来，便将春色到朝家。"]'),
('song-ci-382','醉蓬莱','刘一止','宋','宋词','song-ci','醉蓬莱','[]','正官桥柳润，候馆梅开，暮云凄冽。',120,'宋词/ci.song.5000.json','["正官桥柳润，候馆梅开，暮云凄冽。", "泽国春归，是烧灯时节。", "吹绽红蕖，挽低星斗，共水光澄澈。", "霜瓦楼台，参差似与，蓬壶相接。", "千骑遨游，万家嬉笑，帘卷东风，弄妆成列。", "慢舞尊前，看轻盈回雪。", "来岁今宵，舜韶声里，对六鳌双阙。", "凤检飞来，玉骢去踏，青门华月。"]'),
('song-ci-383','望明河','刘一止','宋','宋词','song-ci','望明河','[]','华旌耀日，报天上使星，初辞金阙。',129,'宋词/ci.song.5000.json','["华旌耀日，报天上使星，初辞金阙。", "许国精忠，试此日传岩，济川舟楫。", "向来鸡林外，况传咏、篇章雄绝。", "问人地、真是唐朝第一，未论勋业。", "鲸波霁云千叠。", "望仙驭缥缈，神山明灭。", "万里勤劳，也等是壮年，绣衣持节。", "丈夫功名事，未肯向、尊前轻伤别。", "看飞棹、归侍宸游，宴赏太平风月。"]'),
('song-ci-384','蓦山溪','刘一止','宋','宋词','song-ci','蓦山溪','[]','卿云衍苒，翠壁天开就。',102,'宋词/ci.song.5000.json','["卿云衍苒，翠壁天开就。", "移下小方壶，照初日、嘉林濯秀。", "君恩暂许，丘壑憩夔龙，开径竹，续岩花，小试丹青手。", "声名德业，汉代谁居右。", "红旆碧油幢，想今古、山中未有。", "霜松手种，应待茯芩生，斋酿熟，玉泉香，还上萱堂寿。"]'),
('song-ci-385','生查子','刘一止','宋','宋词','song-ci','生查子','[]','城头长短更，水调高低唱。',48,'宋词/ci.song.5000.json','["城头长短更，水调高低唱。", "别洒不盈斟，泪洒风烟上。", "明年二月时，更向城阴望。", "只有旧歌辞，传作风流样。"]'),
('song-ci-386','清平乐','刘一止','宋','宋词','song-ci','清平乐','[]','相望吴楚。',54,'宋词/ci.song.5000.json','["相望吴楚。", "远信无凭据。", "欲倩春风吹泪去。", "化作愁云恨雨。", "春应已到三吴。", "楚江日夜东徂。", "惟有溯流鱼上，不知尺素来无。"]'),
('song-ci-387','青玉案','刘一止','宋','宋词','song-ci','青玉案','[]','小山遮断蓝桥路。',80,'宋词/ci.song.5000.json','["小山遮断蓝桥路。", "恨短梦、难飞去。", "长记修眉萦曲度。", "约花开槛，映风招袖，总是怜渠处。", "追欢我已伤迟暮。", "犹有多情旧时句。", "极目高楼千尺许。", "竹枝三唱，为君凄断，东日西边雨。"]'),
('song-ci-388','梦横塘','刘一止','宋','宋词','song-ci','梦横塘','[]','浪痕经雨，鬓影吹寒，晓来无限萧瑟。',130,'宋词/ci.song.5000.json','["浪痕经雨，鬓影吹寒，晓来无限萧瑟。", "野色分桥，翦不断、溪山风物。", "船系朱藤，路迷烟寺，远鸥浮没。", "听疏钟断鼓，似近远遥，惊心事、伤羁客。", "新醅旋压鹅黄，拚清愁在眼，酒病萦骨。", "绣阁娇慵，争解说、短封传忆。", "念谁伴、涂妆绾结。", "嚼蕊吹花弄秋色。", "恨对南云，此时凄断，有何人知得。"]'),
('song-ci-389','西河','刘一止','宋','宋词','song-ci','西河','[]','山驿晚，行人昨停征辔。',125,'宋词/ci.song.5000.json','["山驿晚，行人昨停征辔。", "白沙翠竹锁柴门，乱峰相倚。", "一番急雨洗天回，扫云风定还起。", "念凄断，谁与寄。", "双鱼尽素难委。", "遥知洞户隔烟窗，簟横秋水。", "淡花明玉不胜寒，绿尊初试冰蚁。", "小欢细酌任敧醉。", "扑流萤、应卜心事。", "谁记天涯憔悴。", "对今宵、皓月明河千里。", "梦越空城疏烟里。"]'),
('song-ci-390','眼儿媚','刘一止','宋','宋词','song-ci','眼儿媚','[]','度岁经年两看承。',58,'宋词/ci.song.5000.json','["度岁经年两看承。", "谁信有轻分。", "从前稳过，如今方悔，不会温存。", "眼前无限经行地，何处不销魂。", "多应为你，不看风月，睡过黄昏。"]'),
('song-ci-391','水调歌头','刘一止','宋','宋词','song-ci','水调歌头','[]','千古严陵濑，清夜月荒凉。',114,'宋词/ci.song.5000.json','["千古严陵濑，清夜月荒凉。", "水明沙净，波面一叶弄孤光。", "北望旄头天际，杀气遥昏楚甸，云树失青苍。", "愁绝未归客，衰鬓点吴霜。", "听江边，鸣宝瑟，想英皇。", "骑鲸仙裔，高韵清绝胜风篁。", "醉入无何境界，却笑昔人底事，远慕白云乡。", "不见咸阳道，烟草茂陵荒。"]'),
('song-ci-392','水调歌头','刘一止','宋','宋词','song-ci','水调歌头','[]','缥缈青溪畔，山翠欲粘天。',114,'宋词/ci.song.5000.json','["缥缈青溪畔，山翠欲粘天。", "纵云台上，揽风招月自何年。", "新旧今逢二妙，人地一时清绝，高并两峰寒。", "歌发烟霏外，人在去留间。", "著方床，容老子，醉时眠。", "一尊相属，高会何意此时圆。", "况是古今难遇，人月竹花俱妙，曾见句中传。", "不向今宵醉，忍负四婵娟。"]'),
('song-ci-393','鹧鸪天','刘一止','宋','宋词','song-ci','鹧鸪天','[]','岩下清阴引兴长。',64,'宋词/ci.song.5000.json','["岩下清阴引兴长。", "坐中初识令君香。", "揽将风月归诗薮，乞得溪山作醉乡。", "怜我老，与传觞。", "吴霜点鬓又何妨。", "只应银烛交红夜，羞对双歌发彩光。"]'),
('song-ci-394','木兰花・玉楼春','刘一止','宋','宋词','song-ci','木兰花・玉楼春','[]','桂香台上秋风袅。',64,'宋词/ci.song.5000.json','["桂香台上秋风袅。", "鸭绿溪前离思渺。", "一卮芳醑细深倾，听尽阳关须醉倒。", "政成早晚传温诏。", "莫恋江城歌吹绕。", "明年身到凤池边，重看春波生故沼。"]'),
('song-ci-395','浣溪沙','刘一止','宋','宋词','song-ci','浣溪沙','[]','午夜明蟾冷浸溪。',48,'宋词/ci.song.5000.json','["午夜明蟾冷浸溪。", "姮娥应有辟寒犀。", "桂岩仍在曲阑西。", "撷蕊攀条情未已，经丘寻壑想招携。", "不应痴马惜障泥。"]'),
('song-ci-396','点绛唇','刘一止','宋','宋词','song-ci','点绛唇','[]','洞户香凝，宴开特地风烟好。',50,'宋词/ci.song.5000.json','["洞户香凝，宴开特地风烟好。", "靓妆娟妙。", "玉雪光相照。", "认是桃源，绿水红云绕。", "真曾到。", "漾舟人老。", "应被桃花笑。"]'),
('song-ci-397','点绛唇','刘一止','宋','宋词','song-ci','点绛唇','[]','云鬓分行，照人明艳新妆就。',50,'宋词/ci.song.5000.json','["云鬓分行，照人明艳新妆就。", "御香窗牖。", "细酌鹅儿酒。", "铁拨鵾弦，一试春风手。", "龙仙奏。", "绛霄声透。", "不许人间有。"]'),
('song-ci-398','临江仙','刘一止','宋','宋词','song-ci','临江仙','[]','台上风光浓欲滴，傍阑芳桂阴成。',70,'宋词/ci.song.5000.json','["台上风光浓欲滴，傍阑芳桂阴成。", "乱山相对长官青。", "琢诗能句好，举酒见心倾。", "团扇不应秋后弃，几年仁惠风行。", "渭城柳色若为情。", "一尊松竹底，三唱和秋声。"]'),
('song-ci-399','蓦山溪','刘一止','宋','宋词','song-ci','蓦山溪','[]','王家人地，奕奕争高秀。',102,'宋词/ci.song.5000.json','["王家人地，奕奕争高秀。", "金紫照青春，想当日、乌衣巷口。", "声名气概，今见两朱轓，诗似锦，酒如渑，属意风光厚。", "酿泉石壁，未减南阳寿。", "清兴与谁同，探梅萼、溪桥驿堠。", "东风御柳，应访此韩翃，归步稳，赤墀边，肯记幽栖否。"]'),
('song-ci-400','念奴娇','刘一止','宋','宋词','song-ci','念奴娇','[]','小舟漂兀，犯溪烟深入，无穷寒碧。',120,'宋词/ci.song.5000.json','["小舟漂兀，犯溪烟深入，无穷寒碧。", "路绕莲塘浑乱眼，千顷朱朱白白。", "闻说高情，寻盟鸥鹭，爱此风标客。", "掀髯一笑，顿忘身世形迹。", "我爱古邑风流，碧峰争秀峙，相持如掖。", "制锦才雄应未怕，百里文书堆积。", "吏散庭空，举觞遨月，饮兴何妨剧。", "却怜宣子，杖头才挂钱百。"]'),
('song-ci-401','柳梢青','刘一止','宋','宋词','song-ci','柳梢青','[]','柳汀烟暮。',61,'宋词/ci.song.5000.json','["柳汀烟暮。", "常记岸帻，风流张绪。", "酒兴诗情，而今移向，那边佳处。", "使君自乐萧闲，未肯副、岩廊虚伫。", "不念寒窗，老人幽梦，追寻无据。"]'),
('song-ci-402','鹊桥仙','刘一止','宋','宋词','song-ci','鹊桥仙','[]','春风真个，取将花去，酬我清阴满院。',68,'宋词/ci.song.5000.json','["春风真个，取将花去，酬我清阴满院。", "名园清昼漏签迟，未肯负、酒朋歌伴。", "使君情在，暮云合处，卧看碧峰峨弁。", "向来魂梦几曾真，休怨断、楼高不见。"]'),
('song-ci-403','浣溪沙','刘一止','宋','宋词','song-ci','浣溪沙','[]','曾向蓬莱得姓名。',48,'宋词/ci.song.5000.json','["曾向蓬莱得姓名。", "坐中省识是飞琼。", "琵琶翻作步虚声。", "一自当时收拨后，世间弦索不堪听。", "梦回凄断月胧明。"]'),
('song-ci-404','点绛唇','刘一止','宋','宋词','song-ci','点绛唇','[]','岁月飘流，故人相望如箕斗。',50,'宋词/ci.song.5000.json','["岁月飘流，故人相望如箕斗。", "畔愁千首。", "诗骨能清瘦。", "白日鵾弦，同看春风手。", "君知否。", "袖痕别后。", "犹有临歧酒。"]'),
('song-ci-405','点绛唇','刘一止','宋','宋词','song-ci','点绛唇','[]','山邑新凉，夜堂爽气侵南斗。',50,'宋词/ci.song.5000.json','["山邑新凉，夜堂爽气侵南斗。", "为谁骧首。", "月冷冰蛾瘦。", "八万二千，雕琢琼瑶手。", "君知否。", "待君归后。", "双照杯中酒。"]'),
('song-ci-406','望海潮','刘一止','宋','宋词','song-ci','望海潮','[]','东郊人报，春风消息，先归御柳宫梅。',129,'宋词/ci.song.5000.json','["东郊人报，春风消息，先归御柳宫梅。", "残雪恋枝，轻阴阁雨，郁葱瑞气佳哉。", "清晓九门开。", "听舜韶声举，迤逦天街。", "双阙连云，六鳌横海驾峰来。", "华灯竟簇楼台。", "正丰年共乐，欢意徘徊。", "帘卷弄妆，尘香趁马，轻寒细入人怀。", "争待凤舆回。", "看一天星斗，移下蓬莱。", "是处歌谣，太平声入万年杯。"]'),
('song-ci-407','青玉案','刘一止','宋','宋词','song-ci','青玉案','[]','马头双鹊飞来喜。',80,'宋词/ci.song.5000.json','["马头双鹊飞来喜。", "惜凝望、音书至。", "一掬离怀千万事。", "绿窗深夜，短笺封就，应也寻人寄。", "春风鬓畔疏梅蕊。", "映妆艳、清如洗。", "苦恨眼边常忆记。", "楚宫行路，倚桥攀驿，供尽梅花泪。"]'),
('song-ci-408','喜迁莺','刘一止','宋','宋词','song-ci','喜迁莺','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','晓光催角。',126,'宋词/ci.song.5000.json','["晓光催角。", "听宿鸟未惊，邻鸡先觉。", "迤逦烟村，马嘶人起，残月尚穿林薄。", "泪痕带霜微凝，酒力冲寒犹弱。", "叹倦客、悄不禁，重染风尘京洛。", "追念，人别后，心事万重，难觅孤鸿托。", "翠幌娇深，曲屏香暖，争念岁寒飘泊。", "怨月恨花烦恼，不是不曾经著。", "这情味，望一成消减，新来还恶。"]'),
('song-ci-409','踏莎行','刘一止','宋','宋词','song-ci','踏莎行','[]','淡月精神，疏梅风韵。',68,'宋词/ci.song.5000.json','["淡月精神，疏梅风韵。", "粉香融脸胭脂润。", "袖痕犹带玉虬烟，六朝窄样裁宫锦。", "眉黛分愁，眼波传信。", "酒阑画烛交红影。", "有期无定却瞋人，索强我早谙伊性。"]'),
('song-ci-410','浣溪沙','刘一止','宋','宋词','song-ci','浣溪沙','[]','莫问新欢与旧愁。',48,'宋词/ci.song.5000.json','["莫问新欢与旧愁。", "浅颦微笑总风流。", "眼波横注楚江秋。", "十字街头家住处，心肠四散几时休。", "揽风招月是朱楼。"]'),
('song-ci-411','点绛唇','汪藻','宋','宋词','song-ci','点绛唇','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','新月娟娟，夜寒江静山衔斗。',50,'宋词/ci.song.5000.json','["新月娟娟，夜寒江静山衔斗。", "起来搔首。", "梅影横窗瘦。", "好个霜天，闲却传杯手。", "君知否。", "乱鸦啼后。", "归兴浓於酒。"]'),
('song-ci-412','点绛唇','汪藻','宋','宋词','song-ci','点绛唇','[]','高柳蝉嘶，采菱歌断秋风起。',50,'宋词/ci.song.5000.json','["高柳蝉嘶，采菱歌断秋风起。", "晚云如髻。", "湖上山横翠。", "帘卷西楼，过雨凉生袂。", "天如水。", "画楼十二。", "有个人同倚。"]'),
('song-ci-413','小重山','汪藻','宋','宋词','song-ci','小重山','[]','月下潮生红蓼汀。',70,'宋词/ci.song.5000.json','["月下潮生红蓼汀。", "浅霞都敛尽，四山青。", "柳梢风急坠流萤。", "随波处，点点乱寒星。", "别语寄丁宁。", "如今能间隔，几长亭。", "夜来秋气入银屏。", "梧桐雨，远恨不同听。"]'),
('song-ci-414','醉落魄・一斛珠','汪藻','宋','宋词','song-ci','醉落魄・一斛珠','[]','小舟帘隙。',67,'宋词/ci.song.5000.json','["小舟帘隙。", "佳人半露梅妆额。", "绿云低映花如刻。", "恰似秋宵，一半银蟾白。", "结儿梢朵香红扐。", "钿蝉隐隐摇金碧。", "春山秋水浑无迹。", "不露墙头，些子真消息。"]'),
('song-ci-415','蓦山溪','曹组','宋','宋词','song-ci','蓦山溪','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','洗妆真态，不作铅华御。',102,'宋词/ci.song.5000.json','["洗妆真态，不作铅华御。", "竹外一枝斜，想佳人、天寒日暮。", "黄昏小院，无处著清香，风细细，雪垂垂，何况江头路。", "月边疏影，梦到消魂处。", "结子欲黄时，又须著、廉纤细雨。", "孤芳一世，供断有情愁，销瘦却，东阳也，试问花知否。"]'),
('song-ci-416','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','秋劲风高，暗知斗力添弓面。',50,'宋词/ci.song.5000.json','["秋劲风高，暗知斗力添弓面。", "靶分筠斡。", "月到天心满。", "白羽流星，飞上黄金碗。", "胡沙雁。", "云边惊散。", "压尽天山箭。"]'),
('song-ci-417','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','疏柳残蝉，助人离思斜阳外。',50,'宋词/ci.song.5000.json','["疏柳残蝉，助人离思斜阳外。", "淡烟疏霭。", "节物随时改。", "水已无情，风更无情㬠。", "兰舟解。", "水流风快。", "回首人何在。"]'),
('song-ci-418','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','密炬高烧，宝刀时翦金花碎。',50,'宋词/ci.song.5000.json','["密炬高烧，宝刀时翦金花碎。", "照人欢醉。", "也照人无睡。", "待得灰心，陪尽千行泪。", "笼纱里。", "夜凉如水。", "犹喜长成对。"]'),
('song-ci-419','如梦令','曹组','宋','宋词','song-ci','如梦令','[]','门外绿阴千顷。',40,'宋词/ci.song.5000.json','["门外绿阴千顷。", "两两黄鹂相应。", "睡起不胜情，行到碧梧金井。", "人静。", "人静。", "风动一枝花影。"]'),
('song-ci-420','扑蝴蝶','曹组','宋','宋词','song-ci','扑蝴蝶','[]','人生一世。',90,'宋词/ci.song.5000.json','["人生一世。", "思量争甚底。", "花开十日，已随尘共水。", "且看欲尽花枝，未厌伤多酒盏，何须细推物理。", "幸容易。", "有人争奈，只知名与利。", "朝朝日日，忙忙劫劫地。", "待得一晌闲时，又却三春过了，何如对花沈醉。"]'),
('song-ci-421','忆少年','曹组','宋','宋词','song-ci','忆少年','[]','年时酒伴，年时去处，年时春色。',58,'宋词/ci.song.5000.json','["年时酒伴，年时去处，年时春色。", "清明又近也，却天涯为客。", "念过眼、光阴难再得。", "想前欢、尽成陈迹。", "登临恨无语，把阑干暗拍。"]'),
('song-ci-422','蓦山溪','曹组','宋','宋词','song-ci','蓦山溪','[]','草熏风暖，楼阁笼轻雾。',102,'宋词/ci.song.5000.json','["草熏风暖，楼阁笼轻雾。", "墙短出花梢，映谁家、绿杨朱户。", "寻芳拾翠，绮陌自青春，江南远，踏青时，谁念方羁旅。", "昔游如梦，空忆横塘路。", "罗袖舞台风，想桃花、依然旧树。", "一怀离恨，满眼欲归心，山连水，水连云，怅望人何处。"]'),
('song-ci-423','相思会・千年调','曹组','宋','宋词','song-ci','相思会・千年调','[]','人无百年人，刚作千年调。',95,'宋词/ci.song.5000.json','["人无百年人，刚作千年调。", "待把门关铁铸，鬼见失笑。", "多愁早老。", "惹尽闲烦恼。", "我醒也，枉劳心，谩计较。", "粗衣淡饭，赢取暖和饱。", "住个宅儿，只要不大不小。", "常教洁净，不种闲花草。", "据见定、乐平生，便是神仙了。"]'),
('song-ci-424','品令','曹组','宋','宋词','song-ci','品令','[]','乍寂寞。',65,'宋词/ci.song.5000.json','["乍寂寞。", "帘栊静，夜久寒生罗幕。", "窗儿外、有个梧桐树，早一叶、两叶落。", "独倚屏山欲寐，月转惊飞乌鹊。", "促织儿、声响虽不大，敢教贤、睡不著。"]'),
('song-ci-425','小重山','曹组','宋','宋词','song-ci','小重山','[]','帘卷东风日射窗。',70,'宋词/ci.song.5000.json','["帘卷东风日射窗。", "小山庭院静，接回廊。", "疏疏晴雨弄斜阳。", "凭栏久，墙外杏花香。", "时节好寻芳。", "多情怀酒伴，忆欢狂。", "归鸿应已度潇湘。", "音书杳，前事忍思量。"]'),
('song-ci-426','小重山','曹组','宋','宋词','song-ci','小重山','[]','陌上花繁莺乱啼。',70,'宋词/ci.song.5000.json','["陌上花繁莺乱啼。", "骅骝金络脑，锦障泥。", "寻芳行乐忆当时。", "联镖处，飞鞚绿杨堤。", "春物又芳菲。", "情如风外柳，只依依。", "空怜佳景负归期。", "愁心切，惟有梦魂知。"]'),
('song-ci-427','青玉案','曹组','宋','宋词','song-ci','青玉案','[]','碧山锦树明秋霁。',82,'宋词/ci.song.5000.json','["碧山锦树明秋霁。", "路转陡、疑无地。", "忽有人家临曲水。", "竹篱茅舍，酒旗沙岸，一簇成村市。", "凄凉只恐乡心起。", "凤楼远、回头谩凝睇。", "何处今宵孤馆里。", "一声征雁，半窗残月，总是离人泪。"]'),
('song-ci-428','鹧鸪天','曹组','宋','宋词','song-ci','鹧鸪天','[]','辇路薰风起绿槐。',64,'宋词/ci.song.5000.json','["辇路薰风起绿槐。", "都人凝望满天街。", "云韶杳杳鸣鞘肃，芝盖亭亭障扇开。", "微雨过，绝纤埃。", "内家车子走轻雷。", "千门不敢垂帘看，总上银钩等驾来。"]'),
('song-ci-429','渔家傲','曹组','宋','宋词','song-ci','渔家傲','[]','水上落红时片片。',72,'宋词/ci.song.5000.json','["水上落红时片片。", "江头雪絮飞缭乱。", "渺渺碧波天漾远。", "平沙暖。", "花风一阵苹香满。", "晚来醉著无人唤。", "残阳已在青山半。", "睡觉只疑花改岸。", "抬头看。", "元来弱缆风吹断。"]'),
('song-ci-430','阮郎归','曹组','宋','宋词','song-ci','阮郎归','[]','檐头风佩响丁东。',56,'宋词/ci.song.5000.json','["檐头风佩响丁东。", "帘疏烛影红。", "秋千人散月溶溶。", "楼台花气中。", "春酒醒，夜寒浓。", "绣衾谁与同。", "只愁梦短不相逢。", "觉来罗帐空。"]'),
('song-ci-431','临江仙','曹组','宋','宋词','song-ci','临江仙','[]','青琐窗深红兽暖，灯前共倒金尊。',70,'宋词/ci.song.5000.json','["青琐窗深红兽暖，灯前共倒金尊。", "数枝梅浸玉壶春。", "雪明浑似晓，香重欲成云。", "户外马嘶催客起，席间欢意留人。", "从他微霰落粉粉。", "不妨吹酒面，归去醒馀醺。"]'),
('song-ci-432','鹧鸪天','曹组','宋','宋词','song-ci','鹧鸪天','[]','浅笑轻颦不在多。',64,'宋词/ci.song.5000.json','["浅笑轻颦不在多。", "远山微黛接横波。", "情吞醽醁千锺酒，心醉飞琼一曲歌。", "人欲散，奈愁何。", "更看朱袖拂云和。", "夜深醉墨淋浪处，书遍香红拥项罗。"]'),
('song-ci-433','青门饮','曹组','宋','宋词','song-ci','青门饮','[]','山静烟沈，岸空潮落。',129,'宋词/ci.song.5000.json','["山静烟沈，岸空潮落。", "晴天万里，飞鸿南渡。", "冉冉黄花，翠翅金钿，还是倚风凝露。", "岁岁青门饮，尽龙山、高阳俦侣。", "旧赏成空，回首旧游，人在何处。", "此际谁怜萍泛，空自感光阴，暗伤羁旅。", "醉里悲歌，夜深惊梦，无奈觉来情绪。", "孤馆昏还晓。", "厌时闻、南楼钟鼓。", "泪眼临风，肠断望中归路。"]'),
('song-ci-434','青玉案','曹组','宋','宋词','song-ci','青玉案','[]','田园有计归须早。',79,'宋词/ci.song.5000.json','["田园有计归须早。", "在家纵贫亦好。", "南来北去何日了。", "光阴送尽，可怜青鬓，暗逐流年老。", "寂寥孤馆残灯照。", "乡思惊时梦初觉。", "落月苍苍关河晓。", "一声鸡唱，马嘶人起，又上长安道。"]'),
('song-ci-435','好事近','曹组','宋','宋词','song-ci','好事近','[]','茅舍竹篱边，雀噪晚枝时节。',53,'宋词/ci.song.5000.json','["茅舍竹篱边，雀噪晚枝时节。", "一阵暗香飘处，已难禁愁绝。", "江南得地故先开，不待有飞雪。", "肠断几回山路，恨无人攀折。"]'),
('song-ci-436','醉花阴','曹组','宋','宋词','song-ci','醉花阴','[]','九陌寒轻春尚早。',62,'宋词/ci.song.5000.json','["九陌寒轻春尚早。", "灯火都门道。", "月下步莲人，薄薄香罗，峭窄春衫小。", "梅妆浅淡风蛾袅。", "随路听嬉笑。", "无限面皮儿，虽则不同，各是一般好。"]'),
('song-ci-437','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','小小朱桥，柳边人过横塘路。',50,'宋词/ci.song.5000.json','["小小朱桥，柳边人过横塘路。", "细风时度。", "□浪痕痕去。", "草软沙平，稳衬寻幽步。", "□□处。", "乱红飞舞。", "回首春城暮。"]'),
('song-ci-438','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','云透斜阳，半楼红影明窗户。',50,'宋词/ci.song.5000.json','["云透斜阳，半楼红影明窗户。", "暮山无数。", "归雁愁远去。", "十里平芜，花远重重树。", "空凝伫。", "故人何处。", "可惜春将暮。"]'),
('song-ci-439','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','沈醉归来，洞房灯火闲相照。',50,'宋词/ci.song.5000.json','["沈醉归来，洞房灯火闲相照。", "夜寒犹峭。", "信意和衣倒。", "春梦虽多，好梦长长少。", "纱窗晓。", "凤帏人悄。", "花外空啼鸟。"]'),
('song-ci-440','水龙吟','曹组','宋','宋词','song-ci','水龙吟','[]','晓天谷雨晴时，翠罗护日轻烟里。',125,'宋词/ci.song.5000.json','["晓天谷雨晴时，翠罗护日轻烟里。", "酴醿径暖，柳花风淡，千葩浓丽。", "三月春光，上林池馆，西都花市。", "看轻盈隐约，何须解语，凝情处、无穷意。", "金殿筠笼岁贡，最姚黄、一枝娇贵。", "东风既与花王，芍药须为近侍。", "歌舞筵中，满装归帽，斜簪云髻。", "有高情未已，齐烧绛蜡，向阑边醉。"]'),
('song-ci-441','声声慢','曹组','宋','宋词','song-ci','声声慢','[]','重檐飞峻，丽彩横空，繁华壮观都城。',119,'宋词/ci.song.5000.json','["重檐飞峻，丽彩横空，繁华壮观都城。", "云母屏开八面，人在青冥。", "凭栏瑞烟深处，望皇居、遥识蓬瀛。", "回环阁道，五花相斗，压尽旗亭。", "歌酒长春不夜，金翠照罗绮，笑语盈盈。", "陆海人山辐辏，万国欢声。", "登临四时总好，况花朝、月白风清。", "丰年乐，岁熙熙、且醉太平。"]'),
('song-ci-442','蝶恋花','曹组','宋','宋词','song-ci','蝶恋花','[]','帘卷真珠深院静。',70,'宋词/ci.song.5000.json','["帘卷真珠深院静。", "满地槐阴，镂日如云影。", "午枕花前情思凝。", "象床冰簟光相映。", "过面风情如酒醒。", "沈水瓶寒，带绠来金井。", "涤尽烦襟无睡兴。", "阑干六曲还重凭。"]'),
('song-ci-443','浣溪沙','曹组','宋','宋词','song-ci','浣溪沙','[]','柳絮池台淡淡风。',48,'宋词/ci.song.5000.json','["柳絮池台淡淡风。", "碧波花岫小桥通。", "云连丽宇倚晴空。", "芳草绿杨人去住，短墙幽径燕西东。", "攀条弄蕊得从容。"]'),
('song-ci-444','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','霜落吴江，万畦香稻来场圃。',50,'宋词/ci.song.5000.json','["霜落吴江，万畦香稻来场圃。", "夜村舂黍。", "草屋寒灯雨。", "玉粒长腰，沈水温温注。", "相留住。", "共抄云子。", "更听歌声度。"]'),
('song-ci-445','点绛唇','曹组','宋','宋词','song-ci','点绛唇','[]','一片南云，定知来做巫山雨。',50,'宋词/ci.song.5000.json','["一片南云，定知来做巫山雨。", "歌声才度。", "只向风中住。", "恼乱襄王，无限牵情处。", "长天暮。", "又还飞去。", "目断阳台路。"]'),
('song-ci-446','婆罗门引','曹组','宋','宋词','song-ci','婆罗门引','[]','涨云暮卷，漏声不到小帘栊。',93,'宋词/ci.song.5000.json','["涨云暮卷，漏声不到小帘栊。", "银河淡扫澄空。", "皓月当轩高挂，秋入广寒宫。", "正金波不动，桂影朦胧。", "佳人未逢。", "叹此夕、与谁同。", "望远伤怀对景，霜满愁红。", "南楼何处，想人在、长笛一声中。", "凝泪眼、泣尽西风。"]'),
('song-ci-447','失调名','曹组','宋','宋词','song-ci','失调名','[]','甚时得归京里去。',8,'宋词/ci.song.5000.json','["甚时得归京里去。"]'),
('song-ci-448','卜算子','曹组','宋','宋词','song-ci','卜算子','[]','松竹翠萝寒，迟日江山暮。',52,'宋词/ci.song.5000.json','["松竹翠萝寒，迟日江山暮。", "幽径无人独自芳，此恨凭谁诉。", "似共梅花语。", "尚有寻芳侣。", "著意闻时不肯香，香在无心处。"]'),
('song-ci-449','小重山','曹组','宋','宋词','song-ci','小重山','[]','深拥熏篝倏已冥。',70,'宋词/ci.song.5000.json','["深拥熏篝倏已冥。", "寂寥山枕畔，梦难成。", "谁堪三两夜乌声。", "银缸炧，花影上围屏。", "犹记旧时情。", "帘边人似月，月如冰。", "从今张眼到天明。", "衣带缓，谁与问伶俜。"]'),
('song-ci-450','脱银袍','曹组','宋','宋词','song-ci','脱银袍','[]','济楚风光，升平时世。',87,'宋词/ci.song.5000.json','["济楚风光，升平时世。", "端门支散，碗遂逐旋温来，吃得过、那堪更使金器。", "分明是。", "与穷汉、消灾灭罪。", "又没支分，犹然递滞。", "打笃磨槎来根底。", "换头巾，便上弄交番斯替。", "告官里。", "驼逗高阳饿鬼。"]'),
('song-ci-451','忆瑶姬','曹组','宋','宋词','song-ci','忆瑶姬','[]','雨细云轻，花娇玉软，於中好个情性。',124,'宋词/ci.song.5000.json','["雨细云轻，花娇玉软，於中好个情性。", "争奈无缘相见，有分孤零。", "香笺细写频相问。", "我一句句儿都听。", "到如今，不得同欢，伏惟与他耐静。", "此事凭谁执证。", "有楼前明月，窗外花影。", "拚了一生烦恼，为伊成病。", "只恐更把风流逞。", "便因循、误人无定。", "恁时节、若要眼儿斯觑，除非会圣。"]'),
('song-ci-452','蓦山溪','万俟咏','宋','宋词','song-ci','蓦山溪','[]','芳菲叶底。',102,'宋词/ci.song.5000.json','["芳菲叶底。", "谁会秋江意。", "深绿护轻黄，怕青女、霜侵憔悴。", "开分早晚，都占九秋天，花四出，香七里。", "独步珠宫里。", "佳名岩桂。", "却是因遗子。", "不自月中来，又那得、萧萧风味。", "霓裳旧曲，休问广寒人，飞太白，酬仙蕊。", "香外无香比。"]'),
('song-ci-453','临江仙','万俟咏','宋','宋词','song-ci','临江仙','[]','寒甚正前三五日。',70,'宋词/ci.song.5000.json','["寒甚正前三五日。", "风将腊雪侵寅。", "彩鸡缕燕已惊春。", "玉梅飞上苑，金柳动天津。", "□□□□□□□，□□□□□□。", "□□□□□□□。", "春盘共饤饾，绕坐庆时新。"]'),
('song-ci-454','雪明鹊夜慢・雪明鹊夜','万俟咏','宋','宋词','song-ci','雪明鹊夜慢・雪明鹊夜','[]','望五云多处春深，开阆苑、别就蓬岛。',115,'宋词/ci.song.5000.json','["望五云多处春深，开阆苑、别就蓬岛。", "正梅雪韵清，桂月光皎。", "凤帐龙帘萦嫩风，御座深、翠金间绕。", "半天中、香泛千花，灯挂百宝。", "圣时观风重腊，有箫鼓沸空，锦绣匝道。", "竞呼卢、气贯调欢笑。", "暗里金钱掷下，来侍燕、歌太平睿藻。", "愿年年此际，迎春不老。"]'),
('song-ci-455','凤皇枝令・凤凰枝令','万俟咏','宋','宋词','song-ci','凤皇枝令・凤凰枝令','[]','人间天上。',64,'宋词/ci.song.5000.json','["人间天上。", "端楼龙凤灯先赏。", "倾城粉黛月明中，春思荡。", "醉金瓯仙酿。", "一从鸾辂北向。", "旧时宝座应蛛网。", "游人此际客江乡，空怅望。", "梦连昌清唱。"]'),
('song-ci-456','南歌子','万俟咏','宋','宋词','song-ci','南歌子','[]','梅夏暗丝雨，麦秋扇浪风。',31,'宋词/ci.song.5000.json','["梅夏暗丝雨，麦秋扇浪风。", "香芦结黍趁天中。", "五日凄凉今古、与谁同。"]'),
('song-ci-457','明月照高楼慢・明月照高楼','万俟咏','宋','宋词','song-ci','明月照高楼慢・明月照高楼','[]','平分素商。',123,'宋词/ci.song.5000.json','["平分素商。", "四垂翠幕，斜界银潢。", "颢气通建章。", "正烟澄练色，露洗水光。", "明映波融太液，影随帘挂披香。", "楼观壮丽，附霁云、耀绀碧相望。", "宫妆。", "三千从赭黄。", "万年世代，一部笙簧。", "夜宴花漏长。", "乍莺歌断续，燕舞回翔。", "玉座频燃绛蜡，素娥重按霓裳。", "还是共唱御制词，送御觞。"]'),
('song-ci-458','失调名','万俟咏','宋','宋词','song-ci','失调名','[]','昔年曾共黄花酒，一笑新香。',13,'宋词/ci.song.5000.json','["昔年曾共黄花酒，一笑新香。"]'),
('song-ci-459','尉迟杯慢・尉迟杯','万俟咏','宋','宋词','song-ci','尉迟杯慢・尉迟杯','[]','碎云薄。',126,'宋词/ci.song.5000.json','["碎云薄。", "向碧玉枝缀万萼。", "如将汞粉匀开，疑使柏麝熏却。", "雪魄未应若。", "况天赋、标艳仍绰约。", "当暄风暖日佳处，戏蝶游蜂看著。", "重重绣帘珠箔。", "障秾艳霏霏，异香漠漠。", "见说徐妃，当年嫁了，信任玉钿零落。", "无言自啼露萧索。", "夜深待、月上栏干角。", "广寒宫、要与姮娥，素妆一夜相学。"]'),
('song-ci-460','钿带长中腔','万俟咏','宋','宋词','song-ci','钿带长中腔','[]','簇真香。',77,'宋词/ci.song.5000.json','["簇真香。", "似风前拆麝囊。", "嫩紫轻红，间斗异芳。", "风流富贵，自觉兰蕙荒。", "独占蕊珠春光。", "绣结流苏密织，魂梦悠扬。", "气融液散满洞房。", "朝寒料峭，殢娇不易当。", "著意要得韩郎。"]'),
('song-ci-461','春草碧・番枪子','万俟咏','宋','宋词','song-ci','春草碧・番枪子','[]','又随芳绪生，看翠霁连空，愁遍征路。',122,'宋词/ci.song.5000.json','["又随芳绪生，看翠霁连空，愁遍征路。", "东风里，谁望断西塞，恨迷南浦。", "天涯地角，意不尽、消沈万古。", "曾是送别长亭下，细绿暗烟雨。", "何处。", "乱红铺绣茵，有醉眠荡子，拾翠游女。", "王孙远，柳外共残照，断云无语。", "池塘梦生，谢公后、还能继否。", "独上画楼，春山暝、雁飞去。"]'),
('song-ci-462','三台','万俟咏','宋','宋词','song-ci','三台','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','见梨花初带夜月，海棠半含朝雨。',213,'宋词/ci.song.5000.json','["见梨花初带夜月，海棠半含朝雨。", "内苑春、不禁过青门，御沟涨、潜通南浦。", "东风静、细柳垂金缕。", "望凤阙、非烟非雾。", "好时代、朝野多欢，遍九陌、太平箫鼓。", "乍莺儿百啭断续，燕子飞来飞去。", "近绿水、台榭映秋千，斗草聚、双双游女。", "饧香更、酒冷踏青路。", "会暗识、夭桃朱户。", "向晚骤、宝马雕鞍，醉襟惹、乱花飞絮。", "正轻寒轻暖漏永，半阴半晴云暮。", "禁火天、已是试新妆，岁华到、三分佳处。", "清明看、汉宫传蜡炬。", "散翠烟、飞入槐府。", "敛兵卫、阊阖门开，住传宣、又还休务。"]'),
('song-ci-463','恋芳春慢','万俟咏','宋','宋词','song-ci','恋芳春慢','[]','蜂蕊分香，燕泥破润，暂寒天气清新。',125,'宋词/ci.song.5000.json','["蜂蕊分香，燕泥破润，暂寒天气清新。", "帝里繁华，昨夜细雨初匀。", "万品花藏四苑，望一带、柳接重津。", "寒食近，蹴踘秋千，又是无限游人。", "红妆趁戏，绮罗夹道，青帘卖酒，台榭侵云。", "处处笙歌，不负治世良辰。", "共见西城路好，翠华定、将出岩宸。", "谁知道，仁主祈祥为民，非事行春。"]'),
('song-ci-464','安平乐慢','万俟咏','宋','宋词','song-ci','安平乐慢','[]','瑞日初迟，绪风乍暖，千花百草争香。',125,'宋词/ci.song.5000.json','["瑞日初迟，绪风乍暖，千花百草争香。", "瑶池路稳，阆苑春深，云树水殿相望。", "柳曲沙平，看尘随青盖，絮惹红妆。", "卖酒绿阴傍。", "无人不醉春光。", "有十里笙歌，万家罗绮，身世疑在仙乡。", "行乐知无禁，五侯半隐少年场。", "舞妙歌妍，空妒得、莺娇燕忙。", "念芳菲、都来几日，不堪风雨疏狂。"]'),
('song-ci-465','卓牌儿・卓牌子','万俟咏','宋','宋词','song-ci','卓牌儿・卓牌子','[]','东风绿杨天，如画出、清明院宇。',121,'宋词/ci.song.5000.json','["东风绿杨天，如画出、清明院宇。", "玉艳淡泊，梨花带月，胭脂零落，海棠经雨。", "单衣怯黄昏，人正在、珠帘笑语。", "相并戏蹴秋千，共携手、同倚栏干，暗香时度。", "翠窗绣户。", "路缭绕、潜通幽处。", "断魂凝伫。", "嗟不似飞絮。", "闲闷闲愁，难消遣、此日年年意绪。", "无据。", "奈酒醒春去。"]'),
('song-ci-466','昭君怨','万俟咏','宋','宋词','song-ci','昭君怨','[]','春到南楼雪尽。',47,'宋词/ci.song.5000.json','["春到南楼雪尽。", "惊动灯期花信。", "小雨一番寒。", "倚阑干。", "莫把阑干倚。", "一望几重烟水。", "何处是京华。", "暮云遮。"]'),
('song-ci-467','昭君怨','万俟咏','宋','宋词','song-ci','昭君怨','[]','一望西山烟雨。',47,'宋词/ci.song.5000.json','["一望西山烟雨。", "目断心飞何处。", "天外白云城。", "几多程。", "谩记阳关句。", "衣上粉啼痕污。", "陇水一分流。", "此生休。"]'),
('song-ci-468','诉衷情','万俟咏','宋','宋词','song-ci','诉衷情','[]','一鞭清晓喜还家。',54,'宋词/ci.song.5000.json','["一鞭清晓喜还家。", "宿醉困流霞。", "夜来小雨新霁，双燕舞风斜。", "山不尽，水无涯。", "望中赊。", "送春滋味，念远情怀，分付杨花。"]'),
('song-ci-469','梅花引','万俟咏','宋','宋词','song-ci','梅花引','[]','晓风酸。',70,'宋词/ci.song.5000.json','["晓风酸。", "晓霜乾。", "一雁南飞人度关。", "客衣单。", "客衣单。", "千里断魂，空歌行路难。", "寒梅惊破前村雪。", "寒鸡啼破西楼月。", "酒肠宽。", "酒肠宽。", "家在日边，不堪频倚阑。"]'),
('song-ci-470','忆秦娥','万俟咏','宋','宋词','song-ci','忆秦娥','[]','千里草。',56,'宋词/ci.song.5000.json','["千里草。", "萋萋尽处遥山小。", "遥山小。", "行有远似，此山多少。", "天若有情天亦老。", "此情说便说不了。", "说不了。", "一声唤起，又惊春晓。"]'),
('song-ci-471','忆少年','万俟咏','宋','宋词','song-ci','忆少年','[]','陇云溶泄，陇山峻秀，陇泉呜咽。',58,'宋词/ci.song.5000.json','["陇云溶泄，陇山峻秀，陇泉呜咽。", "行人暂驻马，已不胜愁绝。", "上陇首、凝眸天四阔。", "更一声、塞雁凄切。", "征书待寄远，有知心明月。"]'),
('song-ci-472','长相思','万俟咏','宋','宋词','song-ci','长相思','[]','一声声。',44,'宋词/ci.song.5000.json','["一声声。", "一更更。", "窗外芭蕉窗里灯。", "此时无限情。", "梦难成。", "恨难平。", "不道愁人不喜听。", "空阶滴到明。"]'),
('song-ci-473','长相思','万俟咏','宋','宋词','song-ci','长相思','[]','短长亭。',44,'宋词/ci.song.5000.json','["短长亭。", "古今情。", "楼外凉蟾一晕生。", "雨馀秋更清。", "暮云平。", "暮山横。", "几叶秋声和雁声。", "行人不要听。"]'),
('song-ci-474','木兰花慢','万俟咏','宋','宋词','song-ci','木兰花慢','[]','恨莺花渐老，但芳草、绿汀洲。',124,'宋词/ci.song.5000.json','["恨莺花渐老，但芳草、绿汀洲。", "纵岫壁千寻，榆钱万叠，难买春留。", "梅花向来始别，又匆匆，结子满枝头。", "门外垂杨岸侧，画桥谁系兰舟。", "悠悠。", "岁月如流。", "叹水覆、杳难收。", "凭画阑，往往抬头举眼，都是春愁。", "东风晚来更恶，怕飞红、拍絮入书楼。", "双燕归来问我，怎生不上帘钩。"]'),
('song-ci-475','武陵春','万俟咏','宋','宋词','song-ci','武陵春','[]','燕子飞来花在否，微雨退、掩重门。',66,'宋词/ci.song.5000.json','["燕子飞来花在否，微雨退、掩重门。", "正满院梨花雪照人。", "独自个、怯黄昏。", "轻风淡月总消魂。", "罗衣暗惹啼痕。", "谩觑著、秋千腰褪裙。", "可㬠是、不宜春。"]'),
('song-ci-476','快活年近拍','万俟咏','宋','宋词','song-ci','快活年近拍','[]','千秋万岁君，五帝三王世。',94,'宋词/ci.song.5000.json','["千秋万岁君，五帝三王世。", "观风重令节，与民乐盛际。", "蕊宫长春，洞天不老，花艳蝉辉，十里照春珠翠。", "闹罗绮。", "遥望太极，一簇通明里。", "钧台奏寿，蓬山呈妙戏。", "六宫人来，五云楼迥，风送歌声，依约睿思圣制。"]'),
('song-ci-477','醉蓬莱','万俟咏','宋','宋词','song-ci','醉蓬莱','[]','正波泛银汉，漏滴铜壶，上元佳致。',120,'宋词/ci.song.5000.json','["正波泛银汉，漏滴铜壶，上元佳致。", "绛烛银灯，若繁星连缀。", "明月逐人，暗尘随马，尽五陵豪贵。", "鬓惹乌云，裙拖湘水，谁家姝丽。", "金阙南边，彩山北面，接地罗绮，沸天歌吹。", "六曲屏开，拥三千珠翠。", "帝乐□深，凤炉烟喷，望舜颜瞻礼。", "太平无事，君臣宴乐，黎民欢醉。"]'),
('song-ci-478','芰荷香','万俟咏','宋','宋词','song-ci','芰荷香','[]','小潇湘。',120,'宋词/ci.song.5000.json','["小潇湘。", "正天影倒碧，波面容光。", "水仙朝罢，间列绿盖红幢。", "吹风细雨，荡十顷、浥浥清香。", "人在水精中央。", "霜绡雾縠，襟袂收凉。", "款放轻舟闹红里，有晴蜓点水，交颈鸳鸯。", "翠阴密处，曾觅相并青房。", "晚霞散绮，泛远净、一叶鸣榔。", "拟去尽促雕觞。", "歌云未断，月上飞梁。"]'),
('song-ci-479','别瑶姬慢・忆瑶姬','万俟咏','宋','宋词','song-ci','别瑶姬慢・忆瑶姬','[]','可惜香红。',128,'宋词/ci.song.5000.json','["可惜香红。", "又一番骤雨，几阵狂风。", "霎时留不往，便夜来和月，飞过帘栊。", "离愁未了，酒病相仍，便堪此恨中。", "片片随、流水斜阳去，各自西东。", "又还是、九十春光，误双飞蝶，并采游峰。", "人生能几许，细算来何物，得似情浓。", "沈腰暗减，潘鬓先秋，寸心不易供。", "望暮云、千里沈沈障翠峰。"]'),
('song-ci-480','忆秦娥','万俟咏','宋','宋词','song-ci','忆秦娥','[]','天如洗。',56,'宋词/ci.song.5000.json','["天如洗。", "金波冷浸冰壶里。", "冰壶里。", "一年得似，此宵能几。", "等闲莫把栏干倚。", "马蹄去便三千里。", "三千里。", "几重云岫，几重烟水。"]'),
('song-ci-481','南柯子・南歌子','田为','宋','宋词','song-ci','南柯子・南歌子','[]','梦怕愁时断，春从醉里回。',62,'宋词/ci.song.5000.json','["梦怕愁时断，春从醉里回。", "凄凉怀抱向谁开。", "些子清明时候、被莺催。", "柳外都成絮，栏边半是苔。", "多情帘燕独徘徊。", "依旧满身花雨、又归来。"]'),
('song-ci-482','南柯子・南歌子','田为','宋','宋词','song-ci','南柯子・南歌子','[]','团玉梅梢重，香罗芰扇低。',62,'宋词/ci.song.5000.json','["团玉梅梢重，香罗芰扇低。", "帘风不动蝶交飞。", "一样绿阴庭院、锁斜晖。", "对月怀歌扇，因风念舞衣。", "何须惆怅惜芳菲。", "┾却一年憔悴、待春归。"]'),
('song-ci-483','念奴娇','田为','宋','宋词','song-ci','念奴娇','[]','嫩冰未白，被霜风换却，满院秋色。',120,'宋词/ci.song.5000.json','["嫩冰未白，被霜风换却，满院秋色。", "小阁深沈围坐促，初拥红炉宜窄。", "帘密收香，窗明迟夜，砚冷凝新滴。", "无人知道，个中多少岑寂。", "翻念一枕高唐，当年仙梦觉，难寻消息。", "睡起微醒衣袖重，不管腰支犹索。", "旋暖银簧，时添酥字，笋玉寒无力。", "如今肠断，暮云依旧凝碧。"]'),
('song-ci-484','探春・探春慢','田为','宋','宋词','song-ci','探春・探春慢','[]','小雨分山，断云镂日，丹青难状清晓。',122,'宋词/ci.song.5000.json','["小雨分山，断云镂日，丹青难状清晓。", "柳眼窥晴，梅妆迎暖，林外幽禽啼早。", "烟径润如酥，正浓淡遥看堤草。", "望中新景无穷，最是一年春好。", "骄马黄金络脑。", "争探得东君，何处先到。", "万盏飞觞，千金倚玉，不肯轻辜年少。", "桃李怯残寒，半吐芳心犹小。", "谩教蜂蝶多情，未应知道。"]'),
('song-ci-485','惜黄花慢','田为','宋','宋词','song-ci','惜黄花慢','[]','雁空浮碧，印晓月，露洗重阳天气。',131,'宋词/ci.song.5000.json','["雁空浮碧，印晓月，露洗重阳天气。", "望极楼外，淡烟半隔疏林，掩映断桥流水。", "黄金篱畔白衣人，更谁会、渊明深意。", "晚风底。", "落日乱鸿，飞起无际。", "情多对景凄凉，念旧赏，步屐登高迢递。", "兴满东山，共携素手持杯，劝泛玉浆云蕊。", "此时霜鬓欲归心，谩老尽、悲秋情味。", "向醉里。", "免得又成憔悴。"]'),
('song-ci-486','江神子慢・江城子慢','田为','宋','宋词','song-ci','江神子慢・江城子慢','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','玉台挂秋月。',134,'宋词/ci.song.5000.json','["玉台挂秋月。", "铅素浅，梅花傅香雪。", "冰姿洁。", "金莲衬、小小凌波罗袜。", "雨初歇。", "楼外孤鸿声渐远，远山外、行人音信绝。", "此恨对语犹难，那堪更寄书说。", "教人红销翠减，觉衣宽金缕，都为轻别。", "太情切。", "消魂处、画角黄昏时节。", "声呜咽。", "落尽庭花春去也，银蟾迥、无情圆又缺。", "恨伊不似馀香，惹鸳鸯结。"]'),
('song-ci-487','转调二郎神・二郎神','徐伸','宋','宋词','song-ci','转调二郎神・二郎神','[]','闷来弹雀，又搅破、一帘花影。',129,'宋词/ci.song.5000.json','["闷来弹雀，又搅破、一帘花影。", "谩试著春衫，还思纤手，熏彻金炉烬冷。", "动是愁多如何向，但怪得、新来多病。", "想旧日沈腰，而今潘鬓，不堪临镜。", "重省。", "别时泪滴，罗衣犹凝。", "料为我厌厌，日高慵起，长托春酲未醒。", "雁翼不来，马蹄轻驻，门闭一庭芳景。", "空伫立，尽日阑干倚遍，昼长人静。"]'),
('song-ci-488','喜迁莺','江汉','宋','宋词','song-ci','喜迁莺','[]','升平无际。',126,'宋词/ci.song.5000.json','["升平无际。", "庆八载相业，君臣鱼水。", "镇抚风稜，调燮精神，合是圣朝房魏。", "凤山政好，还被画毂朱轮催起。", "按锦辔。", "映玉带金鱼，都人争指。", "丹陛。", "常注意。", "追念裕陵，元佐今无几。", "绣衮香浓，鼎槐风细。", "荣耀满门朱紫。", "四方具瞻师表，尽道一夔足矣。", "运花笔，又管领年年，烘春桃李。"]'),
('song-ci-489','失调名','田中行','宋','宋词','song-ci','失调名','[]','为谁和泪倚阑干。',8,'宋词/ci.song.5000.json','["为谁和泪倚阑干。"]'),
('song-ci-490','风入松','田中行','宋','宋词','song-ci','风入松','[]','一宵风雨送春归。',86,'宋词/ci.song.5000.json','["一宵风雨送春归。", "绿暗红稀。", "画楼尽日凭阑意，与谁同拈花枝。", "门外蔷薇开也，枝头梅子酸时。", "玉人应是数归期。", "翠敛愁眉。", "塞鸿不到双鱼远，恨楼前、流水难西。", "新恨欲题红叶，东风满院花飞。"]'),
('song-ci-491','喜迁莺','赵温之','宋','宋词','song-ci','喜迁莺','[]','琼姿冰体。',127,'宋词/ci.song.5000.json','["琼姿冰体。", "料莹光乍傅，广寒宫里。", "北陆寒深，南园春先，此后万花方起。", "翦霞斗萼，栽芯砌□，天与高致。", "大潇洒，最宜雪宜月，宜亭宜水。", "好是。", "天涯庾岭上，万珠浮动香千里。", "幈写横斜，鬟插垂袅，占尽秀骨清意。", "醉魂易醒，吟兴信来，佳思无际。", "为传语，向东风，甘使无言桃李。"]'),
('song-ci-492','踏青游','赵温之','宋','宋词','song-ci','踏青游','[]','竹外溪边，一枝破寒冲腊。',104,'宋词/ci.song.5000.json','["竹外溪边，一枝破寒冲腊。", "莹素肌、玉雕冰刻。", "赋闲标，足馀韵，岂同常格。", "最风流，生来处处尽好，别得造化工力。", "疏影幽香，意思迥然殊绝。", "算不枉、诗人分别。", "冻云深，凉月皎，愈增清冽。", "大潇洒，尤得静中雅趣，不许莺栖燕歇。"]'),
('song-ci-493','踏莎行','赵温之','宋','宋词','song-ci','踏莎行','[]','妖艳相偎，清香交喷。',68,'宋词/ci.song.5000.json','["妖艳相偎，清香交喷。", "花王尤喜来亲迎。", "有如二女事唐虞，群芳休更夸相并。", "小雨资娇，轻风借润。", "天应知我怜孤韵。", "莫惊岁岁有双葩，仪真自古风流郡。"]'),
('song-ci-494','谒金门','王庭珪','宋','宋词','song-ci','谒金门','[]','溪风紧。',53,'宋词/ci.song.5000.json','["溪风紧。", "溪上官梅整整。", "万木寒痴吹不醒。", "一枝先破冷。", "梦断香云耿耿。", "月淡梨花清影。", "长笛倚楼谁共听。", "调高成绝品。"]'),
('song-ci-495','凤栖梧・蝶恋花','王庭珪','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','琼海无边银浪卷。',70,'宋词/ci.song.5000.json','["琼海无边银浪卷。", "画戟朱楼，缥缈云间见。", "当日使君曾拥传。", "海霞光里时开宴。", "翠斝红鳞吹酒面。", "莫谓今朝，人在天涯远。", "彩凤衔书应不晚。", "愿公难老身长健。"]'),
('song-ci-496','醉桃源・阮郎归','王庭珪','宋','宋词','song-ci','醉桃源・阮郎归','[]','朱门映柳画帘垂。',56,'宋词/ci.song.5000.json','["朱门映柳画帘垂。", "门前闻马嘶。", "主人新著绿袍归。", "天恩下玉墀。", "凭翠袖，拈花枝。", "劝教人醉时。", "请君听唱碧云词。", "倒倾金屈卮。"]'),
('song-ci-497','临江仙','王庭珪','宋','宋词','song-ci','临江仙','[]','家住天门阊阖外，别来几度花开。',70,'宋词/ci.song.5000.json','["家住天门阊阖外，别来几度花开。", "近传消息到江淮。", "玉京知好在，金阙尚崔嵬。", "流落江南山尽处，雨馀苍翠成堆。", "暂同溪馆醉尊罍。", "恐随丹诏动，且任玉山颓。"]'),
('song-ci-498','临江仙','王庭珪','宋','宋词','song-ci','临江仙','[]','问道春来相识否，岭头昨夜开花。',70,'宋词/ci.song.5000.json','["问道春来相识否，岭头昨夜开花。", "水村烟坞寄生涯。", "月寒疏影淡，整整复斜斜。", "素面玉妃嫌粉污，晨妆洗尽铅华。", "香肌应只饭胡麻。", "年年如许瘦，知是阿谁家。"]'),
('song-ci-499','临江仙','王庭珪','宋','宋词','song-ci','临江仙','[]','寂寞久无红袖饮，忽逢浩齿轻讴。',70,'宋词/ci.song.5000.json','["寂寞久无红袖饮，忽逢浩齿轻讴。", "坐令孤客洗穷愁。", "谁知沅水上，却似洛城游。", "闻道辰溪贤令长，深房别锁明眸。", "多年铅鼎养青虬。", "不应携妓女，骑鹤上扬州。"]'),
('song-ci-500','临江仙','王庭珪','宋','宋词','song-ci','临江仙','[]','帘外东风吹断梦，卷帘人探春还。',70,'宋词/ci.song.5000.json','["帘外东风吹断梦，卷帘人探春还。", "一枝疏影动檐间。", "鸳鸯□瓦冷，霜月堕栏干。", "闻道寿阳如许好，晨妆洗尽微殷。", "可怜玉骨瘦孱孱。", "谁家长笛□，吹彻玉楼寒。"]'),
('song-ci-501','人娇','王庭珪','宋','宋词','song-ci','人娇','[]','小院桃花，烟锁几重珠箔。',83,'宋词/ci.song.5000.json','["小院桃花，烟锁几重珠箔。", "更深后、海棠睡著。", "东风吹去，落谁家墙角。", "平白地教人，为他情恶。", "花若有情，情应不薄。", "也须悔从前事错。", "而今夜雨，念玉颜飘泊。", "知那里人家，怎生顿著。"]'),
('song-ci-502','忆秦娥','王庭珪','宋','宋词','song-ci','忆秦娥','[]','梅花发。',56,'宋词/ci.song.5000.json','["梅花发。", "夜寒吹笛千山月。", "千山月。", "此时愁听，龙吟幽噎。", "数枝飞尽南枝雪。", "风光又作年时别。", "年时别。", "江头心绪，乱丝千结。"]'),
('song-ci-503','念奴娇','王庭珪','宋','宋词','song-ci','念奴娇','[]','少年时节，见皇州灯火，衣冠朝市。',120,'宋词/ci.song.5000.json','["少年时节，见皇州灯火，衣冠朝市。", "天汉桥边瞻凤辇，帘幕千家垂地。", "人似神仙，身游佛国，谪堕红尘里。", "如今憔悴，渐无往岁欢味。", "此夜帝里喧传，太平祥瑞，有街头人醉。", "更值端门新又起，楼阙千兵严卫。", "朝野多欢，边庭初静，歌舞方腾沸。", "良宵好景，异时多少遗事。"]'),
('song-ci-504','点绛唇','王庭珪','宋','宋词','song-ci','点绛唇','[]','花外红楼，当时青鬓颜如玉。',50,'宋词/ci.song.5000.json','["花外红楼，当时青鬓颜如玉。", "淡烟残烛。", "醉入花间宿。", "白发相逢，犹唱当时曲。", "当时曲。", "断弦难续。", "且尽杯中醁。"]'),
('song-ci-505','点绛唇','王庭珪','宋','宋词','song-ci','点绛唇','[]','玉漏春迟，铁关金锁星桥夜。',50,'宋词/ci.song.5000.json','["玉漏春迟，铁关金锁星桥夜。", "暗尘随马。", "明月应无价。", "天半朱楼，银汉星光射。", "更深也。", "翠娥如画。", "犹在凉蟾下。"]'),
('song-ci-506','点绛唇','王庭珪','宋','宋词','song-ci','点绛唇','[]','春入西园，数重花外红楼起。',50,'宋词/ci.song.5000.json','["春入西园，数重花外红楼起。", "倚阑金翠。", "人在非烟里。", "风月佳时，蓬岛开平地。", "笙歌沸。", "画桥灯市。", "一夜惊桃李。"]'),
('song-ci-507','西江月','王庭珪','宋','宋词','song-ci','西江月','[]','一拂退黄衫子，几团嗅芯蜂儿。',58,'宋词/ci.song.5000.json','["一拂退黄衫子，几团嗅芯蜂儿。", "西风吹下月中枝。", "种在寒岩影里。", "人道蜡梅相似，又传菊满东篱。", "饶伊颜色入时宜。", "安得香传九里。"]'),
('song-ci-508','江城子','王庭珪','宋','宋词','song-ci','江城子','[]','锦袍绣帽跃金鞍。',86,'宋词/ci.song.5000.json','["锦袍绣帽跃金鞍。", "卷旗幡。", "整师还。", "轻骑穷追，湘尾鼓声寒。", "千里尘清高会处，张翠幕，万人看。", "藕丝衫袖捧雕盘。", "玉颓山。", "夜将阑。", "幸遇休兵，且尽玉壶宽。", "未用汉军频出塞，徒生事，斩楼兰。"]'),
('song-ci-509','江城子','王庭珪','宋','宋词','song-ci','江城子','[]','渡头犹唱棹歌声。',86,'宋词/ci.song.5000.json','["渡头犹唱棹歌声。", "雨初晴。", "月初生。", "忽见飞虹，夭矫挂寒汀。", "两岸小儿齐拍手，今夜里，放人行。", "朱栏画鹢照江亭。", "客来登。", "眼初明。", "如泛银河，天上跨长鲸。", "君是济川舟楫手，将许事，笑谈成。"]'),
('song-ci-510','江城子','王庭珪','宋','宋词','song-ci','江城子','[]','夜郎江上看元宵。',86,'宋词/ci.song.5000.json','["夜郎江上看元宵。", "斗回杓。", "雪初消。", "灯火银花，何处是星桥。", "哄得满城春不夜，三妓女，五溪徭。", "此时回首忆行朝。", "太平楼。", "倚层宵。", "红蜡光中，买酒听吹箫。", "且就天涯聊一醉，歌一曲，望京谣。"]'),
('song-ci-511','江城子','王庭珪','宋','宋词','song-ci','江城子','[]','天回北斗欲中宵。',86,'宋词/ci.song.5000.json','["天回北斗欲中宵。", "屡移杓。", "客魂消。", "记得皇州，灯火虹成桥。", "异俗西南开万里，冠带尽，百蛮徭。", "卢溪太守未还朝。", "起朱楼。", "接丛宵。", "翠幕红妆，歌管玉为箫。", "民乐丰登无一事，看下诏，采风谣。"]'),
('song-ci-512','江城子','王庭珪','宋','宋词','song-ci','江城子','[]','楼头钟鼓变新声。',86,'宋词/ci.song.5000.json','["楼头钟鼓变新声。", "晚霞晴。", "水云生。", "何处归帆，争泊蓼花汀。", "遥望虹桥如画里，鳌背上，著人行。", "夜阑风定见危亭。", "却重登。", "景方明。", "影落波心，疑是海中鲸。", "愿借吸川沧海量，为公寿，落桥成。"]'),
('song-ci-513','蝶恋花','王庭珪','宋','宋词','song-ci','蝶恋花','[]','月落灯残人散后。',70,'宋词/ci.song.5000.json','["月落灯残人散后。", "忽到尊前，但觉眉儿皱。", "数日不来如许瘦。", "裙腰减尽君知否。", "公子风流应自有。", "占断春光，肯落谁人手。", "已是许多时做就。", "重教舞彻双罗袖。"]'),
('song-ci-514','蝶恋花','王庭珪','宋','宋词','song-ci','蝶恋花','[]','罨画楼中人已醉。',70,'宋词/ci.song.5000.json','["罨画楼中人已醉。", "别院微闻，笑语帘垂地。", "催唤倾城香雾起。", "翠帷双卷春风里。", "妆样尖新歌妙丽。", "满酌金尊，不信人憔悴。", "饥客眼寒谁管你。", "主人见惯浑闲事。"]'),
('song-ci-515','蝶恋花','王庭珪','宋','宋词','song-ci','蝶恋花','[]','桂树新生都几许。',70,'宋词/ci.song.5000.json','["桂树新生都几许。", "兄弟骑龙，双入蟾宫去。", "一日两枝同折处。", "姮娥拍手都分与。", "杨柳江头春色暮。", "白马青衫，两郡文章主。", "只恐远方难久住。", "高宗梦觉思霖雨。"]'),
('song-ci-516','满庭芳','王庭珪','宋','宋词','song-ci','满庭芳','[]','颓玉成山，倾江作酒，醉来莫问升沈。',118,'宋词/ci.song.5000.json','["颓玉成山，倾江作酒，醉来莫问升沈。", "少年狂怪，应笑老婆心。", "也会东涂西抹，行穿过、柳陌花阴。", "诚何用，腰龟左顾，犹待铸黄金。", "如今。", "回首处，青楼缥缈，朱箔重深。", "叹江海飘零，离恨难禁。", "好在铜梁玉垒，将军骑、他日重临。", "归来看，文君未老，相对抚鸣琴。"]'),
('song-ci-517','满庭芳','王庭珪','宋','宋词','song-ci','满庭芳','[]','宿雨初收，晚风微度，万家帘卷青烟。',118,'宋词/ci.song.5000.json','["宿雨初收，晚风微度，万家帘卷青烟。", "暗尘随马，人物似神仙。", "试问天公借月，天须放、明月教圆。", "应移下，广寒宫殿，灯火接星躔。", "卢川。", "元古郡，当时太守，宾从俱贤。", "到如今井邑，歌吹喧阗。", "花下红妆卖酒，时相遇、曲水桥边。", "谁知道，山城父老，重见中兴年。"]'),
('song-ci-518','满庭芳','王庭珪','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','东阁官梅，玉栏朱槛，未如山馆疏篱。',118,'宋词/ci.song.5000.json','["东阁官梅，玉栏朱槛，未如山馆疏篱。", "水边竹外，斜出两三枝。", "最好西湖月下，林处士、著意吟时。", "何须说，扬州旧日，何逊更能诗。", "谁知。", "深雪里，玉妃粲粲，初下瑶池。", "笑人间春色，只在桃蹊。", "紫燕黄鹂解语，来时但、青实离离。", "争知道，调羹附鼎，终得近丹墀。"]'),
('song-ci-519','柳梢青','王庭珪','宋','宋词','song-ci','柳梢青','[]','兰亭丝竹。',61,'宋词/ci.song.5000.json','["兰亭丝竹。", "高会群贤，其人如玉。", "曲水流觞，灯前细雨，檐花蔌蔌。", "舞雩初试春衣，听咏歌、童子五六。", "泽畔行吟，沙汀拾翠，满江新绿。"]'),
('song-ci-520','菩萨蛮','王庭珪','宋','宋词','song-ci','菩萨蛮','[]','武陵西上沅陵渡。',52,'宋词/ci.song.5000.json','["武陵西上沅陵渡。", "扁舟忘了来时路。", "花外有人烟。", "相逢疑是仙。", "清尊留夜语。", "醉倒知何处。", "归去客心惊。", "金鸡嘲哳鸣。"]'),
('song-ci-521','浣溪沙','王庭珪','宋','宋词','song-ci','浣溪沙','[]','薄薄春衫簇绮霞。',48,'宋词/ci.song.5000.json','["薄薄春衫簇绮霞。", "画檐晨起见栖鸦。", "宿妆仍拾落梅花。", "回首高楼闻笑语，倚栏红袖卷轻纱。", "玉肌微减旧时些。"]'),
('song-ci-522','浣溪沙','王庭珪','宋','宋词','song-ci','浣溪沙','[]','九里香风动地来。',48,'宋词/ci.song.5000.json','["九里香风动地来。", "寻香空绕百千回。", "错惊秋色上崔嵬。", "谁识芗林三昧手，能令花落又花开。", "返魂元学岭头梅。"]'),
('song-ci-523','虞美人','王庭珪','宋','宋词','song-ci','虞美人','[]','城东楼阁连云起。',66,'宋词/ci.song.5000.json','["城东楼阁连云起。", "冠绝辰州市。", "莲灯初发万枝红。", "也似江南风景、半天中。", "花衢柳陌年时静。", "划地今年盛。", "棚前箫鼓闹如雷。", "添个辰溪女子、舞三台。"]'),
('song-ci-524','桃源忆故人','王庭珪','宋','宋词','song-ci','桃源忆故人','[]','催花一霎清明雨。',56,'宋词/ci.song.5000.json','["催花一霎清明雨。", "留得东风且住。", "两岸柳汀烟坞。", "未放行人去。", "人如双鹄云间举。", "明夜扁舟何处。", "只向武陵南渡。", "便是长安路。"]'),
('song-ci-525','醉花阴','王庭珪','宋','宋词','song-ci','醉花阴','[]','红尘紫阳春来早。',62,'宋词/ci.song.5000.json','["红尘紫阳春来早。", "晚市烟光好。", "灯发万枝莲，华月光中，天净开蓬岛。", "老人旧日曾年少。", "年少还须老。", "今夕在天涯，烛影星桥，也似长安道。"]'),
('song-ci-526','醉花阴','王庭珪','宋','宋词','song-ci','醉花阴','[]','玉妃谪堕烟村远。',62,'宋词/ci.song.5000.json','["玉妃谪堕烟村远。", "犹似瑶池见。", "缺月挂寒梢，时有幽香，飞到朱帘畔。", "春风岭上淮南岸。", "曾为谁魂断。", "依旧瘦稜稜，天若有情，天也应须管。"]'),
('song-ci-527','醉花阴','王庭珪','宋','宋词','song-ci','醉花阴','[]','月娥昨夜江头过。',62,'宋词/ci.song.5000.json','["月娥昨夜江头过。", "把素衫揉破。", "冷逐晓云归，留与东风，吹作千千朵。", "云残香瘦春犹可。", "玉笛愁无那。", "倚著画楼人，且莫教他，吹动些儿个。"]'),
('song-ci-528','雨霖铃','王庭珪','宋','宋词','song-ci','雨霖铃','["\u897f\u6e56"]','琼楼玉宇。',123,'宋词/ci.song.5000.json','["琼楼玉宇。", "满人寰似、海边洲渚。", "蓬莱又还水浅，鲸涛静见，银宫如许。", "紫极鸣筲声断，望霓舟何处。", "待夜深、重倚层霄，认得瑶池广寒路。", "郢中旧曲谁能度。", "恨歌声、响入青云去。", "西湖近时绝唱，总不道、月梅盐絮。", "暗想当年宾从，毫端有惊人句。", "谩说枚叟邹生，共作梁园赋。"]'),
('song-ci-529','鹊桥仙','王庭珪','宋','宋词','song-ci','鹊桥仙','[]','云静天高，山明水阔。',68,'宋词/ci.song.5000.json','["云静天高，山明水阔。", "一年待个中秋月。", "十分魄少一分圆，今宵已觉蟾光别。", "且尽金尊，遥瞻玉阙。", "更深江水沙如雪。", "来宵风雨不相关，重须买酒追佳节。"]'),
('song-ci-530','感皇恩','王庭珪','宋','宋词','song-ci','感皇恩','[]','飞雪满貂裘，马蹄轻骤。',81,'宋词/ci.song.5000.json','["飞雪满貂裘，马蹄轻骤。", "笔下文章焕星斗。", "凌云才调，尽是夺标高手。", "况闻场屋里，知名久。", "金榜篆云，银鞍披绣。", "归去天香满衣袖。", "莫辞今夕，且尽一尊芳酒。", "为君歌一曲，为君寿。"]'),
('song-ci-531','感皇恩','王庭珪','宋','宋词','song-ci','感皇恩','[]','羸马怯征鞍，骎骎欲骤。',81,'宋词/ci.song.5000.json','["羸马怯征鞍，骎骎欲骤。", "昨夜文星动南斗。", "广寒宫近，欲上烟霄携手。", "素娥不奈冷，凄凉久。", "知是谪仙，肝肠锦绣。", "天半清风动襟袖。", "而今西笑，且饮新丰美酒。", "悠然还独酌，谁为寿。"]'),
('song-ci-532','感皇恩','王庭珪','宋','宋词','song-ci','感皇恩','[]','一叶下西风，寒生南浦。',81,'宋词/ci.song.5000.json','["一叶下西风，寒生南浦。", "椎鼓鸣桡送君去。", "长亭把酒，却倩阿谁留住。", "尊前人似玉，能留否。", "醉中暂听，离歌几许。", "听不能终泪如雨。", "无情江水，断送扁舟何处。", "归时烟浪卷，朱帘暮。"]'),
('song-ci-533','寰海清','王庭珪','宋','宋词','song-ci','寰海清','[]','画鼓轰天。',107,'宋词/ci.song.5000.json','["画鼓轰天。", "暗尘随宝马，人似神仙。", "天恁不教昼短，明月长圆。", "天应未知道，天天。", "须肯放、三夜如年。", "流酥拥上香軿。", "为个甚、晚妆特地鲜妍。", "花下清阴乍合，曲水桥边。", "高人到此也乘兴，任横街，一一须穿。", "莫言无国艳，有朱门、锁婵娟。"]'),
('song-ci-534','浪淘沙','王庭珪','宋','宋词','song-ci','浪淘沙','[]','翠袖卷轻纱。',64,'宋词/ci.song.5000.json','["翠袖卷轻纱。", "玉腕慵遮。", "蕊珠宫殿倚彤霞。", "不愤江南梅信早，争下香车。", "月露洗凝华。", "艳压群葩。", "暗传春信到天涯。", "试问东风谁第一，先到人家。"]'),
('song-ci-535','好事近','王庭珪','宋','宋词','song-ci','好事近','[]','宴罢莫匆匆，聊驻玉鞍金勒。',53,'宋词/ci.song.5000.json','["宴罢莫匆匆，聊驻玉鞍金勒。", "闻道建溪新焙，尽龙蟠苍璧。", "黄金碾入碧花瓯，瓯翻素涛色。", "今夜酒醒归去，觉风生两腋。"]'),
('song-ci-536','解佩令','王庭珪','宋','宋词','song-ci','解佩令','[]','湘江停瑟。',84,'宋词/ci.song.5000.json','["湘江停瑟。", "洛川回雪。", "是耶非、相逢飘瞥。", "云鬓风裳，照心事、娟娟山月。", "翦烟花、带萝同结。", "留环盟切。", "贻珠情彻。", "解携时、玉声愁绝。", "罗袜尘生，早波面、春痕欲灭。", "送人行、水声凄咽。"]'),
('song-ci-537','西江月','薛式','宋','宋词','song-ci','西江月','[]','一是金丹总数，河图象出真机。',58,'宋词/ci.song.5000.json','["一是金丹总数，河图象出真机。", "谁知罔象尽玄微。", "大道从兹孕起。", "斗柄璇玑正位，阴中却抱阳辉。", "昆仑子母著绯衣。", "此是乾坤真理。"]'),
('song-ci-538','西江月','薛式','宋','宋词','song-ci','西江月','[]','偃月炉中金鼎，三台两曜行神。',58,'宋词/ci.song.5000.json','["偃月炉中金鼎，三台两曜行神。", "尊卑简易汞中真。", "握固休推心肾。", "白虎长存坎户，青龙却与南邻。", "阴魂阳魄似窗尘。", "大意不离玄牝。"]'),
('song-ci-539','西江月','薛式','宋','宋词','song-ci','西江月','[]','天上三清真境，三皇五帝规模。',58,'宋词/ci.song.5000.json','["天上三清真境，三皇五帝规模。", "瞿昙老氏仲尼徒。", "经史深藏妙素。", "间有真人出世，来明赤子玄珠。", "蟾光终日耀昏衢。", "满目黄芽显露。"]'),
('song-ci-540','西江月','薛式','宋','宋词','song-ci','西江月','[]','内有五行相制，包含一粒红铅。',58,'宋词/ci.song.5000.json','["内有五行相制，包含一粒红铅。", "相生相杀自天然。", "此药殊无贵贱。", "会向我家园里，栽培一亩天田。", "中男小女共相连。", "种得黄芽满院。"]'),
('song-ci-541','西江月','薛式','宋','宋词','song-ci','西江月','[]','凿破玄元三五，拨开造化圭璋。',58,'宋词/ci.song.5000.json','["凿破玄元三五，拨开造化圭璋。", "希夷妙旨在中央。", "咫尺无名罔象。", "片饷工夫便得，教君地久天长。", "蓬莱仙岛是吾乡。", "怎不留心信向。"]'),
('song-ci-542','西江月','薛式','宋','宋词','song-ci','西江月','[]','竹破须还竹补，人衰须假铅全。',58,'宋词/ci.song.5000.json','["竹破须还竹补，人衰须假铅全。", "思量只是眼睛前。", "自是时人不见。", "日月相交离坎，龙蛇产在先天。", "长生妙药在家园。", "一饷工夫便现。"]'),
('song-ci-543','西江月','薛式','宋','宋词','song-ci','西江月','[]','此道至灵至圣，无令泄漏轻为。',58,'宋词/ci.song.5000.json','["此道至灵至圣，无令泄漏轻为。", "全凭德行两相宜。", "言语须防避忌。", "要籍五行生旺，须明阳盛阴衰。", "三人同志谨防危。", "进火工夫仔细。"]'),
('song-ci-544','西江月','薛式','宋','宋词','song-ci','西江月','[]','炼就光明莹玉，回来却入黄泉。',58,'宋词/ci.song.5000.json','["炼就光明莹玉，回来却入黄泉。", "升腾须假至三年。", "携养殷勤眷恋。", "九九才终变化，神功岂假言宣。", "分明顷刻做神仙。", "永驾鸾车凤辇。"]'),
('song-ci-545','西江月','薛式','宋','宋词','song-ci','西江月','[]','一气初回遇朔，鼎中神水温温。',58,'宋词/ci.song.5000.json','["一气初回遇朔，鼎中神水温温。", "刚柔相会气均匀。", "妙在无过浑沌。", "八卦循回循绕，推排九窍追奔。", "东西沈静合朝昏。", "莫与常人议论。"]'),
('song-ci-546','临江仙','陈克','宋','宋词','song-ci','临江仙','[]','枕帐依依残梦，斋房忽忽馀酲。',66,'宋词/ci.song.5000.json','["枕帐依依残梦，斋房忽忽馀酲。", "薄衣团扇绕阶行。", "曲阑幽树，看得绿成阴。", "檐雨为谁凝咽，林花似我飘零。", "微吟休作断肠声。", "流莺百啭，解道此时情。"]'),
('song-ci-547','临江仙','陈克','宋','宋词','song-ci','临江仙','[]','四海十年兵不解，胡尘直到江城。',70,'宋词/ci.song.5000.json','["四海十年兵不解，胡尘直到江城。", "岁华销尽客心惊。", "疏髯浑似雪，衰涕欲生冰。", "送老齑盐何处是，我缘应在吴兴。", "故人相望若为情。", "别愁深夜雨，孤影小窗灯。"]'),
('song-ci-548','渔家傲','陈克','宋','宋词','song-ci','渔家傲','[]','宝瑟尘生郎去后。',72,'宋词/ci.song.5000.json','["宝瑟尘生郎去后。", "绿窗闲却春风手。", "浅色宫罗新染就。", "晴时后。", "裁缝细意花枝斗。", "象尺熏炉移永昼。", "粉涩浥浥蔷薇透。", "晚景看来浑似旧。", "沈吟久。", "个侬争得知人瘦。"]'),
('song-ci-549','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','浅画香膏拂紫绵。',48,'宋词/ci.song.5000.json','["浅画香膏拂紫绵。", "牡丹花重翠云偏。", "手挼梅子并郎肩。", "病起心情终是怯，困来模样不禁怜。", "旋移针线小窗前。"]'),
('song-ci-550','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','香雾空濛堕彩蟾。',48,'宋词/ci.song.5000.json','["香雾空濛堕彩蟾。", "倾城催映出重帘。", "□□银烛夜厌厌。", "何物与侬供醉眼，半黄梅子带红盐。", "粉融香润玉纤纤。"]'),
('song-ci-551','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','淡墨花枝掩薄罗。',48,'宋词/ci.song.5000.json','["淡墨花枝掩薄罗。", "嫩蓝裙子窣湘波。", "水晶新样碾风荷。", "问著似羞还似恶，恼来成笑不成歌。", "芙蓉帐里奈君何。"]'),
('song-ci-552','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','短烛荧荧照碧窗。',48,'宋词/ci.song.5000.json','["短烛荧荧照碧窗。", "重重帘幕护梨霜。", "幽欢不怕夜偏长。", "罗袜钿钗红粉醉，曲屏深幔绿橙香。", "征鸿离远断人肠。"]'),
('song-ci-553','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','小院春来百草青。',48,'宋词/ci.song.5000.json','["小院春来百草青。", "拂墙桃李已飘零。", "绝知春意总无凭。", "卢女嫁时终薄命，徐娘身老谩多情。", "洗香吹粉转娉婷。"]'),
('song-ci-554','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','窗纸幽幽不肯明。',48,'宋词/ci.song.5000.json','["窗纸幽幽不肯明。", "寒更忍作断肠声。", "背人残烛却多情。", "合下心期唯有梦，如今魂梦也无凭。", "几行闲泪莫纵横。"]'),
('song-ci-555','摊破浣溪沙・山花子','陈克','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','□慢梳头浅画眉。',56,'宋词/ci.song.5000.json','["□慢梳头浅画眉。", "乱莺残梦起多时。", "不道小庭花露湿，翦酴醿。", "帘额好风低燕子，窗油晴日打蜂儿。", "翠袖粉笺闲弄笔，写新诗。"]'),
('song-ci-556','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','花满院。',53,'宋词/ci.song.5000.json','["花满院。", "飞去飞来双燕。", "红雨入帘寒不卷。", "晓屏山六扇。", "翠袖玉笙凄断。", "脉脉两娥愁浅。", "消息不知郎近远。", "一春长梦见。"]'),
('song-ci-557','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','柳丝碧。',53,'宋词/ci.song.5000.json','["柳丝碧。", "柳下人家寒食。", "莺语匆匆花寂寂。", "玉阶春藓湿。", "闲凭薰笼无力。", "心事有谁知得。", "檀炷绕窗灯背壁。", "画檐残雨滴。"]'),
('song-ci-558','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','深院静。',53,'宋词/ci.song.5000.json','["深院静。", "尘暗曲房凄冷。", "黄叶满阶风不定。", "无端吹酒醒。", "露湿小园幽径。", "悄悄啼姑相应。", "半被馀熏残烛影。", "夜长人独冷。"]'),
('song-ci-559','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','春漏促。',53,'宋词/ci.song.5000.json','["春漏促。", "谁见两人心曲。", "罨画屏风银蜡烛。", "泪珠红蔌蔌。", "懊恼欢娱不足。", "只许梦中相逐。", "今夜月明何处宿。", "画桥春水绿。"]'),
('song-ci-560','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','春草碧。',53,'宋词/ci.song.5000.json','["春草碧。", "忆著去年寒食。", "白纻红裙香□□，折花闹调客。", "好在江南江北。", "燕子不传消息。", "醉眼腾腾羞面赤。", "断肠侬记得。"]'),
('song-ci-561','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','罗帐薄。',53,'宋词/ci.song.5000.json','["罗帐薄。", "缥缈绮疏飞阁。", "红地团花金解络。", "香囊垂四角。", "尽日春风帘幕。", "谁见绿屏纤弱。", "云压枕函钗自落。", "无端春梦恶。"]'),
('song-ci-562','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','愁脉脉。',53,'宋词/ci.song.5000.json','["愁脉脉。", "目断江南江北。", "烟树重重芳信隔。", "小楼山几尺。", "细草孤云斜日。", "一向弄晴天色。", "帘外落花飞不得。", "东风无气力。"]'),
('song-ci-563','谒金门','陈克','宋','宋词','song-ci','谒金门','[]','春寂寂。',53,'宋词/ci.song.5000.json','["春寂寂。", "绿暗溪南溪北。", "溪水沈沈天一色。", "鸟飞春树黑。", "肠断小楼吹笛，醉里看朱成碧。", "愁满眼前遮不得。", "可怜双鬓白。"]'),
('song-ci-564','虞美人','陈克','宋','宋词','song-ci','虞美人','[]','踏车不用青裙女。',66,'宋词/ci.song.5000.json','["踏车不用青裙女。", "日夜歌声苦。", "风流墨绶强跻攀。", "唤起潜蛟飞舞、破天悭。", "公庭休更重门掩。", "细听催诗点。", "一尊已咏北窗风。", "卧看雪儿纤手、剥莲蓬。"]'),
('song-ci-565','虞美人','陈克','宋','宋词','song-ci','虞美人','[]','小山戢戢盆池浅。',66,'宋词/ci.song.5000.json','["小山戢戢盆池浅。", "芳树阴阴转。", "红阑干上刺蔷薇。", "蝴蝶飞来飞去、两三枝。", "绣裙斜立腰肢困。", "翠黛萦新恨。", "风流踪迹使人猜。", "过了斗鸡时节、合归来。"]'),
('song-ci-566','虞美人','陈克','宋','宋词','song-ci','虞美人','[]','绿阴满院帘垂地。',66,'宋词/ci.song.5000.json','["绿阴满院帘垂地。", "落絮萦香砌。", "池光不定药栏低。", "闲并一双鸂鶒、没人时。", "旧欢黯黯成幽梦。", "帐卷金泥重。", "日虹斜处暗尘飞。", "脉脉小窗孤枕、镜花移。"]'),
('song-ci-567','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','[]','柳条窣窣闲庭院。',52,'宋词/ci.song.5000.json','["柳条窣窣闲庭院。", "锦波绣浪春风转。", "红日上阑干。", "晚来花更寒。", "绿檀金隐起。", "翠被香烟里。", "幽恨有谁知。", "空梁落燕泥。"]'),
('song-ci-568','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','赤阑桥尽香街直。',52,'宋词/ci.song.5000.json','["赤阑桥尽香街直。", "笼街细柳娇无力。", "金碧上青空。", "花晴帘影红。", "黄衫飞白马。", "日日青楼下。", "醉眼不逢人。", "午香吹暗尘。"]'),
('song-ci-569','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','[]','池塘淡淡浮鸂鶒。',52,'宋词/ci.song.5000.json','["池塘淡淡浮鸂鶒。", "杏花吹尽垂杨碧。", "天气度清明。", "小园新雨晴。", "绿窗描绣罢。", "笑语酴醿下。", "围坐赌青梅。", "困从双脸来。"]'),
('song-ci-570','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','绿芜墙绕青苔院。',52,'宋词/ci.song.5000.json','["绿芜墙绕青苔院。", "中庭日淡芭蕉卷。", "蝴蝶上阶飞。", "烘帘自在垂。", "玉钩双语燕。", "宝甃杨花转。", "几处簸钱声。", "绿窗春睡轻。"]'),
('song-ci-571','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','[]','柳条到地莺声滑。',52,'宋词/ci.song.5000.json','["柳条到地莺声滑。", "鸳鸯睡稳清沟阔。", "九曲转朱阑。", "花深人对闲。", "日长刀尺罢。", "试屐樱桃下。", "䰉髻玉钗风。", "云轻线脚红。"]'),
('song-ci-572','菩萨蛮','陈克','宋','宋词','song-ci','菩萨蛮','[]','绿阴寂寂樱桃下。',52,'宋词/ci.song.5000.json','["绿阴寂寂樱桃下。", "盆池劣照蔷薇架。", "帘影假山前。", "映阶红叶翻。", "芭蕉笼碧砌。", "猧子中庭睡。", "香径没人来。", "拂墙花又开。"]'),
('song-ci-573','点绛唇','陈克','宋','宋词','song-ci','点绛唇','[]','曲陌春风，谁家姊妹同墙看。',50,'宋词/ci.song.5000.json','["曲陌春风，谁家姊妹同墙看。", "映花烘暖。", "困入茸茸眼。", "细马轻衫，倚醉偷回面。", "垂杨转。", "坠鞭挥扇。", "白地肝肠断。"]'),
('song-ci-574','好事近','陈克','宋','宋词','song-ci','好事近','[]','寻遍石亭春，黯黯暮山明灭。',53,'宋词/ci.song.5000.json','["寻遍石亭春，黯黯暮山明灭。", "竹外小溪深处，倚一枝寒月。", "淡云疏雨苦无情，得折便须折。", "醉帽凤鬟归去，有馀香愁绝。"]'),
('song-ci-575','千秋岁','陈克','宋','宋词','song-ci','千秋岁','["\u957f\u6c5f"]','柏舟高躅。',87,'宋词/ci.song.5000.json','["柏舟高躅。", "晚岁宜遐福。", "门户壮，疏汤沐。", "青袍围白发。", "端锦缥犀轴。", "仙桂长，交柯却映蟠桃熟。", "缥缈长江曲。", "入破□箫逐。", "香雾满，飞华屋。", "玉钩凉月挂，冰麝芙蓉馥。", "千万寿，酒中倒卧南山绿。"]'),
('song-ci-576','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','禁瘆馀寒酒半醒。',64,'宋词/ci.song.5000.json','["禁瘆馀寒酒半醒。", "蒲萄力软被愁侵。", "鲤鱼不寄江南信，绿尽菖蒲春水深。", "疑梦断，怆离襟。", "重帘复幕静愔愔。", "赤阑干外梨花雨，还是去年寒食心。"]'),
('song-ci-577','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','芳树阴阴脱晚红。',64,'宋词/ci.song.5000.json','["芳树阴阴脱晚红。", "馀香不断玉钗风。", "簿情夫婿花相似，一片西飞一片东。", "金翡翠，绣芙蓉。", "从教纤媚笑床空。", "揉蓝衫子休无赖，只与离人结短封。"]'),
('song-ci-578','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','小市桥弯更向东。',64,'宋词/ci.song.5000.json','["小市桥弯更向东。", "便门长记旧相逢。", "踏青会散秋千下，鬓影衣香怯晚风。", "悲往事，向孤鸿。", "断肠肠断旧情浓。", "梨花院落黄茅店，绣被春寒此夜同。"]'),
('song-ci-579','豆叶黄・忆王孙','陈克','宋','宋词','song-ci','豆叶黄・忆王孙','[]','粉墙丹柱柳丝中。',36,'宋词/ci.song.5000.json','["粉墙丹柱柳丝中。", "帘箔轻明花影重。", "午醉醒来一面风。", "绿匆匆。", "几颗樱桃叶底红。"]'),
('song-ci-580','豆叶黄・忆王孙','陈克','宋','宋词','song-ci','豆叶黄・忆王孙','[]','树头初日鹁鸠鸣。',36,'宋词/ci.song.5000.json','["树头初日鹁鸠鸣。", "野店山桥新雨晴。", "短褐无泥竹杖轻。", "水泠泠。", "梅片飞时春草青。"]'),
('song-ci-581','豆叶黄・忆王孙','陈克','宋','宋词','song-ci','豆叶黄・忆王孙','[]','秋千人散小庭空。',36,'宋词/ci.song.5000.json','["秋千人散小庭空。", "麝冷灯昏愁杀侬。", "独有闲阶两袖风。", "月胧胧。", "一树梨花细雨中。"]'),
('song-ci-582','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','柳外东风不满旗。',64,'宋词/ci.song.5000.json','["柳外东风不满旗。", "青裾白面出疏篱。", "㬠来打鼓侬吹笛，催送儿郎踏浪飞。", "倾两耳，斗双螭。", "家家春酒泻尖泥。", "侬今已是沧浪客，莫向尊前唱教池。"]'),
('song-ci-583','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','罨画溪头春水生。',48,'宋词/ci.song.5000.json','["罨画溪头春水生。", "铜官山外夕阳明。", "暖风无力小舟横。", "万事悠悠生处熟，三杯兀兀醉时醒。", "杏花杨柳更多情。"]'),
('song-ci-584','浣溪沙','陈克','宋','宋词','song-ci','浣溪沙','[]','桥北桥南新雨晴。',48,'宋词/ci.song.5000.json','["桥北桥南新雨晴。", "柳边花底暮寒轻。", "万家灯火照溪明。", "凫舄差池官事了，木山彩错市人惊。", "街头酒贱唱歌声。"]'),
('song-ci-585','减字木兰花','陈克','宋','宋词','song-ci','减字木兰花','[]','阆风玄圃。',52,'宋词/ci.song.5000.json','["阆风玄圃。", "阳羡溪头山好处。", "郁郁葱葱。", "胜日尊罍笑语中。", "十分芳酒。", "鹤发初生千万寿。", "乐事年年。", "弟劝兄酬阿母前。"]'),
('song-ci-586','临江仙','陈克','宋','宋词','song-ci','临江仙','[]','老屋风悲脱叶，枯城月破浮烟。',68,'宋词/ci.song.5000.json','["老屋风悲脱叶，枯城月破浮烟。", "谁人惨惨把忧端。", "蛮歌犯星起，重觉在天边。", "秋色巧摧愁鬓，夜寒偏著诗肩。", "不知桂影为谁圆。", "何须照床里，终是一人眠。"]'),
('song-ci-587','清平乐','陈克','宋','宋词','song-ci','清平乐','[]','枕边清血。',54,'宋词/ci.song.5000.json','["枕边清血。", "梦好离肠切。", "笑倚柳条同挽结。", "满眼河桥烟月。", "莺啼新晓璁珑。", "罗窗寂寞春空。", "只许梦魂相近，此生枉是相逢。"]'),
('song-ci-588','鹧鸪天','陈克','宋','宋词','song-ci','鹧鸪天','[]','白苎吴侬红颊儿。',64,'宋词/ci.song.5000.json','["白苎吴侬红颊儿。", "行歌半是使君诗。", "山茶处处春犹浅，灯市人人夜不归。", "拚剧饮，莫相违。", "皇恩往往下丹墀。", "挥毫却对莲花炬，忆著苹洲秉烛时。"]'),
('song-ci-589','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','午夜添红蜡，分曹立翠娥。',62,'宋词/ci.song.5000.json','["午夜添红蜡，分曹立翠娥。", "觥筹寂寂断经过。", "谁料绮丛香里、是银河。", "老去空髯戟，愁来奈脸波。", "一杯如此断肠何。", "枉杀两人心事、只闻歌。"]'),
('song-ci-590','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','献鲤荣今日，凭熊瑞此邦。',62,'宋词/ci.song.5000.json','["献鲤荣今日，凭熊瑞此邦。", "年年寿酒乐城隍。", "共道使君椿树、似甘棠。", "歌舞重城晓，从容燕席凉。", "不须苏合与都梁。", "风外荷花无数、是炉香。"]'),
('song-ci-591','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','北固烟中寺，西津雨后山。',62,'宋词/ci.song.5000.json','["北固烟中寺，西津雨后山。", "看公英气两眉间。", "如在林霏、江月袭人寒。", "展翼声名久，占熊福艾全。", "风流不是地行仙。", "好去鞭笞鸾凤、紫微天。"]'),
('song-ci-592','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','云里千山暖，溪头八月凉。',62,'宋词/ci.song.5000.json','["云里千山暖，溪头八月凉。", "华簪霭霭待萱堂。", "羡子怀中双橘、半青黄。", "老去齐眉案，闲来坦腹床。", "相如何日从长杨。", "惭愧年年高会、索槟榔。"]'),
('song-ci-593','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','胜日萱庭小，西风橘柚长。',62,'宋词/ci.song.5000.json','["胜日萱庭小，西风橘柚长。", "天怜扇枕彩衣郎。", "乞与淡云纤月、十分凉。", "潋滟三危雾，氤氲百濯香。", "年来椿树更苍苍。", "不用蓝桥辛苦、捣玄霜。"]'),
('song-ci-594','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','画幛经梅润，罗衣尚麦寒。',62,'宋词/ci.song.5000.json','["画幛经梅润，罗衣尚麦寒。", "古苔苍石绿句栏。", "帘外映花新竹、两三竿。", "蠢蠢吴蚕卧，娉娉楚女闲。", "红阴角子共尝酸。", "肠断个侬憨态、小眉弯。"]'),
('song-ci-595','南歌子','陈克','宋','宋词','song-ci','南歌子','[]','看月凭肩枨，娇春枕臂眠。',62,'宋词/ci.song.5000.json','["看月凭肩枨，娇春枕臂眠。", "不尽花絮夜来寒。", "帐底浓香残梦、更缠绵。", "起晚笼莺怪，妆迟绣伴牵。", "声声催唤药栏边。", "整髻收裙无力、上秋千。"]'),
('song-ci-596','虞美人','陈克','宋','宋词','song-ci','虞美人','[]','越罗巧画春山叠。',66,'宋词/ci.song.5000.json','["越罗巧画春山叠。", "个里融香雪。", "满身空翠不胜寒。", "恰似那回偷印、小眉山。", "青骢油壁西陵下。", "仿佛当时话。", "而今眼底是高唐。", "拂拂淡云疏雨、断人肠。"]'),
('song-ci-597','双燕儿','朱敦复','宋','宋词','song-ci','双燕儿','[]','尚志服事跛神仙。',64,'宋词/ci.song.5000.json','["尚志服事跛神仙。", "辛勤了、万千般。", "一朝身死入黄泉。", "至诚地、哭皇天。", "旁人苦苦叩玄言。", "不免得、告诸贤。", "禁法蝎儿不曾传。", "吃畜生、四十年。"]'),
('song-ci-598','聒龙谣','朱敦儒','宋','宋词','song-ci','聒龙谣','[]','肩拍洪崖，手携子晋，梦里暂辞尘宇。',125,'宋词/ci.song.5000.json','["肩拍洪崖，手携子晋，梦里暂辞尘宇。", "高步层霄，俯人间如许。", "算蜗战、多少功名，问蚁聚、几回今古。", "度银潢、展尽参旗，桂花澹，月飞去。", "天风紧，玉楼斜，舞万女霓袖，光摇金缕。", "明廷宴阕，倚青冥回顾。", "过瑶池、重借双成，就楚岫、更邀巫女。", "转云车、指点虚无，引蓬莱路。"]'),
('song-ci-599','聒龙谣','朱敦儒','宋','宋词','song-ci','聒龙谣','[]','凭月携箫，溯空秉羽，梦踏绛霄仙去。',125,'宋词/ci.song.5000.json','["凭月携箫，溯空秉羽，梦踏绛霄仙去。", "花冷街榆，悄中天风露。", "并真官、蕊佩芬芳，望帝所、紫云容与。", "享钧天、九奏传觞，听龙啸，看莺舞。", "惊尘世，悔平生，叹万感千恨，谁怜深素。", "群仙念我，好人间难住。", "劝阿母、偏与金桃，教酒星、剩斟琼醑。", "醉归时、手授丹经，指长生路。"]'),
('song-ci-600','雨中花・夜行船','朱敦儒','宋','宋词','song-ci','雨中花・夜行船','[]','故国当年得意，射麋上苑，走马长楸。',118,'宋词/ci.song.5000.json','["故国当年得意，射麋上苑，走马长楸。", "对匆匆佳气，赤县神州。", "好景何曾虚过，胜友是处相留。", "向伊川雪夜，洛浦花朝，占断狂游。", "胡尘卷地，南走炎荒，曳裾强学应刘。", "空漫说、螭蟠龙卧，谁取封侯。", "塞雁年年北去，蛮江日日西流。", "此生老矣，除非春梦，重到东周。"]'),
('song-ci-601','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','当年五陵下，结客占春游。',114,'宋词/ci.song.5000.json','["当年五陵下，结客占春游。", "红缨翠带，谈笑跋马水西头。", "落日经过桃叶，不管插花归去，小袖挽人留。", "换酒春壶碧，脱帽醉青楼。", "楚云惊，陇水散，两漂流。", "如今憔悴，天涯何处可消忧。", "长揖飞鸿旧月。", "不知今夕烟水，都照几人愁。", "有泪看芳草，无路认西州。"]'),
('song-ci-602','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','白日去如箭，达者惜分阴。',114,'宋词/ci.song.5000.json','["白日去如箭，达者惜分阴。", "问君何苦，长抱冰炭利名心。", "冀望封侯一品，侥倖升仙三岛，不死解烧金。", "听取百年曲，三叹有遗音。", "会良朋，逢美景，井频斟。", "昔人已矣，松下泉底不如今。", "幸遇重阳佳节，高处红萸黄菊，好把醉乡寻。", "澹澹飞鸿没，千古共销魂。"]'),
('song-ci-603','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','偏赏中秋月，从古到如今。',114,'宋词/ci.song.5000.json','["偏赏中秋月，从古到如今。", "金风玉露相间，别做一般清。", "是处帘栊争卷，谁家管弦不动，乐世足欢情。", "莫指关山路，空使翠蛾颦。", "水精盘，鲈鱼脍，点新橙。", "鹅黄酒暖，纤手传杯任频斟。", "须惜晓参横后，直到来年今夕，十二数亏盈。", "未必来年看，得似此回明。"]'),
('song-ci-604','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','平生看明月，西北有高楼。',114,'宋词/ci.song.5000.json','["平生看明月，西北有高楼。", "如今羁旅，常叹茅屋暗悲秋。", "闻说吴淞江上，有个垂虹亭好，结友漾轻舟。", "记得蓬莱路，端是旧曾游。", "趁黄鹄，湖影乱，海光浮。", "绝尘胜处，合是不数白苹洲。", "何物陶朱张翰，劝汝橙齑鲈脍，交错献还酬。", "寄语梅仙道，来岁肯同不。"]'),
('song-ci-605','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','天宇著垂象，日月共回旋。',114,'宋词/ci.song.5000.json','["天宇著垂象，日月共回旋。", "因何明月，偏被指点古来传。", "浪语修成七宝，漫说霓裳九奏，阿姊最婵娟。", "愤激书青奏，伏愿听臣言。", "诏六丁，驱狡兔，屏痴蟾。", "移根老桂，种在历历白榆边。", "深锁广寒宫殿，不许姮娥歌舞，按次守星躔。", "永使无亏缺，长对日团圆。"]'),
('song-ci-606','水调歌头','朱敦儒','宋','宋词','song-ci','水调歌头','[]','中秋一轮月，只和旧青冥。',114,'宋词/ci.song.5000.json','["中秋一轮月，只和旧青冥。", "都缘人意，须道今夕别般明。", "是处登临开宴，争看吴歌楚舞，沈醉倒金尊。", "各自心中事，悲乐几般情。", "烛摧花，鹤警露，忽三更。", "舞茵未卷，玉绳低转便西倾。", "认取眼前流景，试看月归何处，因甚有亏盈。", "我自阖门睡，高枕笑浮生。"]'),
('song-ci-607','桂枝香','朱敦儒','宋','宋词','song-ci','桂枝香','[]','春寒未定。',124,'宋词/ci.song.5000.json','["春寒未定。", "是欲近清明，雨斜风横。", "深闭朱门，尽日柳摇金井。", "年光自趁飞花紧。", "奈幽人、雪添双鬓。", "谢山携妓，黄垆贳酒，旧愁慵整。", "念壮节、漂零未稳。", "负九江风笛，五湖烟艇。", "起舞悲歌，泪眼自看清影。", "新莺又向愁时听。", "把人间、如梦深省。", "旧溪鹤在，寻云弄水，是事休问。"]'),
('song-ci-608','水龙吟','朱敦儒','宋','宋词','song-ci','水龙吟','[]','放船千里凌波去。',126,'宋词/ci.song.5000.json','["放船千里凌波去。", "略为吴山留顾。", "云屯水府，涛随神女，九江东注。", "北客翩然，壮心偏感，年华将暮。", "念伊嵩旧隐，巢由故友，南柯梦、遽如许。", "回首妖氛未扫，问人间、英雄何处。", "奇谋报国，可怜无用，尘昏白羽。", "铁锁横江，锦帆冲浪，孙郎良苦。", "但求敲桂棹，悲吟梁父，泪流如雨。"]'),
('song-ci-609','水龙吟','朱敦儒','宋','宋词','song-ci','水龙吟','[]','晓来极目同云，暧空降雪花零乱。',126,'宋词/ci.song.5000.json','["晓来极目同云，暧空降雪花零乱。", "平生尘想，老来俗状，都齐惊散。", "玉凤凌霄，素虬横海，一杯相劝。", "任霓裳学舞，梅妆作面，终不似、天裁翦。", "正是年华美满。", "斗迎春、巧飞钗燕。", "冲寒醉眼，倚空长揖，群仙笑粲。", "说道瑶池，有人来报，西真开宴。", "便争回蕊佩，高驰羽驾，卷东风转。"]'),
('song-ci-610','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','见梅惊笑，问经年何处，收香藏白。',122,'宋词/ci.song.5000.json','["见梅惊笑，问经年何处，收香藏白。", "似语如愁，却问我、何苦红尘久客。", "观里栽桃，仙家种杏，到处成疏隔。", "千林无伴，澹然独傲霜雪。", "且与管领春回，孤标争肯接、雄蜂雌蝶。", "岂是无情，知受了、多少凄凉风月。", "寄驿人遥，和羹心在，忍使芳尘歇。", "东风寂寞，可怜谁为攀折。"]'),
('song-ci-611','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','插天翠柳，被何人，推上一轮明月。',121,'宋词/ci.song.5000.json','["插天翠柳，被何人，推上一轮明月。", "照我藤床凉似水，飞入瑶台琼阙。", "雾冷笙箫，风轻环佩，玉锁无人掣。", "闲云收尽，海光天影相接。", "谁信有药长生，素娥新炼就、飞霜凝雪。", "打碎珊瑚，争似看、仙桂扶疏横绝。", "洗尽凡心，满身清露，冷浸萧萧发。", "明朝尘世，记取休向人说。"]'),
('song-ci-612','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','晚凉可爱，是黄昏人静，风生苹叶。',120,'宋词/ci.song.5000.json','["晚凉可爱，是黄昏人静，风生苹叶。", "谁作秋声穿细柳，初听寒蝉凄切。", "旋采芙蓉，重熏沈水，暗里香交彻。", "拂开冰簟，小床独卧明月。", "老来应免多情，还因风景好，愁肠重结。", "可惜良宵人不见，角枕兰衾虚设。", "宛转无眠，起来闲步，露草时明灭。", "银河西去，画楼残角呜咽。"]'),
('song-ci-613','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','老来可喜，是历遍人间，谙知物外。',121,'宋词/ci.song.5000.json','["老来可喜，是历遍人间，谙知物外。", "看透虚空，将恨海愁山，一时挼碎。", "免被花迷，不为酒困，到处惺惺地。", "饱来觅睡，睡起逢场作戏。", "休说古往今来，乃翁心里，没许多般事。", "也不蕲仙不佞佛，不学栖栖孔子。", "懒共贤争，从教他笑，如此只如此。", "杂剧打了，戏衫脱与呆底。"]'),
('song-ci-614','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','素秋天气，是登山临水，昔人悲处。',121,'宋词/ci.song.5000.json','["素秋天气，是登山临水，昔人悲处。", "我遇清时无个事，好约莺迁鸿翥。", "旋整兰舟，多携芳酝，笑里轻帆举。", "松江缆月，望云飞棹延伫。", "别乘文雅风流，新词光万丈，珠连锦聚。", "恨不同游，指浩渺、玉宇琼楼相付。", "桂子收香，蟾辉采露，暂辍尊前舞。", "丝囊封寄，倩他双翠衔去。"]'),
('song-ci-615','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','腊回春近，正日添宫线，香传梅驿。',120,'宋词/ci.song.5000.json','["腊回春近，正日添宫线，香传梅驿。", "玉律冰壶此际显，天与奇才英识。", "贯日孤忠，凌云独志，曾展回天力。", "功名由命，等闲却铩鸾翮。", "谁信夫子如今，眠云情意稳，风尘机息。", "邂逅初心得计处，伊水鸥闲波碧。", "但恐天教，经纶缘在，未遂紫烟客。", "君王图旧，看公归觐京国。"]'),
('song-ci-616','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','放船纵棹，趁吴江风露，平分秋色。',121,'宋词/ci.song.5000.json','["放船纵棹，趁吴江风露，平分秋色。", "帆卷垂虹波面冷，初落萧萧枫叶。", "万顷琉璃，一轮金鉴，与我成三客。", "碧空寥阔，瑞星银汉争白。", "深夜悄悄鱼龙，灵旗收暮霭，天光相接。", "莹澈乾坤，全放出、叠玉层冰宫阙。", "洗尽凡心，相忘尘世，梦想都销歇。", "胸中云海，浩然犹浸明月。"]'),
('song-ci-617','苏武慢','朱敦儒','宋','宋词','song-ci','苏武慢','[]','枕海山横，陵江潮去，雉堞秋风残照。',138,'宋词/ci.song.5000.json','["枕海山横，陵江潮去，雉堞秋风残照。", "闲寻桂子，试听菱歌，湖上晚来凉好。", "几处兰舟，采莲游女，归去隔花相恼。", "奈长安不见，刘郎已老，暗伤怀抱。", "谁信得、旧日风流，如今憔悴，换却五陵年少。", "逢花倒趓，遇酒坚辞，常是懒歌慵笑。", "除奉天威，扫平狂虏，整顿乾坤都了。", "共赤松携手，重骑明月，再游蓬岛。"]'),
('song-ci-618','木兰花慢','朱敦儒','宋','宋词','song-ci','木兰花慢','[]','折芙蓉弄水，动玉佩、起秋风。',120,'宋词/ci.song.5000.json','["折芙蓉弄水，动玉佩、起秋风。", "正柳外闲云，溪头澹月，映带疏钟。", "人间厌谪堕久，恨霓旌未返碧楼空。", "且与时人度日，自怜怀抱谁同。", "当时种玉五云东。", "露冷夜耕龙。", "念瑞草成畦，琼疏未采，尘染衰容。", "谁知素心未已，望清都绛阙有无中。", "寂寞归来隐几，梦听帝乐冲融。"]'),
('song-ci-619','木兰花慢','朱敦儒','宋','宋词','song-ci','木兰花慢','[]','指荣河峻岳，锁胡尘、几经秋。',122,'宋词/ci.song.5000.json','["指荣河峻岳，锁胡尘、几经秋。", "叹故苑花空，春游梦冷，万斛堆愁。", "簪缨散、关塞阻，恨难寻杏馆觅瓜畴。", "凄惨年来岁往，断鸿去燕悠悠。", "拘幽。", "化碧海西头。", "剑履问谁收。", "但易水歌传，子山赋在，青史名留。", "吾曹镜中看取，且狂歌载酒古扬州。", "休把霜髯老眼，等闲清泪空流。"]'),
('song-ci-620','洞仙歌','朱敦儒','宋','宋词','song-ci','洞仙歌','[]','今年生日，庆一百省岁。',103,'宋词/ci.song.5000.json','["今年生日，庆一百省岁。", "喜趁烧灯作欢会。", "问先生有甚，阴德神丹，霜雪里、鹤在青松相似。", "总无奇异处，只是天然，冷澹寻常旧家计。", "探袖弄明珠，满眼儿孙，一壶酒、□向花间长醉。", "且落魄、装个老人星，共野叟行歌，太平时世。"]'),
('song-ci-621','洞仙歌','朱敦儒','宋','宋词','song-ci','洞仙歌','[]','风流老峭，负不群奇表。',103,'宋词/ci.song.5000.json','["风流老峭，负不群奇表。", "弹指超凡怎由教。", "把俗儒故纸，推向一边，三界外、寻得一场好笑。", "尘缘无处趓，应见宰官，苦行公心众难到。", "这功名富贵，有也寻常，管做得、越古超今神妙。", "待接得、众生总成佛，向酒肆淫房，再逞年少。"]'),
('song-ci-622','洞仙歌','朱敦儒','宋','宋词','song-ci','洞仙歌','[]','何人不爱，是江梅红绽。',103,'宋词/ci.song.5000.json','["何人不爱，是江梅红绽。", "雪野寒空冻云晚。", "照清溪绰约，粉艳先春，包绛萼、姑射冰肌自暖。", "上林花万品，都借风流，国色天香任欣羡。", "共素娥青女，一笑相逢，人不见、悄悄霜宫月殿。", "想乘云、是在玉皇前，粲蕊佩明珰，侍清都燕。"]'),
('song-ci-623','满庭芳','朱敦儒','宋','宋词','song-ci','满庭芳','[]','鹏海风波，鹤巢云水，梦残身寄尘寰。',118,'宋词/ci.song.5000.json','["鹏海风波，鹤巢云水，梦残身寄尘寰。", "老来穷健，无闷也无欢。", "随分饥餐困睡，浑忘了、秋热春寒。", "清平世，闲人自在，乘兴访溪山。", "渔竿。", "要老伴，浮江载酒，舣棹观澜。", "倩轻鸥假道，白鹭随轩。", "直到垂虹亭上，惊怪我、却做仙官。", "中秋月，披襟四顾，不似在人间。"]'),
('song-ci-624','满庭芳','朱敦儒','宋','宋词','song-ci','满庭芳','[]','花满金盆，香凝碧帐，小楼晓日飞光。',118,'宋词/ci.song.5000.json','["花满金盆，香凝碧帐，小楼晓日飞光。", "有人相伴，开镜点新妆。", "脸嫩琼肌著粉，眉峰秀、波眼宜长。", "云鬟就，玉纤溅水，轻笑换明珰。", "檀郎。", "犹恣意，高敧凤枕，慵下银床。", "问今日何处，斗草寻芳。", "不管馀酲未解，扶头酒、亲捧瑶觞。", "催人起，雕鞍翠幰，乘露看姚黄。"]'),
('song-ci-625','满江红','朱敦儒','宋','宋词','song-ci','满江红','[]','竹翠阴森，寒泉浸、几峰奇石。',115,'宋词/ci.song.5000.json','["竹翠阴森，寒泉浸、几峰奇石。", "销畏日、溪蒲呈秀，水蕉供碧。", "筠簟平铺光欲动，纱裯高挂空无色。", "似月明、苹叶起秋风，潇湘白。", "不敢笑，红尘客。", "争肯羡，神仙宅。", "且披襟脱帽，自适其适。", "靖节窗风犹有待，本初朔饮非长策。", "怎似我、心闲便清凉，无南北。"]'),
('song-ci-626','风流子','朱敦儒','宋','宋词','song-ci','风流子','["\u897f\u6e56"]','吴越东风起，江南路，芳草绿争春。',135,'宋词/ci.song.5000.json','["吴越东风起，江南路，芳草绿争春。", "倚危楼纵目，绣帘初卷，扇边寒减，竹外花明。", "看西湖、画船轻泛水，茵幄稳临津。", "嬉游伴侣，两两携手，醉回别浦，歌遏南云。", "有客愁如海，江山异，举目暗觉伤神。", "空想故园池阁，卷地烟尘。", "但且恁、痛饮狂歌，欲把恨怀开解，转更销魂。", "只是皱眉弹指，冷过黄昏。"]'),
('song-ci-627','望海潮','朱敦儒','宋','宋词','song-ci','望海潮','[]','嵩高维岳，图书之渊，西都二室三川。',129,'宋词/ci.song.5000.json','["嵩高维岳，图书之渊，西都二室三川。", "神鼎定金，麟符刻玉，英灵未称河山。", "谁再整乾坤。", "是挺生真主，浴日开天。", "御归梁苑，驾回汾水凤楼闲。", "升平运属当千。", "眷凝旒暇日，西顾依然。", "银汉诏虹，瑶台赐碧，一新瑞气祥烟。", "重到帝居前。", "怪鹊桥龙阙，飞下人间。", "父老欢呼，翠华来也太平年。"]'),
('song-ci-628','胜胜慢・声声慢','朱敦儒','宋','宋词','song-ci','胜胜慢・声声慢','["\u897f\u6e56"]','红炉围锦，翠幄盘雕，楼前万里同云。',119,'宋词/ci.song.5000.json','["红炉围锦，翠幄盘雕，楼前万里同云。", "青雀窥窗，来报瑞雪纷纷。", "开帘放教飘洒，度华筵、飞入金尊。", "斗迎面，看美人呵手，旋浥罗巾。", "莫说梁园往事，休更羡、越溪访戴幽人。", "此日西湖真境，圣治中兴。", "直须听歌按舞，任留香、满酌杯深。", "最好是，贺丰年、天下太平。"]'),
('song-ci-629','芰荷香','朱敦儒','宋','宋词','song-ci','芰荷香','[]','远寻花。',120,'宋词/ci.song.5000.json','["远寻花。", "正风亭霁雨，烟浦移沙。", "缓提金勒，路拥桃叶香车。", "凭高帐饮，照羽觞、晚日横斜。", "六朝浪语繁华。", "山围故国，绮散馀霞。", "无奈尊前万里客，叹人今何在，身老天涯。", "壮心零落，怕听叠鼓掺挝。", "江浮醉眼，望浩渺、空想灵槎。", "曲终泪湿琵琶。", "谁扶上马，不省还家。"]'),
('song-ci-630','沁园春','朱敦儒','宋','宋词','song-ci','沁园春','[]','七十衰翁，告老归来，放怀纵心。',141,'宋词/ci.song.5000.json','["七十衰翁，告老归来，放怀纵心。", "念聚星高宴，围红盛集，如何著得，华发陈人。", "勉意追随，强颜陪奉，费力劳神恐未真。", "君休怪，近频辞雅会，不是无情。", "岩扃。", "旧菊犹存。", "更松偃、梅疏新种成。", "爱静窗明几，焚香宴坐，闲调绿绮，默诵黄庭。", "莲社轻舆，雪溪小棹，有兴何妨寻弟兄。", "如今且，趓花迷酒困，心迹双清。"]'),
('song-ci-631','卜算子慢','朱敦儒','宋','宋词','song-ci','卜算子慢','[]','凭高望远，云断路迷，山簇暮寒凄紧。',108,'宋词/ci.song.5000.json','["凭高望远，云断路迷，山簇暮寒凄紧。", "兰菊如斯，燕子怎知秋尽。", "想闺中、锦换新翻晕。", "自解佩匆匆散后，鸳鸯到今难问。", "只得愁成病。", "是悔上瑶台，误留金枕。", "不忍相忘，万里再寻音信。", "奈飘风、不许蓬莱近。", "又一番、冻雨凄凉，送归鸿成阵。"]'),
('song-ci-632','醉春风','朱敦儒','宋','宋词','song-ci','醉春风','[]','夜饮西真洞。',78,'宋词/ci.song.5000.json','["夜饮西真洞。", "群仙惊戏弄。", "素娥传酒袖凌风，送送送。", "吸尽金波，醉朝天阙，斗班星拱。", "碧简承新宠。", "紫微恩露重。", "忽然推枕草堂空。", "梦梦梦。", "帐冷衾寒，月斜灯暗，画楼钟动。"]'),
('song-ci-633','踏歌','朱敦儒','宋','宋词','song-ci','踏歌','[]','宴阕。',101,'宋词/ci.song.5000.json','["宴阕。", "散津亭鼓吹扁舟发。", "离魂黯、隐隐阳关彻。", "更风愁雨细添凄切。", "恨结。", "叹良朋雅会轻离诀。", "一年价、把酒风花月。", "便山遥水远分吴越。", "书倩雁，梦借蝶。", "重相见、且把归期说。", "只愁到他日，彼此萍踪别。", "总难如、前会时节。"]'),
('song-ci-634','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','溪清水浅，月胧烟澹，玉破梅梢未遍。',68,'宋词/ci.song.5000.json','["溪清水浅，月胧烟澹，玉破梅梢未遍。", "横枝依约影如无，但风里、空香数点。", "乘风欲去，凌波难住，谁见红愁粉怨。", "夜深青女湿微霜，暗香散、广寒宫殿。"]'),
('song-ci-635','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','今年冬后，黄花初绽。',68,'宋词/ci.song.5000.json','["今年冬后，黄花初绽。", "莫怪时光较晚。", "晓来玉露浥芳丛，莹秀色、无尘到眼。", "支筇驻屐，徘徊篱畔。", "弄酌金杯自泛。", "须添罗幕护风霜，要留与、疏梅相见。"]'),
('song-ci-636','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','姮娥怕闹，银蟾传令，且与遮鸾翳凤。',68,'宋词/ci.song.5000.json','["姮娥怕闹，银蟾传令，且与遮鸾翳凤。", "直须人睡俗尘清，放云汉、冰轮徐动。", "山翁散发，披衣松下，琴奏瑶池三弄。", "曲终鹤警露华寒，笑浊世、饶伊做梦。"]'),
('song-ci-637','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','携琴寄鹤，辞山别水，乘兴随云做客。',68,'宋词/ci.song.5000.json','["携琴寄鹤，辞山别水，乘兴随云做客。", "囊中欲试紫金丹，待点化、鸾红凤碧。", "谁知到此，玉梯无路，天上难通消息。", "不如却趁白云归，免误使、山英扫迹。"]'),
('song-ci-638','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','竹西散策，花阴围坐，可恨来迟几日。',68,'宋词/ci.song.5000.json','["竹西散策，花阴围坐，可恨来迟几日。", "披香不觉玉壶空，破酒面、飞红半湿。", "悲歌醉舞，九人而已，总是天涯倦客。", "东风吹泪故园春，问我辈、何时去得。"]'),
('song-ci-639','鹊桥仙','朱敦儒','宋','宋词','song-ci','鹊桥仙','[]','白鸥欲下，金鱼不去，圆叶低开蕙帐。',68,'宋词/ci.song.5000.json','["白鸥欲下，金鱼不去，圆叶低开蕙帐。", "轻风冷露夜深时，独自个、凌波直上。", "幽阑共晚，明珰难寄，尘世教谁将傍。", "会寻织女趁灵槎，泛旧路、银河万丈。"]'),
('song-ci-640','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','西子溪头春到也，大家追趁芳菲。',70,'宋词/ci.song.5000.json','["西子溪头春到也，大家追趁芳菲。", "盘雕翦锦换障泥。", "花添金凿落，风展玉东西。", "先探谁家梅最早，雪儿桂子同携。", "别翻舞袖按新词。", "从今排日醉，醉过牡丹时。"]'),
('song-ci-641','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','堪笑一场颠倒梦，元来恰似浮云。',70,'宋词/ci.song.5000.json','["堪笑一场颠倒梦，元来恰似浮云。", "尘劳何事最相亲。", "今朝忙到夜，过腊又逢春。", "流水滔滔无住处，飞光忽忽西沈。", "世间谁是百年人。", "个中须著眼，认取自家身。"]'),
('song-ci-642','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','直自凤凰城破后，掰钗破镜分飞。',70,'宋词/ci.song.5000.json','["直自凤凰城破后，掰钗破镜分飞。", "天涯海角信音稀。", "梦回辽海北，魂断玉关西。", "月解重圆星解聚，如何不见人归。", "今春还听杜鹃蹄。", "年年看塞雁，一十四番回。"]'),
('song-ci-643','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','最好中秋秋夜月，常时易雨多阴。',70,'宋词/ci.song.5000.json','["最好中秋秋夜月，常时易雨多阴。", "难逢此夜更无云。", "玉轮飞碧落，银幕换层城。", "桂子香浓凝瑞露，中兴气象分明。", "酒楼灯市管弦声。", "今宵谁肯睡，醉看晓参横。"]'),
('song-ci-644','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','生长西都逢化日，行歌不记流年。',70,'宋词/ci.song.5000.json','["生长西都逢化日，行歌不记流年。", "花间相过酒家眠。", "乘风游二室，弄雪过三川。", "莫笑衰容双鬓改，自家风味依然。", "碧潭明月水中天。", "谁闲如老子，不肯作神仙。"]'),
('song-ci-645','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','纱帽篮舆青织盖，儿孙从我嬉游。',70,'宋词/ci.song.5000.json','["纱帽篮舆青织盖，儿孙从我嬉游。", "绿池红径雨初收。", "秾桃偏会笑，细柳几曾愁。", "随分盘筵供笑语，花间社酒新篘。", "踏歌起舞醉方休。", "陶潜能啸傲，贺老最风流。"]'),
('song-ci-646','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','几日春愁无意绪，拈金翦彩慵拈。',70,'宋词/ci.song.5000.json','["几日春愁无意绪，拈金翦彩慵拈。", "小楼终日怕凭阑。", "一双新泪眼，千里旧关山。", "苦恨碧云音信断，只教征雁空还。", "早知盟约是虚言。", "枉裁诗字锦，悔寄泪痕笺。"]'),
('song-ci-647','临江仙','朱敦儒','宋','宋词','song-ci','临江仙','[]','信取虚空无一物，个中著甚商量。',70,'宋词/ci.song.5000.json','["信取虚空无一物，个中著甚商量。", "风头紧后白云忙。", "风元无去住，云自没行藏。", "莫听古人闲语话，终归失马亡羊。", "自家肠肚自端详。", "一齐都打碎，放出大圆光。"]'),
('song-ci-648','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','草草园林作洛川。',64,'宋词/ci.song.5000.json','["草草园林作洛川。", "碧宫红塔借风烟。", "虽无金谷花能笑，也有铜驼柳解眠。", "春似旧，酒依前。", "何妨倚杖雪垂肩。", "五陵侠少今谁健，似我亲逢建武年。"]'),
('song-ci-649','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','检尽历头冬又残。',64,'宋词/ci.song.5000.json','["检尽历头冬又残。", "爱他风雪忍他寒。", "拖条竹杖家家酒，上个篮舆处处山。", "添老大，转痴顽。", "谢天教我老来闲。", "道人还了鸳鸯债，纸帐梅花醉梦间。"]'),
('song-ci-650','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','我是清都山水郎，天教懒慢带疏狂。',64,'宋词/ci.song.5000.json','["我是清都山水郎，天教懒慢带疏狂。", "曾批给露支风敕，累奏留云借月章。", "诗万首，酒千觞，几曾着眼看侯王？玉楼金阙慵归去，且插梅花醉洛阳。"]'),
('song-ci-651','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','唱得梨园绝代声。',64,'宋词/ci.song.5000.json','["唱得梨园绝代声。", "前朝惟数李夫人。", "自从惊破霓裳后，楚奏吴歌扇里新。", "秦嶂雁，越溪砧。", "西风北客两飘零。", "尊前忽听当时曲，侧帽停杯泪满巾。"]'),
('song-ci-652','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','曾为梅花醉不归。',64,'宋词/ci.song.5000.json','["曾为梅花醉不归。", "佳人挽袖乞新词。", "轻红遍写鸳鸯带，浓碧争斟翡翠卮。", "人已老，事皆非。", "花前不饮泪沾衣。", "如今但欲关门睡，一任梅花作雪飞。"]'),
('song-ci-653','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','画舫东时洛水清。',64,'宋词/ci.song.5000.json','["画舫东时洛水清。", "别离心绪若为情。", "西风挹泪分携后，十年长亭九梦君。", "云背水，雁回汀。", "只应芳草见离魂。", "前回共采芙蓉处，风自凄凄月自明。"]'),
('song-ci-654','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','竹粉吹香杏子丹。',64,'宋词/ci.song.5000.json','["竹粉吹香杏子丹。", "试新纱帽纻衣宽。", "日长几案琴书静，地僻池塘鸥鹭闲。", "寻汗漫，听潺湲。", "澹然心寄水云间。", "无人共酌松黄酒，时有飞仙暗往还。"]'),
('song-ci-655','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','至节先庚欲雪天。',64,'宋词/ci.song.5000.json','["至节先庚欲雪天。", "玳筵围锦帐青毡。", "嫖姚副帅招佳客，太守高明别乘贤。", "歌宛转，舞蹁迁。", "金钗十二拥婵娟。", "老人南极星边住，也趁梅花听管弦。"]'),
('song-ci-656','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','凤烛星球初试灯。',64,'宋词/ci.song.5000.json','["凤烛星球初试灯。", "冰轮辗破碧棱层。", "来宵虽道十分满，未必胜如此夜明。", "留上客，换瑶觥。", "任教楼外晓参横。", "春风从旧偏怜我，那更姮娥是故人。"]'),
('song-ci-657','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','通处灵犀一点真。',64,'宋词/ci.song.5000.json','["通处灵犀一点真。", "忺随紫橐步红茵，个中自是神仙住，花作帘栊玉作人。", "偏澹静，最尖新。", "等闲舞雪振歌尘。", "若教宋玉尊前见，应笑襄王梦里寻。"]'),
('song-ci-658','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','天上人间酒最尊。',64,'宋词/ci.song.5000.json','["天上人间酒最尊。", "非甘非苦味通神。", "一杯能变愁山色，三盏全迥冷谷春。", "欢后笑，怒时瞋。", "醒来不记有何因。", "古时有个陶元亮，解道君当恕醉人。"]'),
('song-ci-659','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','有个仙人捧玉卮。',64,'宋词/ci.song.5000.json','["有个仙人捧玉卮。", "满斟坚劝不须辞。", "瑞龙透顶香难比，甘露浇心味更奇。", "开道域，洗尘机。", "融融天乐醉瑶池。", "霓裳拽住君休去，待我醒时更一瓻。"]'),
('song-ci-660','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','不系虚舟取性颠。',64,'宋词/ci.song.5000.json','["不系虚舟取性颠。", "浮河泛海不知年。", "乘风安用青帆引，逆浪何须锦缆牵。", "云荐枕，月铺毡。", "无朝无夜任横眠。", "太虚空里知谁管，有个明官唤做天。"]'),
('song-ci-661','鹧鸪天','朱敦儒','宋','宋词','song-ci','鹧鸪天','[]','极目江湖水浸云。',64,'宋词/ci.song.5000.json','["极目江湖水浸云。", "不堪回首洛阳春。", "天津帐饮凌云客，花市行歌绝代人。", "穿绣陌，踏香尘。", "满城沈醉管弦声。", "如今远客休惆怅，饱向皇都见太平。"]'),
('song-ci-662','木兰花・玉楼春','朱敦儒','宋','宋词','song-ci','木兰花・玉楼春','[]','老后人间无去处。',64,'宋词/ci.song.5000.json','["老后人间无去处。", "多谢碧桃留我住。", "红尘回步旧烟霞，清境开扉新院宇。", "隐几日长香一缕。", "风散飞花红不聚。", "眼前寻见自家春，罢问玉霄云海路。"]'),
('song-ci-663','木兰花・玉楼春','朱敦儒','宋','宋词','song-ci','木兰花・玉楼春','[]','前日寻梅椒样缀。',64,'宋词/ci.song.5000.json','["前日寻梅椒样缀。", "今日寻梅蜂已至。", "乍开绛萼欲生香，略绽粉苞先有意。", "古人今日升沈异。", "定是江南无驿使。", "自调弦管自开尊，笑把花枝花下醉。"]'),
('song-ci-664','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','邻家相唤，酒熟闲相过。',102,'宋词/ci.song.5000.json','["邻家相唤，酒熟闲相过。", "竹径引篮舆，会乡老、吾曹几个。", "沈家姊妹，也是可怜人，回巧笑，发清歌，相间花间坐。", "高谈阔论，无可无不可。", "幸遇太平年，好时节、清明初破。", "浮生春梦，难得是欢娱，休要劝，不须辞，醉便花间卧。"]'),
('song-ci-665','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','琼蔬玉蕊。',102,'宋词/ci.song.5000.json','["琼蔬玉蕊。", "久寄清虚里。", "春到碧溪东，下白云、寻桃问李。", "弹簧吹叶，懒傍少年场，遗楚佩，觅秦箫，踏破青鞋底。", "河桥酒熟，谁解留侬醉。", "两袖拂飞花，空一春、凄凉憔悴。", "东风误我，满帽洛阳尘，唤飞鸿，遮落日，归去烟霞外。"]'),
('song-ci-666','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','西真姊妹。',102,'宋词/ci.song.5000.json','["西真姊妹。", "只这梅花是。", "乘醉下瑶池，粉燕支、何曾梳洗。", "冰姿素艳，无意压群芳，独自笑，有时愁，一点心难寄。", "雪添蕊佩。", "霜护盈盈泪。", "尘世悔重来，梦凄凉，玉楼十二。", "教些香去，说与惜花人，云黯澹，月朦胧，今夜谁同睡。"]'),
('song-ci-667','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','夜来雨过，桃李将开遍。',102,'宋词/ci.song.5000.json','["夜来雨过，桃李将开遍。", "策杖引儿童，也学人、随莺趁燕。", "青天许大，多少好风光，一岁去，一春来，只恁空扰乱。", "西池琼苑。", "游赏人何限。", "玉勒拥朱轮，各骋些、新欢旧怨。", "都齐醉也，说甚是和非，我笑他，他不觉，花落春风晚。"]'),
('song-ci-668','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','元来尘世。',102,'宋词/ci.song.5000.json','["元来尘世。", "放著希奇事。", "行到路穷时，果别有、真山真水。", "登临任意，随步白云生，三秀草，九花藤，满袖琼瑶蕊。", "何须麴老，浩荡心常醉。", "唱个快活歌，更说甚、黄梁梦里。", "苍颜华发，只是旧时人，不动步，却还家，处处新桃李。"]'),
('song-ci-669','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','东风不住。',102,'宋词/ci.song.5000.json','["东风不住。", "几阵黄梅雨。", "风外晓莺声，怨飘零、花残春暮。", "鸳鸯散后，供了十年愁，怀旧事，想前欢，忍记丁宁语。", "尘昏青镜，休照孤鸾舞。", "烟锁凤楼空，问吹箫、人今何处。", "小窗惊梦，携手似平生，阳台路。", "行云去。", "目断山无数。"]'),
('song-ci-670','蓦山溪','朱敦儒','宋','宋词','song-ci','蓦山溪','[]','西江东去，总是伤时泪。',102,'宋词/ci.song.5000.json','["西江东去，总是伤时泪。", "北陆日初长，对芳尊、多悲少喜。", "美人去后，花落几春风，杯漫洗。", "人难醉。", "愁见飞灰细。", "梅边雪外。", "风味犹相似。", "迤逦暖乾坤，仗君主、雄风英气。", "吾曹老矣，端是有心人、追剑履。", "辞黄绮。", "珍重萧生意。"]'),
('song-ci-671','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','先生馋病老难医。',57,'宋词/ci.song.5000.json','["先生馋病老难医。", "赤米厌晨炊。", "自种畦中白菜，腌成瓮里黄齑。", "肥葱细点，香油慢煼，汤饼如丝。", "早晚一杯无害，神仙九转休痴。"]'),
('song-ci-672','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','先生筇杖是生涯。',57,'宋词/ci.song.5000.json','["先生筇杖是生涯。", "挑月更担花。", "把住都无憎爱，放行总是烟霞。", "飘然携去，旗亭问酒，萧寺寻茶。", "恰似黄鹂无定，不知飞到谁家。"]'),
('song-ci-673','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','当年弹铗五陵间。',57,'宋词/ci.song.5000.json','["当年弹铗五陵间。", "行处万人看。", "雪猎星飞羽箭，春游花簇雕鞍。", "飘零到此，天涯倦客，海上苍颜。", "多谢江南苏小，尊前怪我青衫。"]'),
('song-ci-674','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','东方千骑拟三河。',57,'宋词/ci.song.5000.json','["东方千骑拟三河。", "灯夕试春罗。", "想是蟾宫高会，暂留暮雨姮娥。", "使君燕喜，王孙赋就，桃叶秋波。", "弱柳移来娇舞，落梅换了行歌。"]'),
('song-ci-675','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','闲愁无奈指频弹。',57,'宋词/ci.song.5000.json','["闲愁无奈指频弹。", "芳景为谁残。", "可惜良宵虚过，且容草草谋欢。", "招要楚雨，留连汉佩，多谢青鸾。", "浓艳暗香争暖，罗帷不用遮寒。"]'),
('song-ci-676','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','元宵初过少吹弹。',57,'宋词/ci.song.5000.json','["元宵初过少吹弹。", "楼角彩灯残。", "踏雪闲寻深院，携壶试觅幽欢。", "麻姑暂语，文君未寝，五老双鸾。", "要共梅花同晓，薄罗不奈春寒。"]'),
('song-ci-677','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','夜来听雪晓来看。',57,'宋词/ci.song.5000.json','["夜来听雪晓来看。", "惊失却尘寰。", "摇撼琼林玉树，心疑身是仙官。", "乘风缥缈，凌空径去，不怕高寒。", "却被孤鸿相劝，何如且在人间。"]'),
('song-ci-678','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','新来省悟一生痴。',57,'宋词/ci.song.5000.json','["新来省悟一生痴。", "寻觅上天梯。", "抛失眼前活计，踏翻暗里危机。", "莫言就错，真须悔过，休更迟疑。", "要识天苏阤味，元来只是黄齑。"]'),
('song-ci-679','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','["\u957f\u6c5f"]','登临何处自销忧。',57,'宋词/ci.song.5000.json','["登临何处自销忧。", "直北看扬州。", "朱雀桥边晚市，石头城下新秋。", "昔人何在，悲凉故国，寂寞潮头。", "个是一场春梦，长江不住东流。"]'),
('song-ci-680','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','胸中尘土久无奇。',57,'宋词/ci.song.5000.json','["胸中尘土久无奇。", "今夕借清辉。", "歌纵群英诸彦，舞狂蕙带荷衣。", "鸳鸯湖上，波平岸远，酒酽鱼肥。", "好是中秋圆月，分明天下人知。"]'),
('song-ci-681','朝中措','朱敦儒','宋','宋词','song-ci','朝中措','[]','红稀绿暗掩重门。',57,'宋词/ci.song.5000.json','["红稀绿暗掩重门。", "芳径罢追寻。", "已是老於前岁，那堪穷似他人。", "一杯自劝，江湖倦客，风雨残春。", "不是酴醿相伴，如何过得黄昏。"]'),
('song-ci-682','促拍丑奴儿','朱敦儒','宋','宋词','song-ci','促拍丑奴儿','[]','清露湿幽香。',62,'宋词/ci.song.5000.json','["清露湿幽香。", "想瑶台、无语凄凉。", "飘然欲去，依然如梦，云度银潢。", "又是天风吹澹月，佩丁东、携手西厢。", "泠泠玉磬，沈沈素瑟，舞遍霓裳。"]'),
('song-ci-683','醉落魄・一斛珠','朱敦儒','宋','宋词','song-ci','醉落魄・一斛珠','[]','海山叠翠。',67,'宋词/ci.song.5000.json','["海山叠翠。", "夕阳殷雨云堆雪。", "鹧鸪声里蛮花发。", "我共扁舟，江上两萍叶。", "东风落酒愁难说。", "谁教春梦分胡越。", "碧城芳草应销歇。", "曾识刘郎，惟有半弯月。"]'),
('song-ci-684','醉思仙','朱敦儒','宋','宋词','song-ci','醉思仙','[]','倚晴空。',114,'宋词/ci.song.5000.json','["倚晴空。", "正三洲下叶，七泽收虹。", "叹年光催老，身世飘蓬。", "南歌客，新丰酒，但万里、云水俱东。", "谢故人，解系船访我，脱帽相从。", "人世欢易失，尊俎且更从容。", "任酒倾波碧，烛翦花红。", "君向楚，我归秦，便分路、青竹丹枫。", "恁时节，漫梦凭夜蝶，书倩秋鸿。"]'),
('song-ci-685','感皇恩','朱敦儒','宋','宋词','song-ci','感皇恩','[]','曾醉武陵溪，竹深花好。',81,'宋词/ci.song.5000.json','["曾醉武陵溪，竹深花好。", "玉佩云鬟共春笑。", "主人好事，坐客雨巾风帽。", "日斜青凤舞，金尊倒。", "歌断渭城，月沈星晓。", "海上归来故人少。", "旧游重到。", "但有夕阳衰草。", "恍然真一梦，人空老。"]'),
('song-ci-686','感皇恩','朱敦儒','宋','宋词','song-ci','感皇恩','[]','早起未梳头，小园行遍。',81,'宋词/ci.song.5000.json','["早起未梳头，小园行遍。", "拄杖穿花露犹泫。", "菊篱瓜畹。", "最喜引枝添蔓。", "先生独自笑，流莺见。", "著意访寻，幽香国艳。", "千里移根未为远。", "浅深相间。", "最要四时长看。", "群芳休怪我，归来晚。"]'),
('song-ci-687','感皇恩','朱敦儒','宋','宋词','song-ci','感皇恩','[]','一个小园儿，两三亩地。',81,'宋词/ci.song.5000.json','["一个小园儿，两三亩地。", "花竹随宜旋装缀。", "槿篱茅舍，便有山家风味。", "等闲池上饮，林间醉。", "都为自家，胸中无事。", "风景争来趁游戏。", "称心如意。", "剩活人间几岁。", "洞天谁道在，尘寰外。"]'),
('song-ci-688','杏花天','朱敦儒','宋','宋词','song-ci','杏花天','[]','挂帘等月阑干曲。',65,'宋词/ci.song.5000.json','["挂帘等月阑干曲。", "厌永昼、劳烟倦局。", "单衣汗透鲛绡缩。", "脱帽梳犀枕玉。", "移床就、碧梧翠竹。", "寄语倩、姮娥伴宿。", "轻风澹露清凉足。", "云缀银河断续。"]'),
('song-ci-689','杏花天','朱敦儒','宋','宋词','song-ci','杏花天','[]','听蝉翦叶迎秋燕。',65,'宋词/ci.song.5000.json','["听蝉翦叶迎秋燕。", "画戟散、金铺开遍。", "清风占住秦筝怨。", "楼上衙牌易晚。", "飞雨过、绣幕尽卷。", "借水沈、龙涎旋碾。", "金盆弄水停歌扇。", "凉在冰肌粉面。"]'),
('song-ci-690','杏花天','朱敦儒','宋','宋词','song-ci','杏花天','[]','残春庭院东风晓。',65,'宋词/ci.song.5000.json','["残春庭院东风晓。", "细雨打、鸳鸯寒峭。", "花尖望见秋千了。", "无路踏青斗草。", "人别后、碧云信杳。", "对好景、愁多欢少。", "等他燕子传音耗。", "红杏开也未到。"]'),
('song-ci-691','恋绣衾','朱敦儒','宋','宋词','song-ci','恋绣衾','[]','木落江南感未平。',66,'宋词/ci.song.5000.json','["木落江南感未平。", "雨萧萧、衰鬓到今。", "甚处是长安路，水连空、山锁暮云。", "老人对酒今如此，一番新、残梦暗惊。", "又是洒黄花泪，问明年、此会怎生。"]'),
('song-ci-692','青玉案','朱敦儒','宋','宋词','song-ci','青玉案','[]','芝房并蒂空称瑞。',81,'宋词/ci.song.5000.json','["芝房并蒂空称瑞。", "几曾见、香旎旎。", "也不论兰休比蕙。", "王孙高韵，说得的当，不减唐诸李。", "今朝影落琼杯里。", "共才子佳人斗高致。", "莫道衰翁都无意。", "为他丰韵，为他情味，销得真个醉。"]'),
('song-ci-693','南歌子','朱敦儒','宋','宋词','song-ci','南歌子','[]','住近沈香浦，门前蕙草春。',62,'宋词/ci.song.5000.json','["住近沈香浦，门前蕙草春。", "鸳鸯飞下柘枝新。", "见弄青梅初著、翠罗裙。", "怕唤拈歌扇，嫌催上舞茵。", "几时微步不生尘。", "来作维摩方丈、散花人。"]'),
('song-ci-694','苏幕遮','朱敦儒','宋','宋词','song-ci','苏幕遮','[]','瘦仙人，穷活计。',76,'宋词/ci.song.5000.json','["瘦仙人，穷活计。", "不养丹砂，不肯参同契。", "两顿家餐三觉睡。", "闭著门儿，不管人闲事。", "又经年，知几岁。", "老屋穿空，幸有天遮蔽。", "不饮香醪常似醉。", "白鹤飞来，笑我颠颠地。"]'),
('song-ci-695','苏幕遮','朱敦儒','宋','宋词','song-ci','苏幕遮','[]','酒壶空，歌扇去。',76,'宋词/ci.song.5000.json','["酒壶空，歌扇去。", "独倚危楼，无限伤心处。", "芳草连天云薄暮。", "故国山河，一阵黄梅雨。", "有奇才，无用处。", "壮节飘零，受尽人间苦。", "欲指虚无问征路。", "回首风云，未忍辞明主。"]'),
('song-ci-696','浪淘沙','朱敦儒','宋','宋词','song-ci','浪淘沙','[]','圆月又中秋。',64,'宋词/ci.song.5000.json','["圆月又中秋。", "南海西头。", "蛮云瘴雨晚难收。", "北客相逢弹泪坐，合恨分愁。", "无酒可销忧。", "但说皇州。", "天家宫阙酒家楼。", "今夜只应清汴水，呜咽东流。"]'),
('song-ci-697','浪淘沙','朱敦儒','宋','宋词','song-ci','浪淘沙','[]','风约雨横江。',64,'宋词/ci.song.5000.json','["风约雨横江。", "秋满篷窗。", "个中物色尽凄凉。", "更是行人行未得，独系归艎。", "拥被换残香。", "黄卷堆床。", "开愁展恨翦思量。", "伊是浮云侬是梦，休问家乡。"]'),
('song-ci-698','浪淘沙','朱敦儒','宋','宋词','song-ci','浪淘沙','[]','白菊好开迟。',64,'宋词/ci.song.5000.json','["白菊好开迟。", "冷蝶空迷。", "沾风惹露也随时。", "何事深藏偏在后，天性难移。", "陶令最怜伊。", "同病相医。", "寒枝瘦叶更栽培。", "直待群芳零落后，独殿东篱。"]'),
('song-ci-699','千秋岁','朱敦儒','宋','宋词','song-ci','千秋岁','[]','占秋呈瑞。',87,'宋词/ci.song.5000.json','["占秋呈瑞。", "四海杨公子。", "蹋拖尚带蓬壶体。", "清新春草句，潇洒兰亭字。", "宦情少，眠云弄月知心事。", "此去应无滞。", "稳步烟宵地。", "鹏万里，鹤千岁。", "他年黄阁老，访我清溪醉。", "青凤舞，贻君万斛瑶花蕊。"]'),
('song-ci-700','定风波','朱敦儒','宋','宋词','song-ci','定风波','[]','红药花前欲送春。',74,'宋词/ci.song.5000.json','["红药花前欲送春。", "金鞭柘弹趁芳尘。", "故傍绣帘挼柳线。", "恰见。", "澹梳妆映瘦腰身。", "闲倚金铺书闷字。", "尤殢。", "为谁憔悴减心情。", "放下彩毫匀粉泪。", "弹指。", "你不知人是不知人。"]'),
('song-ci-701','踏莎行','朱敦儒','宋','宋词','song-ci','踏莎行','[]','梅倚江娥，日舒宫线。',68,'宋词/ci.song.5000.json','["梅倚江娥，日舒宫线。", "老人星唤群仙宴。", "泛杯玉友暖飞浮，堆盘金橘光零乱。", "听命宽心，随缘适愿。", "痴狂赢取身长健。", "醉中等看碧桃春，尊前莫问蓬莱浅。"]'),
('song-ci-702','踏莎行','朱敦儒','宋','宋词','song-ci','踏莎行','[]','花涨藤江，草熏鸭步。',68,'宋词/ci.song.5000.json','["花涨藤江，草熏鸭步。", "锦帆兰棹分春去。", "二翁元是一溪云，暂为山北山南雨。", "绿酒多斟，白须休觑。", "飞丹约定烟霞侣。", "与君先占赤城春，回桡早趁桃源路。"]'),
('song-ci-703','梦玉人引','朱敦儒','宋','宋词','song-ci','梦玉人引','[]','浪萍风梗，寄人间，倦为客。',104,'宋词/ci.song.5000.json','["浪萍风梗，寄人间，倦为客。", "梦里瀛洲，姓名误题仙籍。", "敛翅归来，爱小园、蜕箨篔筜碧。", "新种幽花，戒儿童休摘。", "放怀随分，各逍遥，飞鷃等鹏翼。", "舍此萧闲，问君携杖安适。", "诸彦群英，诗酒皆勍敌。", "太平时，向花前，不醉如何休得。"]'),
('song-ci-704','一落索','朱敦儒','宋','宋词','song-ci','一落索','[]','一夜雨声连晓。',56,'宋词/ci.song.5000.json','["一夜雨声连晓。", "青灯相照。", "旧时情绪此时心，花不见、人空老。", "可惜春光闲了。", "阴多晴少。", "江南江北水连云，问何处、寻芳草。"]'),
('song-ci-705','一落索','朱敦儒','宋','宋词','song-ci','一落索','[]','惯被好花留住。',56,'宋词/ci.song.5000.json','["惯被好花留住。", "蝶飞莺语。", "少年场上醉乡中，容易放、春归去。", "今日江南春暮。", "朱颜何处。", "莫将愁绪比飞花，花有数、愁无数。"]'),
('song-ci-706','渔家傲','朱敦儒','宋','宋词','song-ci','渔家傲','[]','谁转琵琶弹侧调。',72,'宋词/ci.song.5000.json','["谁转琵琶弹侧调。", "征尘万里伤怀抱。", "客散黄昏庭院悄。", "灯相照。", "春寒燕子归来早。", "可惜韶光虚过了。", "多情人已非年少。", "只恐莺啼春又老。", "知音少。", "人间何处寻芳草。"]'),
('song-ci-707','渔家傲','朱敦儒','宋','宋词','song-ci','渔家傲','[]','鉴水稽山尘不染。',72,'宋词/ci.song.5000.json','["鉴水稽山尘不染。", "归来贺老身强健。", "有客跨鲸游汗漫。", "留羽扇。", "玉船取酒青鸾劝。", "莫恨飞花容易散。", "仙家风味何曾减。", "春色一壶丹九转。", "堪为伴。", "雕粱幸有轻盈燕。"]'),
('song-ci-708','渔家傲','朱敦儒','宋','宋词','song-ci','渔家傲','[]','畏暑闲寻湖上径。',72,'宋词/ci.song.5000.json','["畏暑闲寻湖上径。", "雨丝断送凉成阵。", "风里芙蓉斜不整。", "沈红影。", "约回萍叶波心静。", "催唤吴姬迎小艇。", "妆花烛焰明相映。", "饮到夜阑人却醒。", "风雨定。", "欲归更把阑干凭。"]'),
('song-ci-709','望江南・忆江南','朱敦儒','宋','宋词','song-ci','望江南・忆江南','[]','炎昼永，初夜月侵床。',64,'宋词/ci.song.5000.json','["炎昼永，初夜月侵床。", "露卧一丛莲叶畔，芙蓉香细水风凉。", "枕上是仙乡。", "浮世事，能有几多长。", "白日明朝依旧在，黄花非晚是重阳。", "不用苦思量。"]'),
('song-ci-710','十二时・忆少年','朱敦儒','宋','宋词','song-ci','十二时・忆少年','[]','连云衰草，连天晚照，连山红叶。',56,'宋词/ci.song.5000.json','["连云衰草，连天晚照，连山红叶。", "西风正摇落，更前溪呜咽。", "燕去鸿归音信绝。", "问黄花、又共谁折。", "征人最愁处，送寒衣时节。"]'),
('song-ci-711','南乡子','朱敦儒','宋','宋词','song-ci','南乡子','[]','宫样细腰身。',66,'宋词/ci.song.5000.json','["宫样细腰身。", "玉带罗衫稳试新。", "小底走来宣对御，催频。", "曲殿西厢小苑门。", "歌舞斗轻盈。", "不许杨花上锦茵。", "劝得君王真个醉，承恩。", "金凤红袍印粉痕。"]'),
('song-ci-712','南乡子','朱敦儒','宋','宋词','song-ci','南乡子','[]','风雪打黄昏。',66,'宋词/ci.song.5000.json','["风雪打黄昏。", "别殿无人早闭门。", "拜了天香罗袖冷，低颦。", "催灭银灯解绣裙。", "金鸭卧残薰。", "看破屏风数泪痕。", "回首昭阳天样远，销魂。", "又过梅花一番春。"]'),
('song-ci-713','行香子','朱敦儒','宋','宋词','song-ci','行香子','[]','宝篆香沈。',84,'宋词/ci.song.5000.json','["宝篆香沈。", "锦瑟尘侵。", "日长时、懒把金针。", "裙腰暗减，眉黛长颦。", "看梅花过，梨花谢，柳花新。", "春寒院落，灯火黄昏。", "悄无言、独自销魂。", "空弹粉泪，难托清尘。", "但楼前望，心中想，梦中寻。"]'),
('song-ci-714','忆帝京','朱敦儒','宋','宋词','song-ci','忆帝京','[]','元来老子曾垂教。',87,'宋词/ci.song.5000.json','["元来老子曾垂教。", "挫锐和光为妙。", "因甚不听他，强要争工巧。", "只为忒惺惺，惹尽闲烦恼。", "你但莫、多愁早老。", "你但且、不分不晓。", "第一随风便倒拖，第二君言亦大好。", "管取没人嫌，便总道、先生俏。"]'),
('song-ci-715','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','飘萧我是孤飞雁。',56,'宋词/ci.song.5000.json','["飘萧我是孤飞雁。", "不共红尘结怨。", "几度蓬莱清浅。", "侧翅曾傍看。", "有时飞入西真院。", "许趁风光流转。", "玉芯绿花开遍。", "可惜无人见。"]'),
('song-ci-716','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','小园雨霁秋光转。',56,'宋词/ci.song.5000.json','["小园雨霁秋光转。", "天气微寒犹暖。", "黄菊红蕉庭院。", "翠径苔痕软。", "眼前明快眉间展。", "细酌霞觞不浅。", "一曲广陵弹遍。", "目送飞鸿远。"]'),
('song-ci-717','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','雨斜风横香成阵。',56,'宋词/ci.song.5000.json','["雨斜风横香成阵。", "春去空留春恨。", "欢少愁多因甚。", "燕子浑难问。", "碧尖蹙损眉慵晕。", "泪湿燕支红沁。", "可惜海棠吹尽。", "又是黄昏近。"]'),
('song-ci-718','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','西楼几日无人到。',56,'宋词/ci.song.5000.json','["西楼几日无人到。", "依旧红围绿绕。", "楼下落花谁扫。", "不见长安道。", "碧云望断无音耗。", "倚遍阑干残照。", "试问泪弹多少。", "湿遍楼前草。"]'),
('song-ci-719','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','谁能留得朱颜住。',56,'宋词/ci.song.5000.json','["谁能留得朱颜住。", "枉了百般辛苦。", "争似萧然无虑。", "任运随缘去。", "人人放著逍遥路。", "只怕君心不悟。", "弹指百年今古。", "有甚成亏处。"]'),
('song-ci-720','桃源忆故人','朱敦儒','宋','宋词','song-ci','桃源忆故人','[]','玉笙吹彻清商后。',56,'宋词/ci.song.5000.json','["玉笙吹彻清商后。", "寂寞弓弯舞袖。", "巧画远山不就。", "只为眉长皱。", "灵犀望断星难透。", "立到凄凉时候。", "今夜月明如昼。", "人共梅花瘦。"]'),
('song-ci-721','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','春雨细如尘，楼外柳丝黄湿。',53,'宋词/ci.song.5000.json','["春雨细如尘，楼外柳丝黄湿。", "风约绣帘斜去，透窗纱寒碧。", "美人慵翦上元灯，弹泪倚瑶瑟。", "却上紫姑香火，问辽东消息。"]'),
('song-ci-722','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','春雨挠元宵，花绽柳眠无力。',53,'宋词/ci.song.5000.json','["春雨挠元宵，花绽柳眠无力。", "风峭画堂帘幕，卷金泥红湿。", "王孙开宴聚娇饶，越山洗愁碧。", "休说凤凰城里，少年时踪迹。"]'),
('song-ci-723','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','惊见老仙来，触目琳琅奇绝。',53,'宋词/ci.song.5000.json','["惊见老仙来，触目琳琅奇绝。", "打酒道人林下，奏醉翁三叠。", "接䍦倾倒海云飞，物色又催别。", "回棹晚江春雨，胜剡溪风雪。"]'),
('song-ci-724','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','春去尚堪寻，莫恨老来难却。',53,'宋词/ci.song.5000.json','["春去尚堪寻，莫恨老来难却。", "且趁禁烟百七，醉残英馀萼。", "坐间玉润赋妍辞，情语见真乐。", "引满瘿杯竹盏，胜黄金凿落。"]'),
('song-ci-725','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','摇首出红尘，醒醉更无时节。',53,'宋词/ci.song.5000.json','["摇首出红尘，醒醉更无时节。", "活计绿蓑青笠，惯披霜冲雪。", "晚来风定钓丝闲，上下是新月。", "千里水天一色，看孤鸿明灭。"]'),
('song-ci-726','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','眼里数闲人，只有钓翁潇洒。',53,'宋词/ci.song.5000.json','["眼里数闲人，只有钓翁潇洒。", "已佩水仙宫印，恶风波不怕。", "此心那许世人知，名姓是虚假。", "一棹五湖三岛，任船儿尖耍。"]'),
('song-ci-727','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','渔父长身来，只共钓竿相识。',53,'宋词/ci.song.5000.json','["渔父长身来，只共钓竿相识。", "随意转船回棹，似飞空无迹。", "芦花开落任浮生，长醉是良策。", "昨夜一江风雨，都不曾听得。"]'),
('song-ci-728','好事近','朱敦儒','宋','宋词','song-ci','好事近','["\u6d1e\u5ead\u6e56"]','拨转钓鱼船，江海尽为吾宅。',53,'宋词/ci.song.5000.json','["拨转钓鱼船，江海尽为吾宅。", "恰向洞庭沽酒，却钱塘横笛。", "醉颜禁冷更添红，潮落下前碛。", "经过子陵滩畔，得梅花消息。"]'),
('song-ci-729','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','短棹钓船轻，江上晚烟笼碧。',53,'宋词/ci.song.5000.json','["短棹钓船轻，江上晚烟笼碧。", "塞雁海鸥分路，占江天秋色。", "锦鳞拨刺满蓝鱼，取酒价相敌。", "风顺片帆归去，有何人留得。"]'),
('song-ci-730','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','猛向这边来，得个信音端的。',53,'宋词/ci.song.5000.json','["猛向这边来，得个信音端的。", "天与一轮钓线，领烟波千亿。", "红尘今古转船头，鸥鹭已陈迹。", "不受世间拘束，任东西南北。"]'),
('song-ci-731','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','绿泛一瓯云，留住欲飞胡蝶。',53,'宋词/ci.song.5000.json','["绿泛一瓯云，留住欲飞胡蝶。", "相对夜深花下，洗萧萧风月。", "从容言笑醉还醒，争忍便轻别。", "只愿主人留客，更重斟金叶。"]'),
('song-ci-732','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','失却故山云，索手指空为客。',53,'宋词/ci.song.5000.json','["失却故山云，索手指空为客。", "莼菜鲈鱼留我，住鸳鸯湖侧。", "偶然添酒旧壶卢，小醉度朝夕。", "吹笛月波楼下，有何人相识。"]'),
('song-ci-733','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','深住小溪春，好在柳枝桃叶。',53,'宋词/ci.song.5000.json','["深住小溪春，好在柳枝桃叶。", "风澹水轩人静，数双飞胡蝶。", "日长时有一莺啼，兰佩为谁结。", "销散旧愁新恨，泛琴心三叠。"]'),
('song-ci-734','好事近','朱敦儒','宋','宋词','song-ci','好事近','[]','我不是神仙，不会炼丹烧药。',53,'宋词/ci.song.5000.json','["我不是神仙，不会炼丹烧药。", "只是爱闲耽酒，畏浮名拘缚。", "种成桃李一园花，真处怕人觉。", "受用现前活计，且行歌行乐。"]'),
('song-ci-735','长相思','朱敦儒','宋','宋词','song-ci','长相思','[]','昨日晴。',44,'宋词/ci.song.5000.json','["昨日晴。", "今日阴。", "楼下飞花楼上云。", "阑干双泪痕。", "江南人。", "江北人。", "一样春风两样情。", "晚寒潮未平。"]'),
('song-ci-736','长相思','朱敦儒','宋','宋词','song-ci','长相思','[]','海云黄。',44,'宋词/ci.song.5000.json','["海云黄。", "橘洲霜。", "如箭滩流石似羊。", "溪船十丈长。", "人难量。", "水难量。", "过险方知著甚忙。", "归休老醉乡。"]'),
('song-ci-737','乌夜啼','朱敦儒','宋','宋词','song-ci','乌夜啼','[]','翦胜迎春后，和风入律频催。',55,'宋词/ci.song.5000.json','["翦胜迎春后，和风入律频催。", "前回下叶飞霜处，红绽一枝梅。", "正遇时调玉烛，须添酒满金杯。", "寻芳伴侣休闲过，排日有花开。"]'),
('song-ci-738','沙塞子','朱敦儒','宋','宋词','song-ci','沙塞子','[]','万里飘零南越，山引泪、酒添愁。',52,'宋词/ci.song.5000.json','["万里飘零南越，山引泪、酒添愁。", "不见凤楼龙阙、又惊秋。", "九日江亭闲望，蛮树绕，瘴云浮。", "肠断红蕉花晚、水西流。"]'),
('song-ci-739','沙塞子','朱敦儒','宋','宋词','song-ci','沙塞子','[]','蛮径寻春春早，千点雪，已飞梅。',52,'宋词/ci.song.5000.json','["蛮径寻春春早，千点雪，已飞梅。", "席地插花传酒、日西催。", "莫作楚囚相泣，倾银汉，洗瑶池。", "看尽人间桃李、拂衣归。"]'),
('song-ci-740','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','澹澹薰风庭院，青青过雨园林。',58,'宋词/ci.song.5000.json','["澹澹薰风庭院，青青过雨园林。", "铜驼陌上旧莺声。", "今日江边重听。", "落帽酒中有趣，题桥琴里无心。", "香残沈水缕烟轻。", "花影阑干人静。"]'),
('song-ci-741','西江月','朱敦儒','宋','宋词','song-ci','西江月','["\u6d1e\u5ead\u6e56"]','琴上金星正照，砚中鸖眼相青。',58,'宋词/ci.song.5000.json','["琴上金星正照，砚中鸖眼相青。", "闲来自觉有精神。", "心海风恬浪静。", "且喜面前花好，更听林外莺新。", "瓮头清辣洞庭春。", "醉里徐行路稳。"]'),
('song-ci-742','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','元是西都散汉，江南今日衰翁。',58,'宋词/ci.song.5000.json','["元是西都散汉，江南今日衰翁。", "从来颠怪更心风。", "做尽百般无用。", "屈指八旬将到，回头万事皆空。", "云间鸿雁草间虫。", "共我一般做梦。"]'),
('song-ci-743','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','穷后常如囚系，老来半似心风。',58,'宋词/ci.song.5000.json','["穷后常如囚系，老来半似心风。", "饥蚊饿蚤不相容。", "一夜何曾做梦。", "被我不扇不捉，廓然总是虚空。", "寺钟官角任西东。", "别弄些儿骨董。"]'),
('song-ci-744','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','世事短如春梦，人情薄似秋云。',58,'宋词/ci.song.5000.json','["世事短如春梦，人情薄似秋云。", "不须计较苦劳心。", "万事原来有命。", "幸遇三杯酒好，况逢一朵花新。", "片时欢笑且相亲。", "明日阴晴未定。"]'),
('song-ci-745','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','日日深杯酒满，朝朝小圃花开。',58,'宋词/ci.song.5000.json','["日日深杯酒满，朝朝小圃花开。", "自歌自舞自开怀。", "且喜无拘无碍。", "青史几番春梦，黄泉多少奇才。", "不须计较与安排。", "领取而今现在。"]'),
('song-ci-746','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','正月天饶阴雨，江南寒在晨朝。',58,'宋词/ci.song.5000.json','["正月天饶阴雨，江南寒在晨朝。", "娇莺声袅杏花梢。", "暗澹绿窗春晓。", "好梦空留被在，新愁不共香销。", "小楼帘卷路迢迢。", "望断天涯芳草。"]'),
('song-ci-747','西江月','朱敦儒','宋','宋词','song-ci','西江月','[]','织素休寻往恨，攀条幸有前缘。',58,'宋词/ci.song.5000.json','["织素休寻往恨，攀条幸有前缘。", "隔河彼此事经年。", "且说蓬莱清浅。", "障面重新团扇，倾鬟再整花钿。", "歌云舞雪画堂前。", "长共阿郎相见。"]'),
('song-ci-748','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','挼花弄扇。',52,'宋词/ci.song.5000.json','["挼花弄扇。", "碧斗遥山眉黛晚。", "白玉阑干。", "倚遍春风翠袖寒。", "难寻可见。", "何似一双青翅燕。", "人瘦春残。", "芳草连云日下山。"]'),
('song-ci-749','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','寻花携李。',52,'宋词/ci.song.5000.json','["寻花携李。", "红漾轻舟汀柳外。", "小簇春山。", "溪雨岩云不饱帆。", "相逢心醉。", "容易堆盘银烛泪。", "痛饮何言。", "犀箸敲残玉酒船。"]'),
('song-ci-750','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','东风桃李。',52,'宋词/ci.song.5000.json','["东风桃李。", "春水绿波花影外。", "载酒胥山。", "祓禊相期落锦帆。", "吾曹一醉。", "却笑新亭人有泪。", "相对清言。", "不觉黄昏雨打船。"]'),
('song-ci-751','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','闲人行李。',52,'宋词/ci.song.5000.json','["闲人行李。", "羽扇芒鞋尘世外。", "一叠溪山。", "也解分风送客帆。", "时平易醉。", "无复惊心并溅泪。", "长揖忘言。", "回棹桃花插满船。"]'),
('song-ci-752','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','刘郎已老。',52,'宋词/ci.song.5000.json','["刘郎已老。", "不管桃花依旧笑。", "要听琵琶。", "重院莺啼觅谢家。", "曲终人醉。", "多似浔阳江上泪。", "万里东风。", "国破山河落照红。"]'),
('song-ci-753','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','慵歌怕酒。',52,'宋词/ci.song.5000.json','["慵歌怕酒。", "今日春衫惊著瘦。", "双燕帘栊。", "金鸭香沈客泪中。", "琵琶重听。", "谁信人间多少恨。", "落日东风。", "吹得桃花满院红。"]'),
('song-ci-754','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','古人误我。',52,'宋词/ci.song.5000.json','["古人误我。", "独舞西风双泪堕。", "鹤去无踪。", "木落西陵返照红。", "人间难住。", "掷下酒杯何处去。", "楼锁钟残。", "山北山南两点烟。"]'),
('song-ci-755','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','无知老子。',52,'宋词/ci.song.5000.json','["无知老子。", "元住渔舟樵舍里。", "暂借权监。", "持节纡朱我甚惭。", "不能者止。", "免苦龟肠忧虎尾。", "身退心闲。", "剩向人间活几年。"]'),
('song-ci-756','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','斫鱼作鮓。',52,'宋词/ci.song.5000.json','["斫鱼作鮓。", "酒面打开香可醡。", "相唤同来。", "草草杯盘饮几杯。", "人生虚假。", "昨日梅花今日谢。", "不醉何为。", "从古英雄总是痴。"]'),
('song-ci-757','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','今年梅晚。',52,'宋词/ci.song.5000.json','["今年梅晚。", "懒趁寿阳钗上燕。", "月唤霜催。", "不肯人间取次开。", "低鬟掩袂。", "愁寄玉阑金井外。", "粉瘦香寒。", "独抱深心一点酸。"]'),
('song-ci-758','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','无人惜我。',52,'宋词/ci.song.5000.json','["无人惜我。", "我自殷勤怜这个。", "恧峭惺惺。", "不肯随人独自行。", "乾坤许大。", "只在棘针尖上坐。", "依旧多情。", "搂著虚空睡到明。"]'),
('song-ci-759','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','年衰人老。',52,'宋词/ci.song.5000.json','["年衰人老。", "矍铄支离君莫笑。", "白日青天。", "我自心情胜少年。", "超凡入妙。", "游戏神通随意到。", "酒圣诗仙。", "舞棹虚空驾铁船。"]'),
('song-ci-760','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','虚空无碍。',52,'宋词/ci.song.5000.json','["虚空无碍。", "你自痴迷不自在。", "撒手游行。", "到处笙歌拥路迎。", "天然美满。", "不用些儿心计算。", "莫听先生。", "引入深山百丈坑。"]'),
('song-ci-761','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','无人请我。',52,'宋词/ci.song.5000.json','["无人请我。", "我自铺毡松下坐。", "酌酒栽诗。", "调弄梅花作侍儿。", "心欢易醉。", "明月飞来花下睡。", "醉舞谁知。", "花满纱巾月满怀。"]'),
('song-ci-762','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','["\u94b1\u5858\u6c5f"]','花随人去。',52,'宋词/ci.song.5000.json','["花随人去。", "今夜钱塘江上雨。", "宿酒残更。", "潮过西窗不肯明。", "小罗金缕。", "结尽同心留不住。", "何处长亭。", "绣被春寒掩翠屏。"]'),
('song-ci-763','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','有何不可。',52,'宋词/ci.song.5000.json','["有何不可。", "依旧一枚闲底我。", "饭饱茶香。", "瞌睡之时便上床。", "百般经过。", "且喜青鞋踏不破。", "小院低窗。", "桃李花开春昼长。"]'),
('song-ci-764','减字木兰花','朱敦儒','宋','宋词','song-ci','减字木兰花','[]','江南春水。',52,'宋词/ci.song.5000.json','["江南春水。", "罗幕黄昏寒未退。", "好个相知。", "唱到姮娥敛黛眉。", "夜阑人醉。", "风露无情花有泪。", "画角残时。", "一片参旗红杏西。"]'),
('song-ci-765','点绛唇','朱敦儒','宋','宋词','song-ci','点绛唇','[]','淮海秋风，冶城飞下扬州叶。',50,'宋词/ci.song.5000.json','["淮海秋风，冶城飞下扬州叶。", "画船催发。", "倾酒留君别。", "卧倒金壶，相对天涯客。", "阳关彻。", "大江横绝。", "泪湿杯中月。"]'),
('song-ci-766','点绛唇','朱敦儒','宋','宋词','song-ci','点绛唇','[]','客梦初回，卧听吴语开帆索。',50,'宋词/ci.song.5000.json','["客梦初回，卧听吴语开帆索。", "护霜云薄。", "澹澹芙蓉落。", "画舫无情，人去天涯角。", "思量著。", "翠蝉金雀。", "别后新梳掠。"]'),
('song-ci-767','点绛唇','朱敦儒','宋','宋词','song-ci','点绛唇','[]','至日春云，万般祥瑞朝来奏。',50,'宋词/ci.song.5000.json','["至日春云，万般祥瑞朝来奏。", "太平时候。", "乐事家家有。", "玉指呵寒，酥点梅花瘦。", "金杯酒。", "与君为寿。", "只愿人长久。"]'),
('song-ci-768','点绛唇','朱敦儒','宋','宋词','song-ci','点绛唇','[]','春雨春风，问谁染就江南草。',50,'宋词/ci.song.5000.json','["春雨春风，问谁染就江南草。", "燕娇莺巧。", "只是参军老。", "今古红尘，愁了人多少。", "尊前好。", "缓歌低笑。", "醉向花间倒。"]'),
('song-ci-769','点绛唇','朱敦儒','宋','宋词','song-ci','点绛唇','[]','缘径朱阑，暖烟晴日春来早。',50,'宋词/ci.song.5000.json','["缘径朱阑，暖烟晴日春来早。", "自家亭沼。", "不问人寻讨。", "携酒提篮，儿女相随到。", "风光好。", "醉敧纱帽。", "索共梅花笑。"]'),
('song-ci-770','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','狂踪怪迹。',61,'宋词/ci.song.5000.json','["狂踪怪迹。", "谁料年老，天涯为客。", "帆展霜风，船随江月，山寒波碧。", "如今著处添愁，怎忍看、参西雁北。", "洛浦莺花，伊川云水，何时归得。"]'),
('song-ci-771','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','松江胜集。',61,'宋词/ci.song.5000.json','["松江胜集。", "中秋载酒，幽人闲客。", "云将迟疑，桂娥羞涩，一欢难得。", "天怜我辈凄凉，借万里、晴空湛碧。", "浩浩烟波，堂堂风月，今夕何夕。"]'),
('song-ci-772','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','红分翠别。',61,'宋词/ci.song.5000.json','["红分翠别。", "宿酒半醒，征鞍将发。", "楼外残钟，帐前残烛，窗边残月。", "想伊绣枕无眠，记行客、如今去也。", "心下难拚，眼前难觅，口头难说。"]'),
('song-ci-773','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','梅蒸乍热。',61,'宋词/ci.song.5000.json','["梅蒸乍热。", "无处散策，芳菲初歇。", "席展凉莞，帐垂黄草，天然奇绝。", "披襟永昼清风，更荐枕、良宵皓月。", "一梦游仙，软云推倒，广寒宫阙。"]'),
('song-ci-774','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','秋光正洁。',61,'宋词/ci.song.5000.json','["秋光正洁。", "仙家瑞草，黄花初发。", "物外高情，天然雅致，清标偏别。", "仙翁笑酌金杯，庆儿女、团圆喜悦。", "嫁与萧郎，凤凰台上，长生风月。"]'),
('song-ci-775','柳梢青','朱敦儒','宋','宋词','song-ci','柳梢青','[]','水云晚照。',61,'宋词/ci.song.5000.json','["水云晚照。", "浮生了了，霜风衰草。", "日月金梭，江山春梦，天多人少。", "赤松认得虚空，便一向、飞腾缥缈。", "直上蓬瀛，回看沧海，凄然长啸。"]'),
('song-ci-776','采桑子','朱敦儒','宋','宋词','song-ci','采桑子','[]','扁舟去作江南客，旅雁孤云。',52,'宋词/ci.song.5000.json','["扁舟去作江南客，旅雁孤云。", "万里烟尘。", "回首中原泪满巾。", "碧山对晚汀洲冷，枫叶芦根。", "日落波平。", "愁损辞乡去国人。"]'),
('song-ci-777','采桑子','朱敦儒','宋','宋词','song-ci','采桑子','[]','天高风劲尘寰静，佳节重阳。',52,'宋词/ci.song.5000.json','["天高风劲尘寰静，佳节重阳。", "叶下潇湘。", "碧海晴空一陈霜。", "安排弦管倾芳酝，报答秋光。", "昼短歌长。", "红烛黄花夜未央。"]'),
('song-ci-778','采桑子','朱敦儒','宋','宋词','song-ci','采桑子','[]','一番海角凄凉梦，却到长安。',52,'宋词/ci.song.5000.json','["一番海角凄凉梦，却到长安。", "翠帐犀帘。", "依旧屏斜十二山。", "玉人为我调琴瑟，颦黛低鬟。", "云散香残。", "风雨蛮溪半夜寒。"]'),
('song-ci-779','忆秦娥','朱敦儒','宋','宋词','song-ci','忆秦娥','[]','西江碧。',56,'宋词/ci.song.5000.json','["西江碧。", "江亭夜燕天涯客。", "天涯客。", "一杯相属，此夕何夕。", "烛残花冷歌声急。", "秦关汉苑无消息。", "无消息。", "戍楼吹角，故人难得。"]'),
('song-ci-780','忆秦娥','朱敦儒','宋','宋词','song-ci','忆秦娥','[]','霜风急。',56,'宋词/ci.song.5000.json','["霜风急。", "江南路上梅花白。", "梅花白。", "寒溪残月，冷村深雪。", "洛阳醉里曾同摘。", "水西竹外常相忆。", "常相忆。", "宝钗双凤，鬓边春色。"]'),
('song-ci-781','忆秦娥','朱敦儒','宋','宋词','song-ci','忆秦娥','[]','吴船窄。',56,'宋词/ci.song.5000.json','["吴船窄。", "吴江岸下长安客。", "长安客。", "惊尘心绪，转蓬踪迹。", "征鸿也是关河隔。", "孤飞万里谁相识。", "谁相识。", "三更月落，斗横西北。"]'),
('song-ci-782','忆秦娥','朱敦儒','宋','宋词','song-ci','忆秦娥','[]','歌锺列。',56,'宋词/ci.song.5000.json','["歌锺列。", "公堂盛会酬佳节。", "酬佳节。", "皇恩宣布，早梅争发。", "舞场椎鼓催回雪。", "金壶镟酒琼酥热。", "琼酥热。", "今朝不饮，几时欢悦。"]'),
('song-ci-783','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','江上见新年，年夜听春雨。',52,'宋词/ci.song.5000.json','["江上见新年，年夜听春雨。", "有个人人领略春，粉澹红轻注。", "深劝玉东西，低唱黄金缕。", "拈底梅花总是愁，酒尽人归去。"]'),
('song-ci-784','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','陌上雪销初，才得江梅信。',52,'宋词/ci.song.5000.json','["陌上雪销初，才得江梅信。", "翦彩盘金院落香，便觉烧灯近。", "乐事眼前多，春酒今年胜。", "好趁迎梅接柳时，满引金杯饮。"]'),
('song-ci-785','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','碧瓦小红楼，芳草江南岸。',52,'宋词/ci.song.5000.json','["碧瓦小红楼，芳草江南岸。", "雨后纱窗几阵寒，零落梨花晚。", "看到水如云，送尽鸦成点。", "南北东西处处愁，独倚阑干遍。"]'),
('song-ci-786','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','古涧一枝梅，免被园林锁。',52,'宋词/ci.song.5000.json','["古涧一枝梅，免被园林锁。", "路远山深不怕寒，似共春相趓。", "幽思有谁知，托契都难可。", "独自风流独自香，明月来寻我。"]'),
('song-ci-787','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','灼灼一枝桃，粉艳天然好。',52,'宋词/ci.song.5000.json','["灼灼一枝桃，粉艳天然好。", "只被春风摆撼多，颜色凋零早。", "结子未为迟，悔恨随芳草。", "不下山来不出溪，待守刘郎老。"]'),
('song-ci-788','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','旅雁向南飞，风雨群初失。',52,'宋词/ci.song.5000.json','["旅雁向南飞，风雨群初失。", "饥渴辛勤两翅垂，独下寒汀立。", "鸥鹭苦难亲，矰缴忧相逼。", "云海茫茫无处归，谁听哀鸣急。"]'),
('song-ci-789','卜算子','朱敦儒','宋','宋词','song-ci','卜算子','[]','山晓鹧鸪啼，云暗泷州路。',52,'宋词/ci.song.5000.json','["山晓鹧鸪啼，云暗泷州路。", "榕叶阴浓荔子青，百尺桄榔树。", "尽日不逢人，猛地风吹雨。", "惨黯蛮溪鬼峒寒，隐隐闻铜鼓。"]'),
('song-ci-790','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','乱红深翠。',54,'宋词/ci.song.5000.json','["乱红深翠。", "楼阁春风外。", "胡蝶成团飞照水。", "睡鸭无人惊起。", "身闲更觉身轻。", "酒壶歌扇随行。", "芳草绿杨堤畔，一声初听啼莺。"]'),
('song-ci-791','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','人间花少。',54,'宋词/ci.song.5000.json','["人间花少。", "菊小芙蓉老。", "冷澹仙人偏得道。", "买定西风一笑。", "前身原是疏梅。", "黄姑点碎冰肌。", "惟有暗香长在，饱参清露霏微。"]'),
('song-ci-792','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','相留不住。',54,'宋词/ci.song.5000.json','["相留不住。", "又趁东风去。", "楼外夕阳芳草路。", "今夜短亭何处。", "杏花斜压阑干。", "朱帘不卷春寒。", "惆怅黄昏前后，离愁酒病厌厌。"]'),
('song-ci-793','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','多寒易雨。',54,'宋词/ci.song.5000.json','["多寒易雨。", "春事都相误。", "愁过黄昏无著处。", "宝篆烧残香缕。", "低鬟暗摘明珰。", "罗巾挹损残妆。", "檐外几声风玉，丁东敲断人肠。"]'),
('song-ci-794','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','春寒雨妥。',54,'宋词/ci.song.5000.json','["春寒雨妥。", "花萼红难破。", "绣线金针慵不作。", "要见秋千无那。", "西邻姊妹丁宁。", "寻芳更约清明。", "画个丙丁帖子，前阶后院求晴。"]'),
('song-ci-795','清平乐','朱敦儒','宋','宋词','song-ci','清平乐','[]','当初相见。',54,'宋词/ci.song.5000.json','["当初相见。", "君恨相逢晚。", "一曲秦筝弹未遍。", "无奈昭阳人怨。", "便教恩浅情疏。", "隔花空望金舆。", "春晚不拈红粉，碧窗自录仙书。"]'),
('song-ci-796','昭君怨','朱敦儒','宋','宋词','song-ci','昭君怨','[]','胧月黄昏亭榭。',48,'宋词/ci.song.5000.json','["胧月黄昏亭榭。", "池上秋千初架。", "燕子说春寒。", "杏花残。", "泪断愁肠难断。", "往事总成幽怨。", "幽怨几时休。", "泪还流。"]'),
('song-ci-797','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','折桂归来懒觅官。',48,'宋词/ci.song.5000.json','["折桂归来懒觅官。", "十年风月醉家山。", "有人挟瑟伴清闲。", "楚畹飞香兰结佩，蓝田生暖玉连环。", "拥书万卷看双鸾。"]'),
('song-ci-798','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','西塞山边白鹭飞。',48,'宋词/ci.song.5000.json','["西塞山边白鹭飞。", "吴兴江上绿杨低。", "桃花流水鳜鱼肥。", "青箬笠将风里戴，短蓑衣向雨中披。", "斜风细雨不须归。"]'),
('song-ci-799','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','银海清泉洗玉杯。',48,'宋词/ci.song.5000.json','["银海清泉洗玉杯。", "恰篘白酒冷偏宜。", "水林檎嫩折青枝。", "争看使君长寿曲，旋教法部太平词。", "快风凉雨火云摧。"]'),
('song-ci-800','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','碧玉栏干白玉人。',48,'宋词/ci.song.5000.json','["碧玉栏干白玉人。", "倚花吹叶忍黄昏。", "萧郎一去又经春。", "眉澹翠峰愁易聚，脸残红雨泪难匀。", "纤腰减半绿罗裙。"]'),
('song-ci-801','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','雨湿清明香火残。',48,'宋词/ci.song.5000.json','["雨湿清明香火残。", "碧溪桥外燕泥寒。", "日长独自倚阑干。", "脱箨修篁初散绿，褪花新杏未成酸。", "江南春好与谁看。"]'),
('song-ci-802','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','风落芙蓉画扇闲。',48,'宋词/ci.song.5000.json','["风落芙蓉画扇闲。", "凉随春色到人间。", "乍垂罗幕乍飞鸾。", "好把深杯添绿酒，休拈明镜照苍颜。", "浮生难得是清欢。"]'),
('song-ci-803','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','才子佳人相见难。',48,'宋词/ci.song.5000.json','["才子佳人相见难。", "舞收歌罢又更阑。", "密将春恨系幽欢。", "结子同心香佩带，帕儿双字玉连环。", "酒醒灯暗忍重看。"]'),
('song-ci-804','浣溪沙','朱敦儒','宋','宋词','song-ci','浣溪沙','[]','晚菊花前敛翠蛾。',48,'宋词/ci.song.5000.json','["晚菊花前敛翠蛾。", "采花传酒缓声歌。", "柳枝团扇别离多。", "拥髻凄凉论旧事，曾随织女度银梭。", "当年今夕奈愁何。"]'),
('song-ci-805','阮郎归','朱敦儒','宋','宋词','song-ci','阮郎归','[]','柳花陌上拈明珰。',56,'宋词/ci.song.5000.json','["柳花陌上拈明珰。", "娇红新样妆。", "匆匆曾贮一襟香。", "月痕金缕凉。", "分泪扇，掩离觞。", "春残人断肠。", "锦书难寄雁飞忙。", "池塘芳草长。"]'),
('song-ci-806','生查子','朱敦儒','宋','宋词','song-ci','生查子','[]','卧病独眠人，无月中秋节。',48,'宋词/ci.song.5000.json','["卧病独眠人，无月中秋节。", "澹照碧纱灯，冷看银屏雪。", "风露转萧寒，砧杵添凄切。", "伏枕漫书空，到晓愁难说。"]'),
('song-ci-807','眼儿媚','朱敦儒','宋','宋词','song-ci','眼儿媚','[]','青锦成帏瑞香浓。',58,'宋词/ci.song.5000.json','["青锦成帏瑞香浓。", "雅称小帘栊。", "主人好事，金杯留客，共倚春风。", "不知因甚来尘世，香似旧曾逢。", "江梅退步，幽兰偷眼，回避芳丛。"]'),
('song-ci-808','眼儿媚','朱敦儒','宋','宋词','song-ci','眼儿媚','[]','叠翠阑红斗纤浓。',58,'宋词/ci.song.5000.json','["叠翠阑红斗纤浓。", "云雨绮为栊。", "只忧谢了，偏须著意，障雨遮风。", "瑞云香雾虽难觅，蓦地有时逢。", "不妨守定，从他人笑，老入花丛。"]'),
('song-ci-809','眼儿媚','朱敦儒','宋','宋词','song-ci','眼儿媚','[]','紫帔红襟艳争浓。',58,'宋词/ci.song.5000.json','["紫帔红襟艳争浓。", "光彩烁疏栊。", "香为小字，瑞为高姓，道骨仙风。", "此花合向瑶池种，可惜未遭逢。", "阿环见了，羞回眼尾，愁聚眉丛。"]'),
('song-ci-810','诉衷情','朱敦儒','宋','宋词','song-ci','诉衷情','[]','青垂柳线水平池。',54,'宋词/ci.song.5000.json','["青垂柳线水平池。", "芳径燕初飞。", "日长事少人静，山茧换单衣。", "箫鼓远，篆香迟。", "卷帘低。", "半床花影，一枕松风，午醉醒时。"]'),
('song-ci-811','诉衷情','朱敦儒','宋','宋词','song-ci','诉衷情','[]','老人无复少年欢。',54,'宋词/ci.song.5000.json','["老人无复少年欢。", "嫌酒倦吹弹。", "黄昏又是风雨，楼外角声残。", "悲故国，念尘寰。", "事难言。", "下了纸帐，曳上青毡，一任霜寒。"]'),
('song-ci-812','诉衷情','朱敦儒','宋','宋词','song-ci','诉衷情','[]','青旗彩胜又迎春。',54,'宋词/ci.song.5000.json','["青旗彩胜又迎春。", "暖律应祥云。", "金盘内家生菜，宫院遍承恩。", "时节好，管弦新。", "度升平。", "惠风迟日，柳眼梅心，任醉芳尊。"]'),
('song-ci-813','诉衷情','朱敦儒','宋','宋词','song-ci','诉衷情','[]','月中玉兔日中鸦。',54,'宋词/ci.song.5000.json','["月中玉兔日中鸦。", "随我度年华。", "不管寒暄风雨，饱饭热煎茶。", "居士竹，故侯瓜。", "老生涯。", "自然天地，本分云山，到处为家。"]'),
('song-ci-814','菩萨蛮','朱敦儒','宋','宋词','song-ci','菩萨蛮','[]','老人谙尽人间苦。',52,'宋词/ci.song.5000.json','["老人谙尽人间苦。", "近来恰似心头悟。", "九九是重阳。", "重阳菊散芳。", "出门何处去。", "对面谁相语。", "枕臂卧南窗。", "铜炉柏子香。"]'),
('song-ci-815','菩萨蛮','朱敦儒','宋','宋词','song-ci','菩萨蛮','[]','芭蕉叶上秋风碧。',52,'宋词/ci.song.5000.json','["芭蕉叶上秋风碧。", "晚来小雨流苏湿。", "新窨木樨沈。", "香迟斗帐深。", "无人同向夕。", "还是愁成忆。", "忆昔结同心。", "鸳鸯何处寻。"]'),
('song-ci-816','菩萨蛮','朱敦儒','宋','宋词','song-ci','菩萨蛮','[]','风流才子倾城色。',52,'宋词/ci.song.5000.json','["风流才子倾城色。", "红缨翠幰长安陌。", "夜饮小平康。", "暖生银字簧。", "持杯留上客。", "私语眉峰侧。", "半冷水沈香。", "罗帷宫漏长。"]'),
('song-ci-817','菩萨蛮','朱敦儒','宋','宋词','song-ci','菩萨蛮','[]','乡关散尽当年客。',52,'宋词/ci.song.5000.json','["乡关散尽当年客。", "春风寂寞花无色。", "长日掩重门。", "江山眼外昏。", "画图高挂壁。", "嵩少参差碧。", "想见卧云人。", "松黄落洞门。"]'),
('song-ci-818','菩萨蛮','朱敦儒','宋','宋词','song-ci','菩萨蛮','[]','芙蓉红落秋风急。',52,'宋词/ci.song.5000.json','["芙蓉红落秋风急。", "夜寒纸帐霜华湿。", "枕畔木瓜香。", "晓来清兴长。", "轻舟青箬笠。", "短棹溪光碧。", "去觅谢三郎。", "芦花何处藏。"]'),
('song-ci-819','双','朱敦儒','宋','宋词','song-ci','双','[]','拂破秋江烟碧。',56,'宋词/ci.song.5000.json','["拂破秋江烟碧。", "一对双飞鸂鶒。", "应是远来无力。", "捎下相偎沙碛。", "小艇谁吹横笛。", "惊起不知消息。", "悔不当时描得。", "如今何处寻觅。"]'),
('song-ci-820','鼓笛令','朱敦儒','宋','宋词','song-ci','鼓笛令','[]','纸帐绸衾忒暖。',66,'宋词/ci.song.5000.json','["纸帐绸衾忒暖。", "尽自由、横翻倒转。", "睡觉西窗灯一盏。", "恰听打、三更三点。", "残梦不须深念。", "这些个、光阴煞短。", "解散缰绳休系绊。", "把从前、一笔句断。"]'),
('song-ci-821','西湖曲・玉楼春','朱敦儒','宋','宋词','song-ci','西湖曲・玉楼春','[]','今冬寒早风光好。',64,'宋词/ci.song.5000.json','["今冬寒早风光好。", "休怪搀先敧絮帽。", "蟹肥一个可称斤，酒美三杯真合道。", "年年闲梦垂垂了。", "且喜风松吹不倒。", "平分两月是新春，却共梅花依旧笑。"]'),
('song-ci-822','风蝶令・南歌子','朱敦儒','宋','宋词','song-ci','风蝶令・南歌子','[]','试看何时有，元来总是空。',62,'宋词/ci.song.5000.json','["试看何时有，元来总是空。", "丹砂只在酒杯中。", "看取乃公双颊、照人红。", "花外庄周蝶，松间御寇风。", "古人漫尔说西东。", "何似自家识取、卖油翁。"]'),
('song-ci-823','谒金门','朱敦儒','宋','宋词','song-ci','谒金门','[]','春怎恋。',53,'宋词/ci.song.5000.json','["春怎恋。", "楼外绿催红殿。", "短袖迎风愁半卷。", "手寒无处暖。", "目断蓬莱宫殿。", "引去谁怜谁怨。", "相见不如青翅燕。", "举头长安远。"]'),
('song-ci-824','洛妃怨・昭君怨','朱敦儒','宋','宋词','song-ci','洛妃怨・昭君怨','[]','拾翠当年延伫。',48,'宋词/ci.song.5000.json','["拾翠当年延伫。", "解佩感君诚素。", "微步过南冈。", "献明珰。", "襟上泪难再会。", "惆怅幽兰心事。", "心事永难忘。", "寄君王。"]'),
('song-ci-825','燕归梁','朱敦儒','宋','宋词','song-ci','燕归梁','[]','帐掩秋风一半开。',60,'宋词/ci.song.5000.json','["帐掩秋风一半开。", "闲将玉笛吹。", "过云微雨散轻雷。", "夜参差、认楼台。", "暗香移枕新凉住，竹外漏声催。", "放教明月上床来。", "共清梦、两徘徊。"]'),
('song-ci-826','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','泷州几番清秋。',45,'宋词/ci.song.5000.json','["泷州几番清秋。", "许多愁。", "叹我等闲白了、少年头。", "人间事。", "如何是。", "去来休。", "自是不归归去、有谁留。"]'),
('song-ci-827','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','东风吹尽江梅。',45,'宋词/ci.song.5000.json','["东风吹尽江梅。", "橘花开。", "旧日吴王宫殿、长青苔。", "今古事。", "英雄泪。", "老相催。", "长恨夕阳西去、晚潮回。"]'),
('song-ci-828','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','金陵城上西楼。',45,'宋词/ci.song.5000.json','["金陵城上西楼。", "倚清秋。", "万里夕阳垂地、大江流。", "中原乱。", "簪缨散。", "几时收。", "试倩悲风吹泪、过扬州。"]'),
('song-ci-829','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','["\u957f\u6c5f"]','秋风又到人间。',45,'宋词/ci.song.5000.json','["秋风又到人间。", "叶珊珊。", "四望烟波无尽、欠青山。", "浮生事。", "长江水。", "几时闲。", "幸是古来如此、且开颜。"]'),
('song-ci-830','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','吟蛩作尽秋声。',45,'宋词/ci.song.5000.json','["吟蛩作尽秋声。", "月西沈。", "凄断馀香残梦、下层城。", "人不见。", "屏空掩。", "数残更。", "还自搴帷独坐、看青灯。"]'),
('song-ci-831','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','当年两上蓬瀛。',45,'宋词/ci.song.5000.json','["当年两上蓬瀛。", "燕殊庭。", "曾共群仙携手、斗吹笙。", "云涛晚。", "霓旌散。", "海鸥轻。", "却钓松江烟月、醉还醒。"]'),
('song-ci-832','相见欢','朱敦儒','宋','宋词','song-ci','相见欢','[]','深秋庭院初凉。',45,'宋词/ci.song.5000.json','["深秋庭院初凉。", "近重阳。", "篱畔一枝金菊、露微黄。", "鲈脍韵。", "橙齑品。", "酒新香。", "我是升平闲客、醉何妨。"]'),
('song-ci-833','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','一夜新秋风雨。',40,'宋词/ci.song.5000.json','["一夜新秋风雨。", "客恨客愁无数。", "我是卧云人，悔到红尘深处。", "难住。", "难住。", "拂袖青山归去。"]'),
('song-ci-834','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','好个中秋时节。',40,'宋词/ci.song.5000.json','["好个中秋时节。", "莫恨今宵无月。", "岩壑一灯青，寒浸水香留客。", "留客。", "留客。", "相对无言无说。"]'),
('song-ci-835','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','盏底一盘金凤。',40,'宋词/ci.song.5000.json','["盏底一盘金凤。", "满泛酒光浮动。", "引我上烟霞，智力一时无用。", "无用。", "无用。", "蹋破十洲三洞。"]'),
('song-ci-836','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','真个先生爱睡。',40,'宋词/ci.song.5000.json','["真个先生爱睡。", "睡里百般滋味。", "转面又翻身，随意十方游戏。", "游戏。", "游戏。", "到了元无一事。"]'),
('song-ci-837','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','莫恨中秋无月。',40,'宋词/ci.song.5000.json','["莫恨中秋无月。", "月又不甜不辣。", "幸有瓮头春，闲坐暖云香雪。", "香雪。", "香雪。", "满引水晶蕉叶。"]'),
('song-ci-838','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','莫恨中秋无月。',40,'宋词/ci.song.5000.json','["莫恨中秋无月。", "多点金缸红蜡。", "取酒拥丝簧，迎取轻盈桃叶。", "桃叶。", "桃叶。", "唱我新歌白雪。"]'),
('song-ci-839','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','一夜蟠桃吹坼。',40,'宋词/ci.song.5000.json','["一夜蟠桃吹坼。", "刚道有人偷折。", "幸自没踪由，无奈蝶蜂胡说。", "胡说。", "胡说。", "方朔不须耳热。"]'),
('song-ci-840','如梦令','朱敦儒','宋','宋词','song-ci','如梦令','[]','好笑山翁年纪。',40,'宋词/ci.song.5000.json','["好笑山翁年纪。", "不觉七十有四。", "生日近元宵，占早烧灯欢会。", "欢会。", "欢会。", "坐上人人千岁。"]'),
('song-ci-841','春晓曲','朱敦儒','宋','宋词','song-ci','春晓曲','[]','西楼落月鸡声急。',32,'宋词/ci.song.5000.json','["西楼落月鸡声急。", "夜浸疏香寒淅沥。", "玉人酒渴嚼春冰。", "晓色入帘横宝瑟。"]'),
('song-ci-842','柳枝・杨柳枝','朱敦儒','宋','宋词','song-ci','柳枝・杨柳枝','[]','江南岸。',40,'宋词/ci.song.5000.json','["江南岸。", "江北岸。", "折送行人无尽时。", "恨分离。", "酒一杯。", "泪双垂。", "君到长安百事违。", "几时归。"]'),
('song-ci-843','念奴娇','朱敦儒','宋','宋词','song-ci','念奴娇','[]','别离情绪，奈一番好景，一番悲戚。',120,'宋词/ci.song.5000.json','["别离情绪，奈一番好景，一番悲戚。", "燕语莺啼人乍远，还是他乡寒食。", "桃李无言，不堪攀折，总是风流客。", "东君也自，怪人冷淡踪迹。", "花艳草草春工，酒随花意薄，疏狂何益。", "除却清风并皓月，脉脉此情谁识。", "料得文君，重帘不卷，且等闲消息。", "不如归去，受他真个怜惜。"]'),
('song-ci-844','浣溪沙','孙觌','宋','宋词','song-ci','浣溪沙','[]','弱骨轻肌不耐春。',48,'宋词/ci.song.5000.json','["弱骨轻肌不耐春。", "一枝江路玉梅新。", "巡檐索笑为何人。", "素影徘徊波上月，醉香摇荡竹间云。", "酒醒人散梦仙村。"]'),
('song-ci-845','浣溪沙','慕容卿妻','宋','宋词','song-ci','浣溪沙','[]','满目江山忆旧游。',48,'宋词/ci.song.5000.json','["满目江山忆旧游。", "汀洲花草弄春柔。", "长亭舣住木兰舟。", "好梦易随流水去，芳心空逐晓云愁。", "行人莫上望京楼。"]'),
('song-ci-846','水龙吟','周紫芝','宋','宋词','song-ci','水龙吟','[]','黄金双阙横空，望中隐约三山眇。',126,'宋词/ci.song.5000.json','["黄金双阙横空，望中隐约三山眇。", "春皇欲降，渚烟收尽，青虹正绕。", "日到层宵，九枝光满，普天俱照。", "看海中桃熟，云幡绛节，冉冉度、沧波渺。", "遥想建章宫阙，□熏风、月寒清晓。", "红鸾影上，云韶声里，蒙天一笑。", "万国朝元，百蛮款塞，太平多少。", "听尧云深处，人人尽祝，似天难老。"]'),
('song-ci-847','水龙吟','周紫芝','宋','宋词','song-ci','水龙吟','[]','楚山千叠浮空，楚云只在巫山往。',126,'宋词/ci.song.5000.json','["楚山千叠浮空，楚云只在巫山往。", "鸾飞凤舞，当时空记，梦中奇语。", "晓日瞳昽，夕阳零乱，袅红萦素。", "问如今依旧，霏霏冉冉，知他为、谁朝暮。", "玉佩烟鬟飞动，炯星眸、人间相遇。", "嫣然一笑，阳城下蔡，尽成惊顾。", "蕙帐春浓，兰衾日暖，未成行雨。", "但丁宁莫似，阳台梦断，又随风去。"]'),
('song-ci-848','水龙吟','周紫芝','宋','宋词','song-ci','水龙吟','[]','楚山木落风高，暮云黯黯孤容瘦。',126,'宋词/ci.song.5000.json','["楚山木落风高，暮云黯黯孤容瘦。", "天晴似洗，明霞消尽，玉峦排秀。", "九凤飞来，五云深处，一时轻矫。", "恨三山不见，六鳌去后，天空远，人将老。", "堪笑此生如寄，信扁舟、朅来江表。", "望中愁眼，依稀犹认，数峰林杪。", "万里东南，跨江云梦，此情多少。", "问何时还我，千岩万壑，卧霜天晓。"]'),
('song-ci-849','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','近腊风光一半休。',48,'宋词/ci.song.5000.json','["近腊风光一半休。", "南枝未动北枝愁。", "嫦娥莫是见人羞。", "么凤不传蓬岛信，杜鹃空办鹤林秋。", "便须千杖打梁州。"]'),
('song-ci-850','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','欲醉江梅兴未休。',48,'宋词/ci.song.5000.json','["欲醉江梅兴未休。", "待篘春瓮洗春愁。", "不成欢绪却成羞。", "天意若教花似雪，客情宁恨鬓如秋。", "趁他何逊在扬州。"]'),
('song-ci-851','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','无限春情不肯休。',48,'宋词/ci.song.5000.json','["无限春情不肯休。", "江梅未动使人愁。", "东昏觑得玉奴羞。", "对酒情怀疑是梦，忆花天气黯如秋。", "唤春云梦泽南州。"]'),
('song-ci-852','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','水上鸣榔不系船。',48,'宋词/ci.song.5000.json','["水上鸣榔不系船。", "醉来深闭短篷眠。", "潮生潮落自年年。", "一尺鲈鱼新活计，半蓑烟雨旧衣冠。", "庙堂空有画图看。"]'),
('song-ci-853','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','多病嫌秋怕上楼。',48,'宋词/ci.song.5000.json','["多病嫌秋怕上楼。", "苦无情绪懒抬头。", "雁来不寄小银钩。", "一点离情深似海，万重凄恨黯如秋。", "怎生禁得许多愁。"]'),
('song-ci-854','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','醽醁新翻碧玉壶。',48,'宋词/ci.song.5000.json','["醽醁新翻碧玉壶。", "水精钗袅绛纱符。", "吴姬亲手碎菖蒲。", "彩索系时新睡起，榴花剪处要人扶。", "心情还似去年无。"]'),
('song-ci-855','浣溪沙','周紫芝','宋','宋词','song-ci','浣溪沙','[]','学画双蛾苦未成。',48,'宋词/ci.song.5000.json','["学画双蛾苦未成。", "鬓云新结翠鬟轻。", "伴人歌笑已多情。", "飞絮乱花闲院宇，舞鸾歌凤小娉婷。", "阳关休唱断肠声。"]'),
('song-ci-856','卜算子','周紫芝','宋','宋词','song-ci','卜算子','[]','江北上归舟，再见江南岸。',52,'宋词/ci.song.5000.json','["江北上归舟，再见江南岸。", "江北江南几度秋，梦里朱颜换。", "人是岭头云，聚散天谁管。", "君似孤云何处归，我似离群雁。"]'),
('song-ci-857','卜算子','周紫芝','宋','宋词','song-ci','卜算子','[]','霜叶下孤篷，船在垂杨岸。',52,'宋词/ci.song.5000.json','["霜叶下孤篷，船在垂杨岸。", "早是凄凉惜别时，更惜年华换。", "别酒解留人，拚醉君休管。", "醉里朱弦莫谩弹，愁入参差雁。"]'),
('song-ci-858','卜算子','周紫芝','宋','宋词','song-ci','卜算子','[]','絮尽柳成空，春去花如扫。',52,'宋词/ci.song.5000.json','["絮尽柳成空，春去花如扫。", "窗外枝枝海石榴，特为幽人好。", "密叶过疏篱，薄艳明芳草。", "剪得花时却倚阑，楼上人垂手。"]'),
('song-ci-859','木兰花・玉楼春','周紫芝','宋','宋词','song-ci','木兰花・玉楼春','[]','嫦娥天上人谁识。',64,'宋词/ci.song.5000.json','["嫦娥天上人谁识。", "家在蓬山烟水隔。", "不应著意眼前人，便是登瀛当日客。", "双眸炯炯秋波滴。", "也解人间青与白。", "檀郎未摘月边枝，枉是不教花爱惜。"]'),
('song-ci-860','木兰花・玉楼春','周紫芝','宋','宋词','song-ci','木兰花・玉楼春','[]','江头雨后山如髻。',64,'宋词/ci.song.5000.json','["江头雨后山如髻。", "催送新凉风有意。", "月来杨柳绿阴中，秋在梧桐疏影外。", "小窗纹簟凉如水。", "岁岁年年同此味。", "眼前不忍对西风，梦里是堪追往事。"]'),
('song-ci-861','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','春闲昼永。',52,'宋词/ci.song.5000.json','["春闲昼永。", "城下江深山倒影。", "净扫风埃。", "收拾烟光入句来。", "短窗闲倚。", "身似浮云门似水。", "谁伴馀年。", "结得青山一个缘。"]'),
('song-ci-862','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','蓬莱三岛。',52,'宋词/ci.song.5000.json','["蓬莱三岛。", "上有青青千岁草。", "玉佩烟鬟。", "来作人间一笑欢。", "麻姑行酒。", "萼绿华歌清韵袅。", "玉秀兰芳。", "醉舞东风彩袖长。"]'),
('song-ci-863','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','西山岩桂。',52,'宋词/ci.song.5000.json','["西山岩桂。", "常恨香闻烟雨外。", "何似君家。", "戏彩堂前早试花。", "黄金千粟。", "风撼芳条香馥馥。", "一剪无多。", "桃李漫山奈俗何。"]'),
('song-ci-864','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','当年文伯。',52,'宋词/ci.song.5000.json','["当年文伯。", "曾是东坡门下客。", "文采风流。", "奕叶传芳总未休。", "为公持酒。", "愿祝彩衣无限寿。", "归觐枫宸。", "剩醉长安几度春。"]'),
('song-ci-865','摊破浣溪沙・山花子','周紫芝','宋','宋词','song-ci','摊破浣溪沙・山花子','[]','苍璧新敲小凤团。',56,'宋词/ci.song.5000.json','["苍璧新敲小凤团。", "赤泥开印煮清泉。", "醉捧纤纤双玉笋，鹧鸪斑。", "雪浪溅翻金缕袖，松风吹醒玉酡颜。", "更待微甘回齿颊，且留连。"]'),
('song-ci-866','减字木兰花','周紫芝','宋','宋词','song-ci','减字木兰花','[]','门外青骢月下嘶。',56,'宋词/ci.song.5000.json','["门外青骢月下嘶。", "映阶笼烛画帘垂。", "一曲阳关声欲尽，不多时。", "凤饼未残云脚乳，水沈催注玉花瓷。", "忍看捧瓯春笋露，翠鬟低。"]'),
('song-ci-867','水调歌头','周紫芝','宋','宋词','song-ci','水调歌头','[]','白发三千丈，双鬓不胜垂。',114,'宋词/ci.song.5000.json','["白发三千丈，双鬓不胜垂。", "人间忧喜如梦，老矣更何之。", "蘧玉行年过了，未必如今俱是，五十九年非。", "拟把彭殇梦，分付与痴儿。", "君莫羡，客起舞，寿琼卮。", "此生但愿，长遣猿鹤共追随。", "金印借令如斗，富贵那能长久，不饮竟何为。", "莫问蓬莱路，从古少人知。"]'),
('song-ci-868','水调歌头','周紫芝','宋','宋词','song-ci','水调歌头','[]','濯锦桥边月，几度照中秋。',114,'宋词/ci.song.5000.json','["濯锦桥边月，几度照中秋。", "年年此夜清景，伴我与君游。", "万里相随何处，看尽吴波越嶂，更向古徐州。", "应为霜髯老，西望倚黄楼。", "天如水，云似扫，素魂流。", "不知今夕何夕，相对语羁愁。", "故国归来何事，记易南枝惊鹊，还对玉蟾羞。", "踏尽疏桐影，更复为君留。"]'),
('song-ci-869','水调歌头','周紫芝','宋','宋词','song-ci','水调歌头','[]','岁晚念行役，江阔渺风烟。',114,'宋词/ci.song.5000.json','["岁晚念行役，江阔渺风烟。", "六朝文物何在，回首更凄然。", "倚尽危楼杰观，暗想琼枝璧月，罗袜步承莲。", "桃叶山前鹭，无语下寒滩。", "潮寂寞，浸孤垒，涨平川。", "莫愁艇子何处，烟树杳无边。", "王谢堂前双燕，空绕乌衣门巷，斜日草连天。", "只有台城月，千古照婵娟。"]'),
('song-ci-870','水调歌头','周紫芝','宋','宋词','song-ci','水调歌头','[]','落日在烟树，云水两空濛。',114,'宋词/ci.song.5000.json','["落日在烟树，云水两空濛。", "澹霞消尽，何事依约有微红。", "湖上晚来风细，吹尽一天残雨，苍翠湿千峰。", "谁遣长空月，冷浸玉壶中。", "问明月，应解笑，白头翁。", "不堪老去，依旧临水照衰容。", "良夜几横烟棹，独倚危墙西望，目断远山重。", "但恨故人远，此乐与谁同。"]'),
('song-ci-871','沙塞子','周紫芝','宋','宋词','song-ci','沙塞子','[]','秋云微淡月微羞。',62,'宋词/ci.song.5000.json','["秋云微淡月微羞。", "云黯黯、月彩难留。", "只应是、嫦娥心里，也似人愁。", "几时回步玉移钩。", "人共月、同上南楼。", "却重听、画阑西角，月下轻讴。"]'),
('song-ci-872','沙塞子','周紫芝','宋','宋词','song-ci','沙塞子','[]','玉溪秋月浸寒波。',62,'宋词/ci.song.5000.json','["玉溪秋月浸寒波。", "忍持酒、重听骊歌。", "不堪对、绿阴飞阁，月下羞蛾。", "夜深惊鹊转南柯。", "惨别意、无奈愁何。", "他年事、不须重问，转更愁多。"]'),
('song-ci-873','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','荷气吹凉到枕边。',64,'宋词/ci.song.5000.json','["荷气吹凉到枕边。", "薄纱如雾亦如烟。", "清泉浴后花垂雨，白酒倾时玉满船。", "钗欲溜，髻微偏。", "却寻霜粉扑香绵。", "冰肌近著浑无暑，小扇频摇最可怜。"]'),
('song-ci-874','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','乌鹊桥边河汉流。',64,'宋词/ci.song.5000.json','["乌鹊桥边河汉流。", "洗车微雨湿清秋。", "相逢不似长相忆，一度相逢一度愁。", "云却静，月垂钩。", "金针穿得喜回头。", "只应人倚阑干处，便似天孙梳洗楼。"]'),
('song-ci-875','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','尊酒年年乐事多。',64,'宋词/ci.song.5000.json','["尊酒年年乐事多。", "古铜犹得几摩挲。", "他时人物君须记，玉笋班中李泰和。", "烦翠袖，把金荷。", "功名馀事且高歌。", "新来学得长生诀，写就黄庭不换鹅。"]'),
('song-ci-876','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','名在休文季孟间。',64,'宋词/ci.song.5000.json','["名在休文季孟间。", "一时风味更萧然。", "琼林不逐春风老，安用丹砂巧驻颜。", "春入户，酒吹澜。", "小桃枝上锦阑斑。", "明年欲与君为寿，无路相从入道山。"]'),
('song-ci-877','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','袅袅云梳晓髻堆。',63,'宋词/ci.song.5000.json','["袅袅云梳晓髻堆。", "涓涓秋净眼波回。", "旧家十二峰前住，偶为襄王下楚台。", "闲院静，小桃开。", "刘郎前度几回来。", "东风易行云散，花里传觞莫谩催。"]'),
('song-ci-878','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','晴日烘帘暖似春。',64,'宋词/ci.song.5000.json','["晴日烘帘暖似春。", "菊回霜晕浅仍深。", "谁知此地栽花手，便是当时嗅蕊人。", "秋渺渺，夜沈沈。", "一声清唱袅残音。", "娇痴应挽香罗比，六幅双裙染郁金。"]'),
('song-ci-879','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','一点残红欲尽时。',64,'宋词/ci.song.5000.json','["一点残红欲尽时。", "乍凉秋气满屏帏。", "梧桐叶上三更雨，叶叶声声是别离。", "调宝瑟，拨金猊。", "那时同唱鹧鸪词。", "如今风雨西楼夜，不听清歌也泪垂。"]'),
('song-ci-880','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','年少登高意气多。',64,'宋词/ci.song.5000.json','["年少登高意气多。", "黄花压帽醉嵯峨。", "如今满眼看华发，强拈茱萸奈老何。", "千垒岫，万重波。", "一时分付与秦娥。", "明年身健君休问，且对秋风卷翠螺。"]'),
('song-ci-881','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','终日看山不厌山。',64,'宋词/ci.song.5000.json','["终日看山不厌山。", "寻思百计不如闲。", "何时得到重阳日，醉把茱萸仔细看。", "敧醉帽，倚雕阑。", "偶然携酒却成欢。", "篱边黄菊关心事，触误愁人到酒边。"]'),
('song-ci-882','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','读尽牙签玉轴书。',64,'宋词/ci.song.5000.json','["读尽牙签玉轴书。", "不知门外有园蔬。", "借令未解銮坡去，也合雠书在石渠。", "微雨后，小寒初。", "满斟长寿碧琳腴。", "不须更问荆州路，便上追锋御府车。"]'),
('song-ci-883','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','楼上缃桃一萼红。',64,'宋词/ci.song.5000.json','["楼上缃桃一萼红。", "别来开谢几东风。", "武陵春尽无人处，犹有刘郎去后踪。", "香阁小，翠帘重。", "今宵何事偶相逢。", "行云又被风吹散，见了依前是梦中。"]'),
('song-ci-884','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','彩鹢双飞雪浪翻。',64,'宋词/ci.song.5000.json','["彩鹢双飞雪浪翻。", "楚歌声转绿杨湾。", "一川红旆初衔日，两岸朱楼不下帘。", "阑倚处，玉垂纤。", "白团扇底藕丝衫。", "未成密约回秋水，看得羞时隔画檐。"]'),
('song-ci-885','鹧鸪天','周紫芝','宋','宋词','song-ci','鹧鸪天','[]','花褪残红绿满枝。',64,'宋词/ci.song.5000.json','["花褪残红绿满枝。", "嫩寒犹透薄罗衣。", "池塘雨细双鸳睡，杨柳风轻小燕飞。", "人别后，酒醒时。", "午窗残梦子规啼。", "尊前心事人谁问，花底闲愁春又归。"]'),
('song-ci-886','采桑子','周紫芝','宋','宋词','song-ci','采桑子','[]','跳珠雨罢风初静，阑槛凭虚。',52,'宋词/ci.song.5000.json','["跳珠雨罢风初静，阑槛凭虚。", "绛阙清都。", "只在仙人碧玉壶。", "九原唤起王摩诘，画作新图。", "十城芙蕖。", "乞与知章老鉴湖。"]'),
('song-ci-887','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','画幕灯前细雨，垂莲盏里清歌。',58,'宋词/ci.song.5000.json','["画幕灯前细雨，垂莲盏里清歌。", "玉纤持板隔香罗。", "不放行云飞过。", "今夜尘生洛浦，明朝雨在巫山。", "羞蛾且莫斗弯环。", "不似司空见惯。"]'),
('song-ci-888','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','池面风翻弱絮，树头雨退嫣红。',58,'宋词/ci.song.5000.json','["池面风翻弱絮，树头雨退嫣红。", "扑花蝴蝶杳无踪。", "又做一场春梦。", "便是一成去了，不成没个来时。", "眼前无处说相思。", "要说除非梦里。"]'),
('song-ci-889','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','罗袖云轻雾薄，醉肌玉软花柔。',58,'宋词/ci.song.5000.json','["罗袖云轻雾薄，醉肌玉软花柔。", "相逢不道有春愁。", "只道春来微瘦。", "一点人间深意，数声柳下轻讴。", "带将离恨上归舟。", "肠断月斜时候。"]'),
('song-ci-890','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','发白犹敧旅枕，溪深未挂烟莎。',58,'宋词/ci.song.5000.json','["发白犹敧旅枕，溪深未挂烟莎。", "往来苕霅意如何。", "应有轻鸥笑我。", "细算年来活计，只消一个渔舟。", "金鱼无分不须求。", "只乞鲈鱼换酒。"]'),
('song-ci-891','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','连理枝头并蒂，同心带上双垂。',58,'宋词/ci.song.5000.json','["连理枝头并蒂，同心带上双垂。", "背灯偷赠语低低。", "一点浓情先寄。", "翡翠钗头摘处，鸳鸯枕上醒时。", "酸甜红颗阿谁知。", "别是人间滋味。"]'),
('song-ci-892','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','天意未教秋老，花容剗地宜霜。',58,'宋词/ci.song.5000.json','["天意未教秋老，花容剗地宜霜。", "酒肌红软玉肌香。", "不与梨花同样。", "来伴孙郎小宴，临风为舞霓裳。", "更深绿水照红妆。", "便是采莲船上。"]'),
('song-ci-893','西江月','周紫芝','宋','宋词','song-ci','西江月','[]','谁把蓝揉翡翠，天将蜡做梅花。',58,'宋词/ci.song.5000.json','["谁把蓝揉翡翠，天将蜡做梅花。", "晚来秋水映残霞。", "水墨新描图画。", "纸上写将心去，眼边送却愁来。", "今回相见比前回。", "心下忡忡越㬠。"]'),
('song-ci-894','小重山','周紫芝','宋','宋词','song-ci','小重山','[]','溪上晴山簇翠螺。',70,'宋词/ci.song.5000.json','["溪上晴山簇翠螺。", "晓来霜叶醉，小池荷。", "琐窗秋意苦无多。", "帘绣卷，黄菊两三窠。", "小睡拥香罗。", "起来匀醉粉，玉垂梭。", "只愁无奈夜长何。", "你去也，今夜早来麽。"]'),
('song-ci-895','小重山','周紫芝','宋','宋词','song-ci','小重山','[]','碧玉山围十里湖。',70,'宋词/ci.song.5000.json','["碧玉山围十里湖。", "水云天共远，戏双凫。", "河阳花县锦屏铺。", "人不老，长日在蓬壶。", "一笑且踟蹰。", "会骑箕尾去，上云衢。", "十分深注碧琳腴。", "休惜醉，醉后有人扶。"]'),
('song-ci-896','汉宫春','周紫芝','宋','宋词','song-ci','汉宫春','[]','秋意还深，渐银床露冷，梧叶风高。',118,'宋词/ci.song.5000.json','["秋意还深，渐银床露冷，梧叶风高。", "婵娟也应为我，羞照霜毛。", "流年老尽，漫银蟾、冷浸香醪。", "除尽把，平生怨感，一时分付离骚。", "伤心故人千里，问阴晴何处，还记今宵。", "楼高共谁同看，玉桂烟梢。", "南枝鹊绕，叹此生、飘转江皋。", "须更约，他年清照，为人常到寒霄。"]'),
('song-ci-897','汉宫春','周紫芝','宋','宋词','song-ci','汉宫春','[]','香满箱奁，看沈犀弄水，浓麝含薰。',118,'宋词/ci.song.5000.json','["香满箱奁，看沈犀弄水，浓麝含薰。", "荀郎一时旧事，尽属王孙。", "残膏剩馥，须倾囊、乞与兰荪。", "金兽暖，云窗雾阁，为人洗尽馀醺。", "依稀雪梅风味，似孤山尽处，马上烟村。", "从来甲煎浅俗，那忍重闻。", "苏台燕寝，下重帏、深闭孤云。", "都占得，横斜乱影，伴他月下黄昏。"]'),
('song-ci-898','醉落魄・一斛珠','周紫芝','宋','宋词','song-ci','醉落魄・一斛珠','[]','江天云薄。',67,'宋词/ci.song.5000.json','["江天云薄。", "江头雪似杨花落。", "寒灯不管人离索。", "照得人来，真个睡不著。", "归期已负梅花约。", "又还春动空飘泊。", "晓寒谁看伊梳掠。", "雪满西楼，人在阑干角。"]'),
('song-ci-899','醉落魄・一斛珠','周紫芝','宋','宋词','song-ci','醉落魄・一斛珠','[]','柳边池阁。',67,'宋词/ci.song.5000.json','["柳边池阁。", "晚来卷地东风恶。", "人生不解频行乐。", "昨日花开，今日风吹落。", "杨花却似人飘泊。", "春云更似人情薄。", "如今始信从前错。", "为个蝇头，轻负青山约。"]'),
('song-ci-900','醉落魄・一斛珠','周紫芝','宋','宋词','song-ci','醉落魄・一斛珠','[]','薰风池阁。',67,'宋词/ci.song.5000.json','["薰风池阁。", "小红桥下荷花薄。", "沙平水浅山如削。", "水上鸳鸯，何处风吹落。", "今朝端午新梳掠。", "锦丝围腕花柔弱。", "人生只有尊前乐。", "前度刘郎，莫负重来约。"]'),
('song-ci-901','醉落魄・一斛珠','周紫芝','宋','宋词','song-ci','醉落魄・一斛珠','[]','云深海阔。',67,'宋词/ci.song.5000.json','["云深海阔。", "天风吹上黄金阙。", "酒醒不记归时节。", "三十年来，往事无人说。", "浮生正似风中雪。", "丹砂岂是神仙诀。", "世间生死无休歇。", "长伴君闲，只有山中月。"]'),
('song-ci-902','阮郎归','周紫芝','宋','宋词','song-ci','阮郎归','[]','酴醿花谢日迟迟。',56,'宋词/ci.song.5000.json','["酴醿花谢日迟迟。", "杨花无数飞。", "章台侧畔尽风吹。", "飘零无定期。", "烟漠漠，草萋萋。", "江南春尽时。", "可怜踪迹尚东西。", "故园何日归。"]'),
('song-ci-903','阮郎归','周紫芝','宋','宋词','song-ci','阮郎归','[]','月棂疏影照婵娟。',56,'宋词/ci.song.5000.json','["月棂疏影照婵娟。", "闲临小玉盘。", "枣花金钏出纤纤。", "棋声敲夜寒。", "飞雹冷，水精圆。", "夜深人未眠。", "笑催炉兽暖衾鸳。", "莫教银漏残。"]'),
('song-ci-904','阮郎归','周紫芝','宋','宋词','song-ci','阮郎归','["\u897f\u6e56"]','西湖山下水潺潺。',56,'宋词/ci.song.5000.json','["西湖山下水潺潺。", "满山风雨寒。", "枝头红日晓斓斑。", "越梅催晓丹。", "连翠叶，拥金盘。", "玉池生乳泉。", "此生三度试甘酸。", "欲归归尚难。"]'),
('song-ci-905','青玉案','周紫芝','宋','宋词','song-ci','青玉案','[]','青鞋忍踏江沙路。',80,'宋词/ci.song.5000.json','["青鞋忍踏江沙路。", "恨人已、骑鲸去。", "笔底骅骝谁与度。", "西州重到，可怜不见，华屋生存处。", "秋江渺渺高台暮。", "满壁栖鸦醉时句。", "飞上金鸾人漫许。", "清歌低唱，小蛮犹在，空湿梨花雨。"]'),
('song-ci-906','青玉案','周紫芝','宋','宋词','song-ci','青玉案','[]','梅花落尽人谁管。',80,'宋词/ci.song.5000.json','["梅花落尽人谁管。", "暗凄断、伤春眼。", "雪后平芜春尚浅。", "一簪华发，满襟离恨，羞作东风伴。", "斗花小斛兰芽短。", "犹是当时旧庭院。", "拟把新愁凭酒遣。", "春衫重看，酒痕犹在，忍放金杯满。"]'),
('song-ci-907','菩萨蛮','周紫芝','宋','宋词','song-ci','菩萨蛮','[]','翠蛾懒画妆痕浅。',52,'宋词/ci.song.5000.json','["翠蛾懒画妆痕浅。", "香肌得酒花柔软。", "粉汗湿吴绫。", "玉钗敲枕稜。", "鬓丝云卸腻。", "罗带还重系。", "含笑出房栊。", "羞随脸上红。"]'),
('song-ci-908','菩萨蛮','周紫芝','宋','宋词','song-ci','菩萨蛮','[]','风头不定云来去。',52,'宋词/ci.song.5000.json','["风头不定云来去。", "天教月到湖心住。", "遥夜一襟愁。", "水风浑似秋。", "藕花迎露笑。", "暗水飞萤照。", "渔笛莫频吹。", "客愁人不知。"]'),
('song-ci-909','菩萨蛮','周紫芝','宋','宋词','song-ci','菩萨蛮','[]','宝薰拂拂浓如雾。',52,'宋词/ci.song.5000.json','["宝薰拂拂浓如雾。", "暗惊梅蕊风前度。", "依约似江村。", "馀香马上闻。", "画桥风雨暮。", "零落知无数。", "收拾小窗春。", "金炉檀炷深。"]'),
('song-ci-910','西地锦','周紫芝','宋','宋词','song-ci','西地锦','[]','雨细欲收还滴。',55,'宋词/ci.song.5000.json','["雨细欲收还滴。", "满一庭秋色。", "阑干独倚，无人共说，这些愁寂。", "手把玉郎书迹。", "怎不教人忆。", "看看又是黄昏也，敛眉峰轻碧。"]'),
('song-ci-911','谒金门','周紫芝','宋','宋词','song-ci','谒金门','[]','春雨细。',53,'宋词/ci.song.5000.json','["春雨细。", "开尽一番桃李。", "柳暗曲阑花满地。", "日高人睡起。", "绿浸小池春水。", "沙暖鸳鸯双戏。", "薄幸更无书一纸。", "画楼愁独倚。"]'),
('song-ci-912','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','春寒入翠帷，月淡云来去。',48,'宋词/ci.song.5000.json','["春寒入翠帷，月淡云来去。", "院落半晴天，风撼梨花树。", "人醉掩金铺，闲倚秋千柱。", "满眼是相思，无说相思处。"]'),
('song-ci-913','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','青丝结晓鬟，临镜心情懒。',48,'宋词/ci.song.5000.json','["青丝结晓鬟，临镜心情懒。", "知为晓愁浓，画得双蛾浅。", "柳困玉楼空，花落红窗暖。", "相对语春愁，只有春闺燕。"]'),
('song-ci-914','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','新欢君未成，往事无人记。',48,'宋词/ci.song.5000.json','["新欢君未成，往事无人记。", "行雨共行云，如梦还如醉。", "相见又难言，欲住浑无计。", "眉翠莫频低，我已无多泪。"]'),
('song-ci-915','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','清歌忆去年，共唱秦楼曲。',48,'宋词/ci.song.5000.json','["清歌忆去年，共唱秦楼曲。", "门外月横波，帐里人如玉。", "秋风吹彩云，梦断惊难续。", "别调不堪闻，红泪销残烛。"]'),
('song-ci-916','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','金鞍欲别时，芳草溪边渡。',48,'宋词/ci.song.5000.json','["金鞍欲别时，芳草溪边渡。", "不忍上西楼，怕看来时路。", "帘幕卷东风，燕子双双语。", "薄幸不归来，冷落春情绪。"]'),
('song-ci-917','生查子','周紫芝','宋','宋词','song-ci','生查子','[]','轻云浅护霜，晓日红生砌。',48,'宋词/ci.song.5000.json','["轻云浅护霜，晓日红生砌。", "烟共宝薰浓，人与山长翠。", "银浪酒杯浓，锦幄双鸾戏。", "庭下彩衣郎，共祝千千岁。"]'),
('song-ci-918','昭君怨','周紫芝','宋','宋词','song-ci','昭君怨','[]','满院融融花气。',49,'宋词/ci.song.5000.json','["满院融融花气。", "红绣一帘垂地。", "往事忆年时。", "只春知。", "风又暖。", "花渐满。", "人似行云不见。", "无计奈离情。", "恶销凝。"]'),
('song-ci-919','秦楼月・忆秦娥','周紫芝','宋','宋词','song-ci','秦楼月・忆秦娥','[]','东风歇。',56,'宋词/ci.song.5000.json','["东风歇。", "香尘满院花如雪。", "花如雪。", "看看又是，黄昏时节。", "无言独自添香鸭。", "相思情绪无人说。", "无人说。", "照人只有，西楼斜月。"]'),
('song-ci-920','天仙子','周紫芝','宋','宋词','song-ci','天仙子','[]','雪似杨花飞不定。',80,'宋词/ci.song.5000.json','["雪似杨花飞不定。", "枝上冻禽昏欲暝。", "寒窗相对话分飞，箫鼓静。", "灯炯炯。", "一曲阳关和泪听。", "酒入离肠愁欲凝。", "往事不堪重记省。", "劝君莫上玉楼梯，风力劲。", "山色暝。", "忍看去时楼下径。"]'),
('song-ci-921','渔家傲','周紫芝','宋','宋词','song-ci','渔家傲','[]','遇坎乘流随分了。',72,'宋词/ci.song.5000.json','["遇坎乘流随分了。", "鸡虫得失能多少。", "儿辈雌黄堪一笑。", "堪一笑。", "鹤长凫短从他道。", "几度秋风吹梦到。", "花姑溪上人空老。", "唤取扁舟归去好。", "归去好。", "孤篷一枕秋江晓。"]');
